## 11. How to Add a New Page

1. **Create the component** in `src/pages/NewPage.tsx`.

2. **Add the route** in `App.tsx` within `<Routes>`:
   - Public route: `<Route path="/new-path" element={<NewPage />} />`
   - Protected route: `<Route path="/new-path" element={<ProtectedRoute><NewPage /></ProtectedRoute>} />`

3. **Hide BottomNav** if it is a form or modal-style page: add the path pattern to the BottomNav hide list in `AppContent`.

4. **Feature flag** (if needed): `const isEnabled = useFeatureFlag('flag_key');`

5. **Import services** for data access: `import { eventService } from '@/services';`

6. **Handle errors** with `errorHandler.handle(err, { action: 'description' })`.

7. **Add a Skeleton component** for the loading state if the page loads async data. Follow the naming convention: `NewPageSkeleton`.

8. **Follow the page component pattern** from Section 7: state setup, `useEffect` with concurrency guard, loading skeleton return, then full render.

/**
 * Impersonate User Edge Function
 *
 * Allows platform admins (users with app_metadata.is_admin = true) to
 * generate a session for another user. This is useful for debugging and
 * support purposes.
 *
 * Request body: { user_id: string }
 * Returns: { session: { access_token, refresh_token, expires_in, user } }
 */

import { serve } from 'https://deno.land/std@0.177.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.0';

const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;

serve(async (req) => {
  const headers = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  };

  // Handle CORS preflight
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers });
  }

  if (req.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers,
    });
  }

  try {
    // Parse the request body (access_token is passed in body to avoid
    // local edge runtime JWT verification issues with ES256)
    const { user_id, access_token } = await req.json();

    if (!access_token || typeof access_token !== 'string') {
      return new Response(JSON.stringify({ error: 'Missing access_token' }), {
        status: 401,
        headers,
      });
    }

    // Decode the JWT payload to get the caller's user ID
    const payloadBase64 = access_token.split('.')[1];
    if (!payloadBase64) {
      return new Response(JSON.stringify({ error: 'Invalid token format' }), {
        status: 401,
        headers,
      });
    }
    const payload = JSON.parse(atob(payloadBase64));
    const callerUserId = payload.sub;
    if (!callerUserId) {
      return new Response(JSON.stringify({ error: 'Invalid token: missing sub claim' }), {
        status: 401,
        headers,
      });
    }

    // Use service role client to fetch the full user record and verify identity
    const adminClient = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

    const {
      data: { user: caller },
      error: callerError,
    } = await adminClient.auth.admin.getUserById(callerUserId);

    if (callerError || !caller) {
      return new Response(JSON.stringify({ error: 'Invalid authorization token' }), {
        status: 401,
        headers,
      });
    }

    // Check if the caller is a platform admin
    if (!caller.app_metadata?.is_admin) {
      return new Response(JSON.stringify({ error: 'Forbidden: admin access required' }), {
        status: 403,
        headers,
      });
    }
    if (!user_id || typeof user_id !== 'string') {
      return new Response(JSON.stringify({ error: 'Missing or invalid user_id' }), {
        status: 400,
        headers,
      });
    }

    // Prevent impersonating yourself
    if (user_id === caller.id) {
      return new Response(JSON.stringify({ error: 'Cannot impersonate yourself' }), {
        status: 400,
        headers,
      });
    }

    // Verify the target user exists
    const {
      data: { user: targetUser },
      error: targetError,
    } = await adminClient.auth.admin.getUserById(user_id);

    if (targetError || !targetUser) {
      return new Response(JSON.stringify({ error: 'Target user not found' }), {
        status: 404,
        headers,
      });
    }

    if (!targetUser.email) {
      return new Response(
        JSON.stringify({ error: 'Impersonation requires a user with an email address' }),
        { status: 400, headers }
      );
    }

    // Generate a magic link to get session properties
    const {
      data: { properties },
      error: linkError,
    } = await adminClient.auth.admin.generateLink({
      type: 'magiclink',
      email: targetUser.email,
    });

    if (linkError || !properties?.hashed_token) {
      console.error('Failed to generate link:', linkError);
      return new Response(JSON.stringify({ error: 'Failed to generate impersonation session' }), {
        status: 500,
        headers,
      });
    }

    // Verify the OTP to get a real session
    const {
      data: { session },
      error: verifyError,
    } = await adminClient.auth.verifyOtp({
      token_hash: properties.hashed_token,
      type: 'magiclink',
    });

    if (verifyError || !session) {
      console.error('Failed to verify OTP:', verifyError);
      return new Response(JSON.stringify({ error: 'Failed to create impersonation session' }), {
        status: 500,
        headers,
      });
    }

    console.log(
      `Admin ${caller.email} (${caller.id}) impersonated user ${targetUser.email} (${targetUser.id})`
    );

    return new Response(
      JSON.stringify({
        session: {
          access_token: session.access_token,
          refresh_token: session.refresh_token,
          expires_in: session.expires_in,
          user: session.user,
        },
      }),
      { status: 200, headers }
    );
  } catch (error) {
    console.error('Impersonation error:', error);
    return new Response(JSON.stringify({ error: 'Internal server error' }), {
      status: 500,
      headers,
    });
  }
});

/**
 * Send Push Notification Edge Function
 *
 * Processes the notification queue and sends push notifications to subscribed devices.
 * Also saves notifications to the inbox for history.
 *
 * Triggered by:
 * - Database webhook when items are added to notification_queue
 * - Manual invocation for testing
 * - process-scheduled function for scheduled notifications
 */

import { serve } from 'https://deno.land/std@0.177.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.0';
import webpush from 'npm:web-push@3.6.7';
import * as Sentry from 'https://deno.land/x/sentry/index.mjs';

// Initialize Sentry
const SENTRY_DSN = Deno.env.get('SENTRY_DSN');
if (SENTRY_DSN) {
  Sentry.init({
    dsn: SENTRY_DSN,
    defaultIntegrations: false,
    tracesSampleRate: 1.0,
    environment: Deno.env.get('SENTRY_ENVIRONMENT') || 'production',
  });

  // Set Supabase-specific tags
  Sentry.setTag('region', Deno.env.get('SB_REGION'));
  Sentry.setTag('execution_id', Deno.env.get('SB_EXECUTION_ID'));
  Sentry.setTag('function', 'send-push');
}

// Environment variables
const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
const VAPID_PUBLIC_KEY = Deno.env.get('VAPID_PUBLIC_KEY');
const VAPID_PRIVATE_KEY = Deno.env.get('VAPID_PRIVATE_KEY');
const VAPID_SUBJECT = Deno.env.get('VAPID_SUBJECT') || 'mailto:notifications@roster.app';

// Configure web-push with VAPID credentials
if (VAPID_PUBLIC_KEY && VAPID_PRIVATE_KEY) {
  webpush.setVapidDetails(VAPID_SUBJECT, VAPID_PUBLIC_KEY, VAPID_PRIVATE_KEY);
}

// Types
interface QueueItem {
  id: string;
  recipient_user_id: string;
  notification_type: string;
  title: string;
  body: string;
  event_id: string | null;
  participant_id: string | null;
  actor_user_id: string | null;
  action_url: string | null;
  scheduled_for: string;
  status: string;
  attempts: number;
}

interface PushSubscription {
  id: string;
  user_id: string;
  endpoint: string;
  p256dh_key: string;
  auth_key: string;
}

interface NotificationPreferences {
  push_enabled: boolean;
  notify_new_signup: boolean;
  notify_withdrawal: boolean;
  notify_payment_received: boolean;
  notify_capacity_reached: boolean;
  notify_signup_confirmed: boolean;
  notify_event_updated: boolean;
  notify_event_cancelled: boolean;
  notify_payment_reminder: boolean;
  notify_waitlist_promotion: boolean;
}

// Preference key mapping
const PREF_MAP: Record<string, keyof NotificationPreferences> = {
  new_signup: 'notify_new_signup',
  withdrawal: 'notify_withdrawal',
  payment_received: 'notify_payment_received',
  capacity_reached: 'notify_capacity_reached',
  signup_confirmed: 'notify_signup_confirmed',
  event_updated: 'notify_event_updated',
  event_cancelled: 'notify_event_cancelled',
  payment_reminder: 'notify_payment_reminder',
  waitlist_promotion: 'notify_waitlist_promotion',
};

/**
 * Check if user wants to receive this notification type
 */
function shouldSendNotification(
  prefs: NotificationPreferences | null,
  notificationType: string
): boolean {
  // If no preferences, default to sending
  if (!prefs) return true;

  // Check master toggle
  if (!prefs.push_enabled) return false;

  // Check specific notification type
  const prefKey = PREF_MAP[notificationType];
  if (prefKey && prefs[prefKey] === false) return false;

  return true;
}

/**
 * Send a Web Push notification using the web-push library
 */
async function sendWebPush(
  subscription: PushSubscription,
  payload: { title: string; body: string; data?: Record<string, unknown> },
  supabaseClient: ReturnType<typeof createClient>
): Promise<boolean> {
  // Check if VAPID keys are configured
  if (!VAPID_PUBLIC_KEY || !VAPID_PRIVATE_KEY) {
    console.log('VAPID keys not configured, skipping push');
    return false;
  }

  try {
    const pushSubscription = {
      endpoint: subscription.endpoint,
      keys: {
        p256dh: subscription.p256dh_key,
        auth: subscription.auth_key,
      },
    };

    await webpush.sendNotification(pushSubscription, JSON.stringify(payload));
    console.log('Push sent successfully to:', subscription.endpoint.slice(0, 50) + '...');
    return true;
  } catch (error) {
    // Handle specific web-push errors
    if (error instanceof Error) {
      const statusCode = (error as { statusCode?: number }).statusCode;

      // 404 or 410 means the subscription is no longer valid - not an error to report
      if (statusCode === 404 || statusCode === 410) {
        console.log('Subscription expired or invalid:', subscription.id);
        // Mark the subscription as inactive in the database (fire-and-forget)
        supabaseClient
          .from('push_subscriptions')
          .update({ active: false })
          .eq('id', subscription.id)
          .then(({ error: updateError }) => {
            if (updateError) {
              console.error(
                `Failed to mark subscription ${subscription.id} as inactive:`,
                updateError
              );
            } else {
              console.log('Successfully marked subscription as inactive:', subscription.id);
            }
          });
      } else {
        // Unexpected error - log to Sentry
        console.error('Failed to send push:', error.message);
        if (SENTRY_DSN) {
          Sentry.captureException(error, {
            tags: { operation: 'sendWebPush' },
            extra: { subscriptionId: subscription.id, statusCode },
          });
        }
      }
    } else {
      console.error('Failed to send push:', error);
      if (SENTRY_DSN) {
        Sentry.captureException(error, {
          tags: { operation: 'sendWebPush' },
          extra: { subscriptionId: subscription.id },
        });
      }
    }
    return false;
  }
}

serve(async (req) => {
  // CORS headers
  const headers = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  };

  // Handle CORS preflight
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers });
  }

  try {
    // Create Supabase client with service role
    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

    // First, clean up any stale 'processing' items (e.g., from crashed function runs)
    // Items stuck in 'processing' for more than 5 minutes are considered stale
    const staleThreshold = new Date(Date.now() - 5 * 60 * 1000).toISOString();
    // Define the maximum number of attempts allowed for a notification
    const MAX_ATTEMPTS = 3;

    // Mark stale items that have already reached the maximum attempts as failed
    const { error: staleFailError } = await supabase
      .from('notification_queue')
      .update({ status: 'failed' })
      .eq('status', 'processing')
      .gte('attempts', MAX_ATTEMPTS)
      .lt('updated_at', staleThreshold);

    if (staleFailError) {
      console.error('Failed to mark over-attempted stale items as failed:', staleFailError);
      // Continue anyway - this is not critical enough to abort the entire function
    }

    // Reset remaining stale processing items (that have not exhausted attempts) back to pending
    const { error: cleanupError } = await supabase
      .from('notification_queue')
      .update({ status: 'pending' })
      .eq('status', 'processing')
      .lt('updated_at', staleThreshold)
      .lt('attempts', MAX_ATTEMPTS);

    if (cleanupError) {
      console.error('Failed to clean up stale items:', cleanupError);
      // Continue anyway - this is not critical enough to abort the entire function
    }

    // Fetch pending notifications ready to send
    const now = new Date().toISOString();
    const { data: queue, error: queueError } = await supabase
      .from('notification_queue')
      .select('*')
      .eq('status', 'pending')
      .lte('scheduled_for', now)
      .order('created_at', { ascending: true })
      .limit(100);

    if (queueError) {
      console.error('Failed to fetch queue:', queueError);
      if (SENTRY_DSN) {
        Sentry.captureException(queueError, {
          tags: { operation: 'fetchQueue' },
        });
        await Sentry.flush(2000);
      }
      return new Response(JSON.stringify({ error: queueError.message }), {
        status: 500,
        headers,
      });
    }

    if (!queue || queue.length === 0) {
      return new Response(JSON.stringify({ processed: 0, message: 'No pending notifications' }), {
        headers,
      });
    }

    const queueItems = queue as QueueItem[];

    // Batch fetch: Get unique recipient user IDs
    const recipientIds = [...new Set(queueItems.map((item) => item.recipient_user_id))];

    // Batch fetch all preferences for these users (single query instead of N queries)
    const { data: allPrefs } = await supabase
      .from('notification_preferences')
      .select('*')
      .in('user_id', recipientIds);

    // Create a map for quick lookup
    const prefsMap = new Map<string, NotificationPreferences>();
    if (allPrefs) {
      for (const pref of allPrefs) {
        prefsMap.set(pref.user_id, pref as NotificationPreferences);
      }
    }

    // Batch fetch all active subscriptions for these users (single query instead of N queries)
    const { data: allSubscriptions } = await supabase
      .from('push_subscriptions')
      .select('*')
      .in('user_id', recipientIds)
      .eq('active', true);

    // Create a map of user_id -> subscriptions[]
    const subscriptionsMap = new Map<string, PushSubscription[]>();
    if (allSubscriptions) {
      for (const sub of allSubscriptions as PushSubscription[]) {
        const existing = subscriptionsMap.get(sub.user_id) || [];
        existing.push(sub);
        subscriptionsMap.set(sub.user_id, existing);
      }
    }

    const results: { id: string; status: string; error?: string }[] = [];
    const inboxInserts: Array<{
      recipient_user_id: string;
      type: string;
      title: string;
      body: string;
      event_id: string | null;
      participant_id: string | null;
      actor_user_id: string | null;
      action_url: string | null;
    }> = [];

    // Process each queue item using the pre-fetched data
    for (const item of queueItems) {
      let claimedItem: QueueItem | null = null;
      try {
        // Atomically claim this item by marking as processing and incrementing attempts
        // Use conditional update to prevent race conditions with concurrent function instances
        // Only update if status is still 'pending' (optimistic locking)
        const { data: updated, error: updateError } = await supabase
          .from('notification_queue')
          .update({
            status: 'processing',
            attempts: item.attempts + 1,
          })
          .eq('id', item.id)
          .eq('status', 'pending') // Only update if still pending
          .select()
          .single();

        // Distinguish between "no row updated" (claimed elsewhere) and real errors
        if (updateError) {
          if ((updateError as { code?: string }).code === 'PGRST116') {
            // No rows returned: another instance likely claimed this item first
            console.log(`Item ${item.id} already claimed by another instance, skipping`);
          } else {
            // Genuine error when trying to claim the item
            console.error(`Failed to claim item ${item.id} from notification_queue:`, updateError);
          }
          continue;
        }

        if (!updated) {
          // No data returned without an explicit error: treat as not claimed
          console.log(
            `Item ${item.id} was not updated (no data returned), likely claimed by another instance, skipping`
          );
          continue;
        }

        // Use the updated item with current attempts count from database
        const currentItem = updated as QueueItem;
        claimedItem = currentItem;

        // Check user preferences from the pre-fetched map
        const prefs = prefsMap.get(currentItem.recipient_user_id) || null;

        // Check if user wants this notification
        if (!shouldSendNotification(prefs, currentItem.notification_type)) {
          await supabase
            .from('notification_queue')
            .update({
              status: 'skipped',
              processed_at: new Date().toISOString(),
              last_error: 'User preferences',
            })
            .eq('id', currentItem.id);

          results.push({ id: currentItem.id, status: 'skipped' });
          continue;
        }

        // Get user's subscriptions from the pre-fetched map
        const subscriptions = subscriptionsMap.get(currentItem.recipient_user_id) || [];

        if (subscriptions.length === 0) {
          // No active subscriptions, skip but still save to inbox
          await supabase
            .from('notification_queue')
            .update({
              status: 'skipped',
              processed_at: new Date().toISOString(),
              last_error: 'No active push subscriptions',
            })
            .eq('id', currentItem.id);
        } else {
          // Send to all active subscriptions
          const pushPayload = {
            title: currentItem.title,
            body: currentItem.body,
            data: {
              type: currentItem.notification_type,
              url: currentItem.action_url,
              event_id: currentItem.event_id,
            },
          };

          let sentToAny = false;
          for (const sub of subscriptions) {
            const sent = await sendWebPush(sub, pushPayload, supabase);
            if (sent) sentToAny = true;
          }

          // Mark as sent
          await supabase
            .from('notification_queue')
            .update({
              status: sentToAny ? 'sent' : 'skipped',
              processed_at: new Date().toISOString(),
              last_error: sentToAny ? null : 'Push delivery failed',
            })
            .eq('id', currentItem.id);
        }

        // Queue inbox insert for batch processing
        inboxInserts.push({
          recipient_user_id: currentItem.recipient_user_id,
          type: currentItem.notification_type,
          title: currentItem.title,
          body: currentItem.body,
          event_id: currentItem.event_id,
          participant_id: currentItem.participant_id,
          actor_user_id: currentItem.actor_user_id,
          action_url: currentItem.action_url,
        });

        results.push({ id: currentItem.id, status: 'sent' });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        const itemId = claimedItem?.id || item.id;
        console.error(`Failed to process item ${itemId}:`, error);

        // Capture to Sentry with context
        if (SENTRY_DSN) {
          Sentry.captureException(error, {
            tags: {
              operation: 'processQueueItem',
              notificationType: item.notification_type,
            },
            extra: {
              itemId,
              recipientUserId: item.recipient_user_id,
              eventId: item.event_id,
              attempts: claimedItem?.attempts || item.attempts + 1,
            },
          });
        }

        // Retry or fail based on attempts
        // If we successfully claimed the item, use its attempts count; otherwise calculate from original
        const currentAttempts = claimedItem?.attempts || item.attempts + 1;
        const newStatus = currentAttempts >= 3 ? 'failed' : 'pending';
        await supabase
          .from('notification_queue')
          .update({
            status: newStatus,
            last_error: errorMessage,
          })
          .eq('id', itemId);

        results.push({ id: itemId, status: 'error', error: errorMessage });
      }
    }

    // Batch insert all inbox notifications
    let inboxError: string | null = null;
    if (inboxInserts.length > 0) {
      const { error: insertError } = await supabase.from('notifications').insert(inboxInserts);
      if (insertError) {
        // Log the error but don't fail the entire function - push notifications were already sent
        console.error('Failed to insert inbox notifications:', insertError);
        inboxError = insertError.message;
        if (SENTRY_DSN) {
          Sentry.captureException(insertError, {
            tags: { operation: 'insertInboxNotifications' },
            extra: { count: inboxInserts.length },
          });
        }
      }
    }

    // Flush Sentry before returning to ensure all events are sent
    if (SENTRY_DSN) {
      await Sentry.flush(2000);
    }

    return new Response(
      JSON.stringify({
        processed: results.length,
        results,
        ...(inboxError && { inboxError }),
      }),
      { headers }
    );
  } catch (error) {
    console.error('Edge function error:', error);

    // Capture to Sentry and flush before returning
    if (SENTRY_DSN) {
      Sentry.captureException(error, {
        tags: { operation: 'send-push-main' },
      });
      await Sentry.flush(2000);
    }

    return new Response(
      JSON.stringify({
        error: error instanceof Error ? error.message : 'Internal error',
      }),
      { status: 500, headers }
    );
  }
});

/**
 * Process Scheduled Notifications Edge Function
 *
 * Handles time-based notifications like payment reminders (24hr after event).
 * Should be triggered by a cron job (e.g., every hour).
 *
 * Can be set up in Supabase Dashboard:
 * - Go to Database > Webhooks
 * - Or use pg_cron if available
 */

import { serve } from 'https://deno.land/std@0.177.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.0';
import * as Sentry from 'https://deno.land/x/sentry/index.mjs';

// Initialize Sentry
const SENTRY_DSN = Deno.env.get('SENTRY_DSN');
if (SENTRY_DSN) {
  Sentry.init({
    dsn: SENTRY_DSN,
    defaultIntegrations: false,
    tracesSampleRate: 1.0,
    environment: Deno.env.get('SENTRY_ENVIRONMENT') || 'production',
  });

  // Set Supabase-specific tags
  Sentry.setTag('region', Deno.env.get('SB_REGION'));
  Sentry.setTag('execution_id', Deno.env.get('SB_EXECUTION_ID'));
  Sentry.setTag('function', 'process-scheduled');
}

// Environment variables
const SUPABASE_URL = Deno.env.get('SUPABASE_URL')!;
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;

serve(async (req) => {
  // CORS headers
  const headers = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  };

  // Handle CORS preflight
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers });
  }

  try {
    // Create Supabase client with service role
    const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

    const now = new Date();
    let queued = 0;

    // =========================================================================
    // Payment Reminders (24 hours after event ends)
    // =========================================================================
    const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);
    const twentyFiveHoursAgo = new Date(now.getTime() - 25 * 60 * 60 * 1000);

    // Find events that ended between 24-25 hours ago with unpaid participants
    const { data: unpaidParticipants, error: participantsError } = await supabase
      .from('participants')
      .select(
        `
        id,
        name,
        user_id,
        claimed_by_user_id,
        event_id,
        events!inner (
          id,
          name,
          datetime,
          end_datetime
        )
      `
      )
      .eq('payment_status', 'pending')
      .or('user_id.not.is.null,claimed_by_user_id.not.is.null');

    if (participantsError) {
      console.error('Failed to fetch unpaid participants:', participantsError);
      if (SENTRY_DSN) {
        Sentry.captureException(participantsError, {
          tags: { operation: 'fetchUnpaidParticipants' },
        });
      }
    } else if (unpaidParticipants) {
      // Batch-load existing payment reminders for all relevant participants
      // Collect all participant IDs in the current batch
      const participantIds = unpaidParticipants.map((p: { id: string }) => p.id);

      // Fetch existing queued payment reminders for these participants
      const { data: existingQueueReminders, error: existingQueueError } = await supabase
        .from('notification_queue')
        .select('participant_id')
        .in('participant_id', participantIds)
        .eq('notification_type', 'payment_reminder');

      if (existingQueueError) {
        console.error(
          'Failed to fetch existing payment reminders from notification_queue:',
          existingQueueError
        );
        if (SENTRY_DSN) {
          Sentry.captureException(existingQueueError, {
            tags: { operation: 'fetchExistingQueueReminders' },
          });
        }
      }

      // Fetch already-sent payment reminders from notifications table
      const { data: existingNotifications, error: existingNotificationsError } = await supabase
        .from('notifications')
        .select('participant_id')
        .in('participant_id', participantIds)
        .eq('type', 'payment_reminder');

      if (existingNotificationsError) {
        console.error(
          'Failed to fetch existing payment reminders from notifications:',
          existingNotificationsError
        );
        if (SENTRY_DSN) {
          Sentry.captureException(existingNotificationsError, {
            tags: { operation: 'fetchExistingNotifications' },
          });
        }
      }

      // Build lookup sets for quick membership tests inside the loop
      const queuedReminderParticipantIds = new Set(
        (existingQueueReminders ?? []).map((row: { participant_id: string }) => row.participant_id)
      );
      const sentReminderParticipantIds = new Set(
        (existingNotifications ?? []).map((row: { participant_id: string }) => row.participant_id)
      );

      for (const participant of unpaidParticipants) {
        // Get event end time (fall back to datetime if no end_datetime)
        const event = participant.events as {
          id: string;
          name: string;
          datetime: string;
          end_datetime: string | null;
        };
        const eventEndTime = event.end_datetime || event.datetime;

        if (!eventEndTime) continue;

        const endDate = new Date(eventEndTime);

        // Check if event ended between 24-25 hours ago
        if (endDate < twentyFiveHoursAgo || endDate > twentyFourHoursAgo) {
          continue;
        }

        const userId = participant.user_id || participant.claimed_by_user_id;
        if (!userId) continue;

        // Skip if a reminder is already queued for this participant
        if (queuedReminderParticipantIds.has(participant.id)) {
          continue;
        }

        // Also skip if a notification has already been sent for this participant
        if (sentReminderParticipantIds.has(participant.id)) {
          continue;
        }
        // Queue payment reminder
        const { error: insertError } = await supabase.from('notification_queue').insert({
          recipient_user_id: userId,
          notification_type: 'payment_reminder',
          title: 'Payment reminder',
          body: `Don't forget to pay for ${event.name}`,
          event_id: participant.event_id,
          participant_id: participant.id,
          action_url: `/events/${participant.event_id}`,
        });

        if (!insertError) {
          queued++;
        } else {
          console.error('Failed to queue payment reminder:', insertError);
          if (SENTRY_DSN) {
            Sentry.captureException(insertError, {
              tags: { operation: 'queuePaymentReminder' },
              extra: {
                participantId: participant.id,
                eventId: participant.event_id,
                userId,
              },
            });
          }
        }
      }
    }

    // =========================================================================
    // Trigger send-push function to process the queue
    // =========================================================================
    if (queued > 0) {
      try {
        // Invoke the send-push function
        const response = await fetch(`${SUPABASE_URL}/functions/v1/send-push`, {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
            'Content-Type': 'application/json',
          },
        });

        if (!response.ok) {
          const errorText = await response.text();
          console.error('Failed to trigger send-push:', errorText);
          if (SENTRY_DSN) {
            Sentry.captureMessage(`Failed to trigger send-push: ${errorText}`, {
              level: 'error',
              tags: { operation: 'triggerSendPush' },
              extra: { statusCode: response.status, queued },
            });
          }
        }
      } catch (error) {
        console.error('Failed to invoke send-push:', error);
        if (SENTRY_DSN) {
          Sentry.captureException(error, {
            tags: { operation: 'invokeSendPush' },
            extra: { queued },
          });
        }
      }
    }

    // Flush Sentry before returning to ensure all events are sent
    if (SENTRY_DSN) {
      await Sentry.flush(2000);
    }

    return new Response(
      JSON.stringify({
        queued,
        message:
          queued > 0
            ? `Queued ${queued} payment reminders`
            : 'No scheduled notifications to process',
      }),
      { headers }
    );
  } catch (error) {
    console.error('Edge function error:', error);

    // Capture to Sentry and flush before returning
    if (SENTRY_DSN) {
      Sentry.captureException(error, {
        tags: { operation: 'process-scheduled-main' },
      });
      await Sentry.flush(2000);
    }

    return new Response(
      JSON.stringify({
        error: error instanceof Error ? error.message : 'Internal error',
      }),
      { status: 500, headers }
    );
  }
});

/**
 * Push notification handler for the service worker
 * This file is imported by the main service worker via workbox.importScripts
 */

// Handle push notification events
self.addEventListener('push', (event) => {
  if (!event.data) {
    console.warn('Push event received but no data');
    return;
  }

  let data;
  try {
    data = event.data.json();
  } catch {
    console.warn('Failed to parse push data as JSON');
    data = {
      title: 'New Notification',
      body: event.data.text(),
    };
  }

  const title = data.title || 'Roster';
  const options = {
    body: data.body || '',
    icon: '/icon-192x192.svg',
    badge: '/icon-192x192.svg',
    tag: data.data?.type || 'default',
    renotify: true,
    data: data.data || {},
    // Vibration pattern for mobile devices
    vibrate: [100, 50, 100],
    // Actions the user can take
    actions: [
      {
        action: 'open',
        title: 'View',
      },
      {
        action: 'dismiss',
        title: 'Dismiss',
      },
    ],
  };

  event.waitUntil(self.registration.showNotification(title, options));
});

// Handle notification click events
self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  // Handle dismiss action
  if (event.action === 'dismiss') {
    return;
  }

  // Get the URL to navigate to (from notification data or default)
  const urlPath = event.notification.data?.url || '/';

  event.waitUntil(
    clients
      .matchAll({
        type: 'window',
        includeUncontrolled: true,
      })
      .then((clientList) => {
        // Check if there's already a window open with the app
        for (const client of clientList) {
          if (client.url.includes(self.location.origin) && 'focus' in client) {
            // Navigate to the notification URL and focus the window
            return client.navigate(urlPath).then((client) => client?.focus());
          }
        }
        // If no existing window, open a new one
        return clients.openWindow(urlPath);
      })
  );
});

// Handle notification close events (optional analytics)
self.addEventListener('notificationclose', (event) => {
  // Could send analytics about dismissed notifications
  console.log('Notification dismissed:', event.notification.tag);
});

/**
 * Get VAPID public key from IndexedDB (stored by main app on subscription)
 */
async function getVapidKeyFromStorage() {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('push-config', 1);

    request.onerror = () => reject(request.error);

    request.onupgradeneeded = (event) => {
      const db = event.target.result;
      if (!db.objectStoreNames.contains('config')) {
        db.createObjectStore('config');
      }
    };

    request.onsuccess = () => {
      const db = request.result;
      const tx = db.transaction('config', 'readonly');
      const store = tx.objectStore('config');
      const getRequest = store.get('vapidPublicKey');

      getRequest.onsuccess = () => {
        db.close();
        resolve(getRequest.result);
      };
      getRequest.onerror = () => {
        db.close();
        reject(getRequest.error);
      };
    };
  });
}

/**
 * Convert URL-safe base64 to Uint8Array
 */
function urlBase64ToUint8Array(base64String) {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const rawData = atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

// Handle push subscription change events
self.addEventListener('pushsubscriptionchange', (event) => {
  // This fires when the push subscription expires or is revoked
  console.log('Push subscription changed, attempting re-subscription');

  event.waitUntil(
    (async () => {
      try {
        // Get stored VAPID key
        const vapidKey = await getVapidKeyFromStorage();
        if (!vapidKey) {
          console.warn('No VAPID key stored, cannot re-subscribe');
          return;
        }

        // Re-subscribe with the stored VAPID key
        const subscription = await self.registration.pushManager.subscribe({
          userVisibleOnly: true,
          applicationServerKey: urlBase64ToUint8Array(vapidKey),
        });

        console.log('Re-subscribed to push:', subscription.endpoint);

        // Note: The new subscription endpoint should be synced to the server.
        // This will happen automatically when the user opens the app, as the
        // subscription will be detected and updated via pushSubscriptionService.
      } catch (error) {
        console.error('Failed to re-subscribe to push:', error);
      }
    })()
  );
});

