export type { SignupFormData };

interface SignupFormDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  defaultValues: SignupFormData;
  customFields: CustomField[];
  isClaimingForOther: boolean;
  hasExistingRegistration: boolean;
  submitting: boolean;
  onSubmit: (data: SignupFormData) => void;
  onWithdraw: () => void;
  onQuickFill: () => void;
}

/**
 * Drawer component containing the event signup form.
 * Handles both new registrations and updates to existing registrations.
 */
export function SignupFormDrawer({
  open,
  onOpenChange,
  defaultValues,
  customFields,
  isClaimingForOther,
  hasExistingRegistration,
  submitting,
  onSubmit,
  onWithdraw,
  onQuickFill,
}: SignupFormDrawerProps) {
  const {
    register,
    handleSubmit,
    reset,
    setValue,
    watch,
    formState: { errors },
  } = useForm<SignupFormData>({
    resolver: zodResolver(signupFormSchema),
    defaultValues,
  });

  const responses = watch('responses');

  // Reset form when drawer opens or defaultValues change
  useEffect(() => {
    if (open) {
      reset(defaultValues);
    }
  }, [open, defaultValues, reset]);

  const handleResponseChange = (fieldId: string, value: string) => {
    setValue('responses', {
      ...responses,
      [fieldId]: value,
    });
  };

  const registrationFields = (
    <>
      <div className="space-y-1.5">
        <Label htmlFor="signup-name" className="text-xs">
          Name *
        </Label>
        <Input
          id="signup-name"
          type="text"
          {...register('name')}
          autoComplete="off"
          className={`h-9 text-sm ${errors.name ? 'border-destructive' : ''}`}
        />
        {errors.name && <p className="text-xs text-destructive">{errors.name.message}</p>}
      </div>

      {!isClaimingForOther && (
        <>
          <div className="space-y-1.5">
            <Label htmlFor="signup-email" className="text-xs">
              Email (optional)
            </Label>
            <Input
              id="signup-email"
              type="email"
              {...register('email')}
              autoComplete="off"
              className={`h-9 text-sm ${errors.email ? 'border-destructive' : ''}`}
            />
            {errors.email && <p className="text-xs text-destructive">{errors.email.message}</p>}
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="signup-phone" className="text-xs">
              Phone (optional)
            </Label>
            <Input
              id="signup-phone"
              type="tel"
              {...register('phone')}
              autoComplete="off"
              className={`h-9 text-sm ${errors.phone ? 'border-destructive' : ''}`}
            />
          </div>
        </>
      )}

      {customFields && customFields.length > 0 && (
        <div className="pt-2">
          <h3 className="text-sm font-medium">Additional Information</h3>
          {customFields.map((field) => (
            <div key={field.id} className="space-y-1.5 mb-2">
              <Label htmlFor={`signup-${field.id}`} className="text-xs">
                {field.label} {field.required && '*'}
              </Label>
              {field.type === 'select' && field.options ? (
                <Select
                  value={responses[field.id || ''] || ''}
                  onValueChange={(value) => handleResponseChange(field.id || '', value)}
                >
                  <SelectTrigger className="h-9 text-sm">
                    <SelectValue placeholder="Select..." />
                  </SelectTrigger>
                  <SelectContent>
                    {field.options.map((option: string) => (
                      <SelectItem key={option} value={option}>
                        {option}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              ) : (
                <Input
                  id={`signup-${field.id}`}
                  type={field.type}
                  value={responses[field.id || ''] || ''}
                  onChange={(e) => handleResponseChange(field.id || '', e.target.value)}
                  required={field.required}
                  autoComplete="off"
                  className="h-9 text-sm"
                />
              )}
            </div>
          ))}
        </div>
      )}
    </>
  );

  return (
    <FormDrawer
      open={open}
      onOpenChange={onOpenChange}
      footer={
        <div className="flex gap-1.5 w-full">
          {hasExistingRegistration && !isClaimingForOther && (
            <Button
              variant="destructive"
              size="sm"
              className="flex-1 h-10"
              onClick={onWithdraw}
              disabled={submitting}
            >
              <UserX className="h-4 w-4 mr-2" />
              Withdraw
            </Button>
          )}
          {!hasExistingRegistration && !isClaimingForOther && (
            <Button
              variant="outline"
              size="sm"
              className="flex-1 h-10"
              onClick={onQuickFill}
              disabled={submitting}
            >
              <Zap className="h-4 w-4 mr-2" />
              Quick Fill
            </Button>
          )}
          <Button
            type="submit"
            form="signup-form"
            size="sm"
            className="flex-1 bg-primary hover:bg-primary/90 text-white h-10"
            disabled={submitting}
          >
            {submitting ? (
              isClaimingForOther ? (
                'Claiming...'
              ) : hasExistingRegistration ? (
                'Updating...'
              ) : (
                'Joining...'
              )
            ) : isClaimingForOther ? (
              'Claim'
            ) : hasExistingRegistration ? (
              <>
                <UserCheck className="h-4 w-4 mr-2" />
                Update
              </>
            ) : (
              <>
                <UserPlus className="h-4 w-4 mr-2" />
                Join Event
              </>
            )}
          </Button>
        </div>
      }
    >
      <form
        id="signup-form"
        onSubmit={handleSubmit(onSubmit, showFormErrors)}
        className="space-y-2 pt-3 pb-3"
      >
        {isClaimingForOther ? (
          <div className="space-y-2 mt-2">{registrationFields}</div>
        ) : (
          <Tabs defaultValue="registration" className="w-full">
            <TabsList className="w-full h-10">
              <TabsTrigger value="registration" className="flex-1">
                Registration
              </TabsTrigger>
              <TabsTrigger value="notes" className="flex-1">
                Notes
              </TabsTrigger>
            </TabsList>
            <TabsContent value="registration" className="space-y-2 mt-2">
              {registrationFields}
            </TabsContent>

            <TabsContent value="notes" className="space-y-2 mt-2">
              <div className="space-y-1.5">
                <Label htmlFor="signup-notes" className="text-xs">
                  Notes (optional)
                </Label>
                <Textarea
                  id="signup-notes"
                  {...register('notes')}
                  placeholder="Any additional notes or comments..."
                  className="min-h-[300px] text-sm"
                />
              </div>
            </TabsContent>
          </Tabs>
        )}
      </form>
    </FormDrawer>
  );
}

import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { setStorageItem } from '@/lib/storage';

interface ProtectedRouteProps {
  children: React.ReactNode;
}

export function ProtectedRoute({ children }: ProtectedRouteProps) {
  const { user, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-sm text-muted-foreground">Loading...</div>
      </div>
    );
  }

  if (!user) {
    // Store the current path so we can redirect back after login
    setStorageItem('returnUrl', location.pathname + location.search);
    return <Navigate to="/auth/login" replace />;
  }

  return <>{children}</>;
}

import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { FormDrawer } from '@/components/FormDrawer';
import { Input } from '@/components/ui/input';
import { DateTimeInput } from '@/components/DateTimeInput';
import { Copy } from 'lucide-react';
import { toLocalInputValue, fromLocalInputValue } from '@/lib/utils';

interface DuplicateEventDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  eventName: string;
  datetime: string | null;
  endDatetime: string | null;
  submitting: boolean;
  onConfirm: (name: string, datetime: string | null, endDatetime: string | null) => void;
}

export function DuplicateEventDrawer({
  open,
  onOpenChange,
  eventName,
  datetime,
  endDatetime,
  submitting,
  onConfirm,
}: DuplicateEventDrawerProps) {
  const [name, setName] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    if (open) {
      setName(`${eventName} (Copy)`);
      setStartDate(datetime ? toLocalInputValue(datetime) : '');
      setEndDate(endDatetime ? toLocalInputValue(endDatetime) : '');
    }
  }, [open, eventName, datetime, endDatetime]);

  const handleConfirm = () => {
    onConfirm(
      name.trim(),
      startDate ? fromLocalInputValue(startDate) : null,
      endDate ? fromLocalInputValue(endDate) : null
    );
  };

  return (
    <FormDrawer
      open={open}
      onOpenChange={onOpenChange}
      footer={
        <Button
          className="w-full bg-primary hover:bg-primary/90 text-white disabled:opacity-50 disabled:pointer-events-none"
          disabled={submitting || !name.trim() || !!(startDate && endDate && endDate <= startDate)}
          onClick={handleConfirm}
        >
          <Copy className="h-4 w-4 mr-2" />
          {submitting ? 'Duplicating...' : 'Duplicate Event'}
        </Button>
      }
    >
      <div className="space-y-4 pt-3 pb-3">
        <div className="space-y-2">
          <Label htmlFor="dup-name" className="text-sm">
            Event Name
          </Label>
          <Input
            id="dup-name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="h-10 text-sm"
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="dup-start" className="text-sm">
            Start Date & Time
          </Label>
          <DateTimeInput
            id="dup-start"
            value={startDate}
            onChange={(value) => {
              setStartDate(value);
              if (value && (!endDate || value >= endDate)) setEndDate(value);
            }}
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="dup-end" className="text-sm">
            End Date & Time
          </Label>
          <DateTimeInput
            id="dup-end"
            value={endDate}
            onChange={(value) => {
              setEndDate(value);
            }}
            error={!!(startDate && endDate && endDate <= startDate)}
          />
        </div>
      </div>
    </FormDrawer>
  );
}

