export function BottomNav() {
  const location = useLocation();
  const { user } = useAuth();
  const isHomePageEnabled = useFeatureFlag('home_page');

  // Hide navigation for non-authenticated users
  if (!user) {
    return null;
  }

  // Filter out Home nav item if home_page flag is disabled
  const visibleNavItems = navItems.filter((item) => item.path !== '/' || isHomePageEnabled);

  return (
    <nav
      className="fixed bottom-0 left-0 right-0 bg-card border-t border-border z-50"
      role="navigation"
      aria-label="Main navigation"
    >
      <div className="flex justify-around items-center h-14">
        {visibleNavItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;
          return (
            <Link
              key={item.path}
              to={item.path}
              className={cn(
                'flex flex-col items-center justify-center flex-1 h-full py-1 text-xs',
                isActive ? 'text-primary' : 'text-muted-foreground'
              )}
              aria-label={`Navigate to ${item.label}`}
              aria-current={isActive ? 'page' : undefined}
            >
              <Icon className="h-5 w-5 mb-1" aria-hidden="true" />
              <span>{item.label}</span>
            </Link>
          );
        })}
      </div>
    </nav>
  );
}

import { useEffect, useState } from 'react';
import { Smartphone } from 'lucide-react';

export function MobileOnly({ children }: { children: React.ReactNode }) {
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const checkDevice = () => {
      const width = window.innerWidth;
      setIsMobile(width < 768); // Mobile if less than 768px (tablet breakpoint)
    };

    checkDevice();
    window.addEventListener('resize', checkDevice);
    return () => window.removeEventListener('resize', checkDevice);
  }, []);

  if (!isMobile) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center p-8">
        <div className="text-center max-w-md">
          <Smartphone className="w-24 h-24 mx-auto text-muted-foreground mb-6" />
          <h1 className="text-2xl font-bold text-foreground mb-4">Mobile Access Only</h1>
          <p className="text-muted-foreground">
            This platform is designed for mobile use only. Please open this page on your phone to
            continue.
          </p>
        </div>
      </div>
    );
  }

  return <>{children}</>;
}

