import { PaymentStatusBadge } from '@/components/PaymentStatusBadge';
import type { Participant as ServiceParticipant, Label as LabelType } from '@/services';
import type { CustomField } from '@/types/app.types';

type Participant = ServiceParticipant & {
  notes?: string | null;
  user_id?: string | null;
};

interface ParticipantDetailsSheetProps {
  participant: Participant | null;
  labels: LabelType[];
  customFields: CustomField[];
  isOrganizer: boolean;
  isPaid: boolean;
  onClose: () => void;
  onTogglePayment: (participant: Participant) => void;
  onToggleLabel: (participant: Participant, label: LabelType) => void;
}

/**
 * Sheet component for displaying and editing participant details.
 * Shows contact info, payment status, custom field responses, and labels.
 */
export function ParticipantDetailsSheet({
  participant,
  labels,
  customFields,
  isOrganizer,
  isPaid,
  onClose,
  onTogglePayment,
  onToggleLabel,
}: ParticipantDetailsSheetProps) {
  if (!participant) return null;

  return (
    <Sheet open={!!participant} onOpenChange={(open) => !open && onClose()}>
      <SheetContent side="bottom" className="h-[80vh]">
        <SheetHeader>
          <SheetTitle>{participant.name}</SheetTitle>
        </SheetHeader>
        <div className="mt-3 space-y-2">
          <div className="space-y-1.5">
            <h3 className="text-sm font-medium">Contact Information</h3>
            <div className="text-sm space-y-0.5">
              <div>Email: {participant.email || 'Not provided'}</div>
              <div>Phone: {participant.phone || 'Not provided'}</div>
              <div>Registered: {new Date(participant.created_at).toLocaleString()}</div>
            </div>
          </div>

          {isOrganizer && isPaid && (
            <div className="space-y-1.5">
              <h3 className="text-sm font-medium">Payment Status</h3>
              <div className="flex items-center gap-2">
                <PaymentStatusBadge status={participant.payment_status} size="md" />
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => onTogglePayment(participant)}
                  className="text-xs h-7 px-3"
                >
                  {participant.payment_status === 'paid' ? 'Mark as Pending' : 'Mark as Paid'}
                </Button>
              </div>
              {participant.payment_marked_at && (
                <div className="text-xs text-muted-foreground">
                  Updated: {new Date(participant.payment_marked_at).toLocaleString()}
                </div>
              )}
              {participant.payment_notes && (
                <div className="text-xs text-muted-foreground">
                  Notes: {participant.payment_notes}
                </div>
              )}
            </div>
          )}

          {customFields && customFields.length > 0 && (
            <div className="space-y-1.5">
              <h3 className="text-sm font-medium">Additional Information</h3>
              <div className="text-sm space-y-0.5">
                {customFields.map((field) => (
                  <div key={field.id}>
                    {field.label}: {participant.responses[field.id || ''] || 'Not provided'}
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="space-y-1.5">
            <h3 className="text-sm font-medium">Labels</h3>
            <div className="flex flex-wrap gap-1.5">
              {labels.map((label) => {
                const hasLabel = participant.labels?.some((l) => l.id === label.id) || false;
                return (
                  <button
                    key={label.id}
                    onClick={() => onToggleLabel(participant, label)}
                    className={`px-2.5 py-0.5 text-xs rounded-full border transition-colors ${
                      hasLabel
                        ? 'bg-primary text-white border-primary'
                        : 'bg-card text-muted-foreground border-border hover:bg-muted'
                    }`}
                  >
                    {label.name}
                  </button>
                );
              })}
            </div>
          </div>
        </div>
      </SheetContent>
    </Sheet>
  );
}

import { Button } from '@/components/ui/button';
import { LoadingSpinner } from '@/components/LoadingStates';

interface ActionButtonProps {
  loading?: boolean;
  disabled?: boolean;
  onClick?: (e?: React.MouseEvent<HTMLButtonElement>) => void;
  type?: 'button' | 'submit';
  form?: string;
  children: React.ReactNode;
  loadingText?: string;
  size?: 'default' | 'sm' | 'lg';
}

/**
 * Reusable action button component for consistent hover buttons across the app.
 * Positioned as a fixed button above the bottom navigation bar.
 */
export function ActionButton({
  loading = false,
  disabled = false,
  onClick,
  type = 'button',
  form,
  children,
  loadingText = 'Loading...',
  size = 'default',
}: ActionButtonProps) {
  const isDisabled = loading || disabled;

  return (
    <div className="fixed bottom-16 left-0 right-0 z-40 px-3 pb-2">
      <Button
        type={type}
        form={form}
        onClick={onClick}
        className={`w-full text-white shadow-lg drop-shadow-md ${
          isDisabled
            ? 'bg-muted text-muted-foreground cursor-not-allowed'
            : 'bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600'
        }`}
        disabled={isDisabled}
        size={size}
      >
        {loading ? (
          <>
            <LoadingSpinner size="sm" />
            {loadingText}
          </>
        ) : (
          children
        )}
      </Button>
    </div>
  );
}

import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Plus, Trash2 } from 'lucide-react';
import type { CustomField } from '@/types/app.types';

interface CustomFieldsEditorProps {
  customFields: CustomField[];
  onAdd: () => void;
  onUpdate: (id: string, updates: Partial<CustomField>) => void;
  onRemove: (id: string) => void;
}

/**
 * Reusable component for editing custom form fields in event creation/editing.
 * Supports text, email, phone, number, and dropdown field types.
 */
export function CustomFieldsEditor({
  customFields,
  onAdd,
  onUpdate,
  onRemove,
}: CustomFieldsEditorProps) {
  return (
    <div>
      <div className="flex items-center justify-between">
        <h2 className="text-sm font-medium">Custom Fields</h2>
        <Button type="button" size="sm" variant="outline" className="h-8 px-2" onClick={onAdd}>
          <Plus className="h-3 w-3 mr-1" />
          Add Field
        </Button>
      </div>

      {customFields.length > 0 && (
        <div className="space-y-3 mt-3">
          {customFields.map((field) => (
            <div key={field.id} className="p-3 bg-muted rounded border space-y-2">
              <div className="flex items-center gap-2">
                <Input
                  type="text"
                  value={field.label}
                  onChange={(e) => field.id && onUpdate(field.id, { label: e.target.value })}
                  placeholder="Field label"
                  className="flex-1 h-9 text-sm"
                />
                <button
                  type="button"
                  onClick={() => field.id && onRemove(field.id)}
                  className="text-destructive hover:text-destructive/80"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
              </div>
              <div className="flex items-center gap-2">
                <Select
                  value={field.type}
                  onValueChange={(value) => {
                    if (!field.id) return;
                    const nextType = value as CustomField['type'];
                    onUpdate(field.id, {
                      type: nextType,
                      ...(nextType === 'select'
                        ? {
                            options:
                              field.options && field.options.length > 0 ? field.options : [''],
                          }
                        : field.type === 'select'
                          ? { options: field.options }
                          : {}),
                    });
                  }}
                >
                  <SelectTrigger className="flex-1 h-9 text-sm">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="text">Text</SelectItem>
                    <SelectItem value="email">Email</SelectItem>
                    <SelectItem value="tel">Phone</SelectItem>
                    <SelectItem value="number">Number</SelectItem>
                    <SelectItem value="select">Dropdown</SelectItem>
                  </SelectContent>
                </Select>
                <label className="flex items-center gap-1.5 text-xs cursor-pointer">
                  <Checkbox
                    checked={field.required}
                    onCheckedChange={(checked) =>
                      field.id &&
                      onUpdate(field.id, {
                        required: checked === true,
                      })
                    }
                  />
                  Required
                </label>
              </div>
              {field.type === 'select' && (
                <div className="space-y-2">
                  <Label className="text-xs">Options (one per line)</Label>
                  <Textarea
                    value={field.options?.join('\n') || ''}
                    onChange={(e) =>
                      field.id &&
                      onUpdate(field.id, {
                        options: e.target.value.split('\n').filter(Boolean),
                      })
                    }
                    placeholder="Option 1&#10;Option 2&#10;Option 3"
                    className="text-sm resize-none"
                    rows={3}
                  />
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Spinner } from '@/components/ui/spinner';
import { UserAvatar } from '@/components/UserAvatar';
import { PaymentStatusBadge } from '@/components/PaymentStatusBadge';
import { DollarSign, Trash2, UserPlus } from 'lucide-react';
import type { Participant as ServiceParticipant, Label as LabelType } from '@/services';

type Participant = ServiceParticipant & {
  notes?: string | null;
  user_id?: string | null;
};

interface ParticipantListItemProps {
  participant: Participant;
  displayName: string;
  displayNumber: number;
  isOrganizer: boolean;
  isOrganizerItem: boolean;
  isOwnClaimedSpot: boolean;
  claimNumber: string | null;
  isPaid: boolean;
  isArchived: boolean;
  showRegistrationForm: boolean;
  onSelect: (participant: Participant) => void;
  onTogglePayment: (participant: Participant) => void | Promise<void>;
  onWithdraw: (participant: Participant) => void;
}

/**
 * Renders a single participant row in the event detail page's participant list.
 * Handles display of participant info, badges, payment status, and action buttons.
 */
export function ParticipantListItem({
  participant,
  displayName,
  displayNumber,
  isOrganizer,
  isOrganizerItem,
  isOwnClaimedSpot,
  claimNumber,
  isPaid,
  isArchived,
  showRegistrationForm,
  onSelect,
  onTogglePayment,
  onWithdraw,
}: ParticipantListItemProps) {
  const [isTogglingPayment, setIsTogglingPayment] = useState(false);

  const handleTogglePayment = async (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsTogglingPayment(true);
    try {
      await onTogglePayment(participant);
    } finally {
      setIsTogglingPayment(false);
    }
  };

  return (
    <div
      className={`px-3 py-2 hover:bg-muted transition-colors ${isOrganizerItem ? 'bg-primary/5' : isOwnClaimedSpot ? 'bg-primary/5' : ''}`}
    >
      <div className="flex items-center gap-3">
        <div className="text-xs text-muted-foreground font-mono flex-shrink-0">
          {displayNumber}.
        </div>
        <UserAvatar name={displayName} avatarUrl={participant.avatar_url} size="sm" />
        <div className="flex-1 min-w-0 flex justify-between items-center gap-2">
          {/* Left column: name, badges */}
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-1.5 min-w-0">
              {showRegistrationForm ? (
                <button
                  onClick={() => onSelect(participant)}
                  className="text-sm font-medium text-foreground hover:text-foreground/80 transition-colors truncate text-left min-w-0 max-w-full"
                >
                  {displayName}
                </button>
              ) : (
                <span className="text-sm font-medium text-foreground truncate min-w-0 max-w-full">
                  {displayName}
                </span>
              )}
              {isOrganizerItem && (
                <span className="flex-shrink-0 text-[10px] leading-none px-1.5 py-0.5 rounded-full bg-gradient-to-r from-purple-100 to-pink-100 border border-purple-200/50 bg-clip-padding">
                  <span className="bg-gradient-to-r from-purple-500 to-pink-500 bg-clip-text text-transparent font-medium">
                    Organizer
                  </span>
                </span>
              )}
              {isOwnClaimedSpot && claimNumber && (
                <Badge variant="outline" className="text-xs h-5 px-1">
                  +{claimNumber}
                </Badge>
              )}
            </div>
            <div className="flex flex-wrap gap-1 mt-1">
              {participant.labels?.map((label: LabelType) => (
                <Badge key={label.id} variant="outline" className="text-xs h-5">
                  {label.name}
                </Badge>
              ))}
            </div>
          </div>
          {/* Right column: badges and action buttons */}
          <div className="flex flex-col gap-2 flex-shrink-0 items-end">
            {isPaid && isOrganizer && participant.payment_status !== 'pending' && (
              <button onClick={handleTogglePayment} disabled={isTogglingPayment}>
                {isTogglingPayment ? (
                  <Spinner className="h-4 w-4" />
                ) : (
                  <PaymentStatusBadge status={participant.payment_status} size="sm" />
                )}
              </button>
            )}
            {isOrganizer && participant.payment_status === 'pending' && (
              <div className="flex gap-2">
                {isPaid && (
                  <Button
                    size="icon"
                    variant="outline"
                    onClick={handleTogglePayment}
                    disabled={isTogglingPayment}
                    className="h-8 w-8"
                    title="Mark Paid"
                  >
                    {isTogglingPayment ? (
                      <Spinner className="h-4 w-4" />
                    ) : (
                      <DollarSign className="h-4 w-4" />
                    )}
                  </Button>
                )}
                {!isOrganizerItem && !isArchived && (
                  <Button
                    size="icon"
                    variant="outline"
                    onClick={(e) => {
                      e.stopPropagation();
                      onWithdraw(participant);
                    }}
                    className="h-8 w-8 text-destructive border-destructive hover:text-destructive hover:bg-destructive/10"
                    title="Remove"
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

