import * as React from 'react';
import { format } from 'date-fns';
import { ChevronDownIcon } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Calendar } from '@/components/ui/calendar';
import { Input } from '@/components/ui/input';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';

interface DateTimeInputProps {
  value: string;
  onChange: (value: string) => void;
  id?: string;
  className?: string;
  disabled?: boolean;
  error?: boolean;
}

/**
 * DateTime picker with calendar popover and time input
 * Converts between datetime-local format (YYYY-MM-DDTHH:mm) and Date object
 */
export function DateTimeInput({
  value,
  onChange,
  id,
  className,
  disabled,
  error,
}: DateTimeInputProps) {
  const [open, setOpen] = React.useState(false);

  // Parse datetime-local string to Date object
  const parseDateTime = (datetimeLocal: string): Date | undefined => {
    if (!datetimeLocal) return undefined;
    return new Date(datetimeLocal);
  };

  // Format Date back to datetime-local string (YYYY-MM-DDTHH:mm)
  const formatDateTime = (date: Date): string => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    return `${year}-${month}-${day}T${hours}:${minutes}`;
  };

  // Extract time string (HH:mm) from datetime-local value
  const getTimeValue = (datetimeLocal: string): string => {
    if (!datetimeLocal) return '';
    const date = parseDateTime(datetimeLocal);
    if (!date) return '';
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    return `${hours}:${minutes}`;
  };

  const selectedDate = parseDateTime(value);
  const timeValue = getTimeValue(value);

  const handleDateSelect = (date: Date | undefined) => {
    if (date) {
      // Preserve existing time if available, otherwise default to 12:00
      if (selectedDate) {
        date.setHours(selectedDate.getHours());
        date.setMinutes(selectedDate.getMinutes());
      } else {
        date.setHours(12);
        date.setMinutes(0);
      }
      onChange(formatDateTime(date));
      setOpen(false);
    }
  };

  const handleTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const timeString = e.target.value;
    if (!timeString) return;

    const [hours, minutes] = timeString.split(':').map(Number);
    const currentDate = selectedDate || new Date();
    const newDate = new Date(currentDate);
    newDate.setHours(hours);
    newDate.setMinutes(minutes);
    onChange(formatDateTime(newDate));
  };

  if (disabled) {
    return (
      <div className={cn('flex gap-2', className)}>
        <Button
          variant="outline"
          id={id}
          disabled
          className="h-10 flex-1 justify-between font-normal opacity-50 cursor-not-allowed"
        >
          <span className="text-muted-foreground">TBD</span>
          <ChevronDownIcon className="h-4 w-4 opacity-50" />
        </Button>
        <Input
          type="time"
          disabled
          className="h-10 flex-1 bg-background opacity-50 cursor-not-allowed appearance-none [&::-webkit-calendar-picker-indicator]:hidden [&::-webkit-calendar-picker-indicator]:appearance-none"
        />
      </div>
    );
  }

  return (
    <div className={cn('flex gap-2', className)}>
      <Popover open={open} onOpenChange={setOpen}>
        <PopoverTrigger asChild>
          <Button
            variant="outline"
            id={id}
            className={cn(
              'h-10 flex-1 justify-between font-normal',
              !selectedDate && 'text-muted-foreground',
              error && 'border-destructive'
            )}
          >
            {selectedDate ? format(selectedDate, 'MM/dd/yyyy') : 'Select date'}
            <ChevronDownIcon className="h-4 w-4 opacity-50" />
          </Button>
        </PopoverTrigger>
        <PopoverContent className="w-auto overflow-hidden p-0" align="start">
          <Calendar
            mode="single"
            selected={selectedDate}
            captionLayout="dropdown"
            defaultMonth={selectedDate}
            onSelect={handleDateSelect}
          />
        </PopoverContent>
      </Popover>
      <Input
        type="time"
        value={timeValue}
        onChange={handleTimeChange}
        className={cn(
          'h-10 flex-1 bg-background appearance-none [&::-webkit-calendar-picker-indicator]:hidden [&::-webkit-calendar-picker-indicator]:appearance-none',
          error && 'border-destructive'
        )}
      />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Plus, Minus } from 'lucide-react';

interface MaxParticipantsInputProps {
  value: number;
  onChange: (value: number) => void;
  min?: number;
  max?: number;
  label?: string;
  className?: string;
}

export function MaxParticipantsInput({
  value,
  onChange,
  min = 2,
  max = 999,
  label = 'Max Participants',
  className = '',
}: MaxParticipantsInputProps) {
  const [displayValue, setDisplayValue] = useState(value.toString());

  useEffect(() => {
    setDisplayValue(value.toString());
  }, [value]);

  const incrementValue = () => {
    const newValue = Math.min(value + 1, max);
    onChange(newValue);
    setDisplayValue(newValue.toString());
  };

  const decrementValue = () => {
    const newValue = Math.max(value - 1, min);
    onChange(newValue);
    setDisplayValue(newValue.toString());
  };

  const handleInputChange = (inputValue: string) => {
    setDisplayValue(inputValue);

    if (inputValue === '') {
      return;
    }

    const num = parseInt(inputValue);
    if (!isNaN(num) && num >= min && num <= max) {
      onChange(num);
    }
  };

  const handleInputBlur = (inputValue: string) => {
    const fallbackValue = Math.min(Math.max(value, min), max);
    if (inputValue.trim() === '') {
      onChange(fallbackValue);
      setDisplayValue(fallbackValue.toString());
      return;
    }
    const parsed = Number(inputValue);
    if (Number.isNaN(parsed)) {
      onChange(fallbackValue);
      setDisplayValue(fallbackValue.toString());
      return;
    }
    const clamped = Math.min(Math.max(parsed, min), max);
    onChange(clamped);
    setDisplayValue(clamped.toString());
  };

  return (
    <div className={`space-y-2 ${className}`}>
      <Label htmlFor="max-participants-input" className="text-sm">
        {label}
      </Label>
      <div
        className="flex items-center w-fit"
        role="group"
        aria-labelledby="max-participants-input"
      >
        <Button
          type="button"
          variant="outline"
          size="sm"
          className="h-10 w-10 p-0 rounded-l-md rounded-r-none border-r-0"
          onClick={decrementValue}
          aria-label={`Decrease ${label.toLowerCase()} to ${Math.max(value - 1, min)}`}
          disabled={value <= min}
        >
          <Minus className="h-4 w-4" aria-hidden="true" />
        </Button>
        <Input
          id="max-participants-input"
          type="text"
          inputMode="numeric"
          pattern="[0-9]*"
          value={displayValue}
          onChange={(e) => handleInputChange(e.target.value)}
          onBlur={(e) => handleInputBlur(e.target.value)}
          className="h-10 w-16 text-sm text-center rounded-none border-x-0 focus:border-x focus:z-10"
          aria-label={`${label} (${min} to ${max})`}
          min={min}
          max={max}
        />
        <Button
          type="button"
          variant="outline"
          size="sm"
          className="h-10 w-10 p-0 rounded-r-md rounded-l-none border-l-0"
          onClick={incrementValue}
          aria-label={`Increase ${label.toLowerCase()} to ${Math.min(value + 1, max)}`}
          disabled={value >= max}
        >
          <Plus className="h-4 w-4" aria-hidden="true" />
        </Button>
      </div>
    </div>
  );
}

import { Drawer, DrawerContent } from '@/components/ui/drawer';

export interface SortOption {
  value: string;
  label: string;
}

interface SortDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  options: SortOption[];
  selectedValue: string;
  onSelect: (value: string) => void;
}

export function SortDrawer({
  open,
  onOpenChange,
  options,
  selectedValue,
  onSelect,
}: SortDrawerProps) {
  const handleSelect = (value: string) => {
    onSelect(value);
    onOpenChange(false);
  };

  return (
    <Drawer open={open} onOpenChange={onOpenChange}>
      <DrawerContent className="p-0">
        <div className="py-4 px-4">
          {options.map((option, index) => (
            <button
              key={option.value}
