const createMockPreferences = (
  overrides: Partial<NotificationPreferencesType> = {}
): NotificationPreferencesType => ({
  id: 'pref-1',
  user_id: 'user-1',
  push_enabled: true,
  notify_new_signup: true,
  notify_withdrawal: true,
  notify_payment_received: true,
  notify_capacity_reached: true,
  notify_signup_confirmed: true,
  notify_event_updated: true,
  notify_event_cancelled: true,
  notify_payment_reminder: true,
  notify_waitlist_promotion: true,
  created_at: '2023-01-01T00:00:00Z',
  updated_at: '2023-01-01T00:00:00Z',
  ...overrides,
});

describe('NotificationPreferences', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockHookPreferences = null;
  });

  it('hides individual toggles when master toggle is disabled', async () => {
    mockHookPreferences = createMockPreferences({ push_enabled: false });

    render(<NotificationPreferences />);

    await waitFor(() => {
      expect(screen.getByLabelText('Push notifications')).toBeInTheDocument();
    });

    // Individual toggles should not be visible when master is off
    expect(screen.queryByLabelText('New signups')).not.toBeInTheDocument();
    expect(screen.queryByLabelText('Withdrawals')).not.toBeInTheDocument();
  });

  it('shows individual toggles when master toggle is enabled', async () => {
    mockHookPreferences = createMockPreferences({ push_enabled: true });

    render(<NotificationPreferences />);

    await waitFor(() => {
      expect(screen.getByLabelText('New signups')).toBeInTheDocument();
    });

    expect(screen.getByLabelText('Withdrawals')).toBeInTheDocument();
    expect(screen.getByLabelText('Event updates')).toBeInTheDocument();
  });

  it('reverts optimistic update on error', async () => {
    mockHookPreferences = createMockPreferences({ push_enabled: true, notify_new_signup: true });
    mockUpdatePreferences.mockRejectedValue(new Error('Network error'));

    render(<NotificationPreferences />);

    await waitFor(() => {
      expect(screen.getByLabelText('New signups')).toBeInTheDocument();
    });

    const toggle = screen.getByLabelText('New signups');
    expect(toggle).toBeChecked();

    fireEvent.click(toggle);

    // Optimistic update - immediately unchecked
    expect(toggle).not.toBeChecked();

    // Should revert after error
    await waitFor(() => {
      expect(toggle).toBeChecked();
    });
  });
});

import { createContext, useCallback, useContext, useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import type { User, Session } from '@supabase/supabase-js';
import { supabase } from '@/lib/supabase';
import { getStorageItem, removeStorageItem, setStorageItem } from '@/lib/storage';
import { pushSubscriptionService } from '@/services/pushSubscriptionService';

const ADMIN_SESSION_KEY = 'adminSession';

/** Authentication context value type */
interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  isAdmin: boolean;
  isImpersonating: boolean;
  signIn: (email: string, password: string) => Promise<void>;
  signUp: (email: string, password: string, fullName?: string) => Promise<void>;
  signInWithGoogle: () => Promise<void>;
  signInWithGoogleIdToken: (idToken: string) => Promise<void>;
  signOut: () => Promise<void>;
  impersonate: (userId: string) => Promise<void>;
  stopImpersonating: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

/**
 * Authentication provider component that wraps the app.
 * Manages auth state, listens for auth changes, and handles post-login redirects.
 * @param children - Child components to render within the provider
 */
export function AuthProvider({ children }: { children: React.ReactNode }) {
  const navigate = useNavigate();
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((event, session) => {
      setSession(session);
      setUser(session?.user ?? null);

      if (event === 'SIGNED_IN' && session?.user) {
        const returnUrl = getStorageItem('returnUrl');
        if (returnUrl) {
          removeStorageItem('returnUrl');
          const isSafeRelativePath = returnUrl.startsWith('/') && !returnUrl.startsWith('//');
          navigate(isSafeRelativePath ? returnUrl : '/');
        } else {
          const pendingInviteRaw = getStorageItem('pendingInvite');
          if (pendingInviteRaw) {
            // Always remove after reading (whether valid or malformed)
            removeStorageItem('pendingInvite');
            try {
              const pendingInvite = JSON.parse(pendingInviteRaw) as { type?: string; id?: string };
              if (pendingInvite.type && pendingInvite.id) {
                if (pendingInvite.type === 'event') {
                  navigate(`/signup/${pendingInvite.id}`);
                } else if (pendingInvite.type === 'group') {
                  navigate(`/groups/${pendingInvite.id}`);
                }
              }
            } catch {
              // Silently ignore malformed data - already removed from storage
            }
          }
        }
      }
    });

    return () => subscription.unsubscribe();
  }, [navigate]);

  /**
   * Signs in a user with email and password.
   * @param email - User's email address
   * @param password - User's password
   * @throws Error if authentication fails
   */
  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    if (error) throw error;
  };

  /**
   * Creates a new user account.
   * @param email - User's email address
   * @param password - User's password
   * @param fullName - Optional display name stored in user metadata
   * @throws Error if registration fails
   */
  const signUp = async (email: string, password: string, fullName?: string) => {
    const { error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: {
          full_name: fullName || '',
        },
      },
    });
    if (error) throw error;
  };

  /**
   * Initiates Google OAuth sign-in flow.
   * Redirects to Google for authentication.
   * @throws Error if OAuth initiation fails
   */
  const signInWithGoogle = async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: `${window.location.origin}/auth/v1/callback`,
      },
    });
    if (error) throw error;
  };

  /**
   * Signs in using a Google ID token (for native app integrations).
   * @param idToken - Google OAuth ID token
   * @throws Error if authentication fails
   */
  const signInWithGoogleIdToken = async (idToken: string) => {
    const { error } = await supabase.auth.signInWithIdToken({
      provider: 'google',
      token: idToken,
    });
    if (error) throw error;
  };

  /**
   * Signs out the current user.
   * Also cleans up push notification subscription from the database to prevent
   * notifications from being sent to the wrong user on shared devices.
   * Note: Browser subscription is preserved so users don't need to re-grant
   * permission when signing back in.
   * @throws Error if sign out fails
   */
  const signOut = async () => {
    // Remove subscription from database only (keep browser subscription)
    // This prevents notifications from leaking to the next user while
    // preserving browser permission for easier re-subscription
    try {
      await pushSubscriptionService.removeSubscriptionFromDatabase();
    } catch {
      // Don't block sign out if cleanup fails
    }

    // Clear any saved admin session on full sign out
    removeStorageItem(ADMIN_SESSION_KEY);

    const { error } = await supabase.auth.signOut();
    if (error) throw error;
  };

  /**
   * Impersonates another user by calling the impersonate-user edge function.
   * Saves the current admin session so it can be restored later.
   * Only available to platform admins (app_metadata.is_admin = true).
   */
  const impersonate = useCallback(
    async (userId: string) => {
      if (!session) throw new Error('Must be signed in to impersonate');

      const response = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/impersonate-user`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`,
          },
          body: JSON.stringify({ user_id: userId, access_token: session.access_token }),
        }
      );
      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Impersonation failed');
      if (!data?.session) throw new Error('No session returned from impersonation');

      // Save the current admin session for later restoration
      const saved = setStorageItem(
        ADMIN_SESSION_KEY,
        JSON.stringify({
          access_token: session.access_token,
          refresh_token: session.refresh_token,
        })
      );
      if (!saved) throw new Error('Failed to save admin session — cannot impersonate safely');

      // Set the impersonated session
      await supabase.auth.setSession({
        access_token: data.session.access_token,
        refresh_token: data.session.refresh_token,
      });
    },
    [session]
  );

  /**
   * Stops impersonating and restores the original admin session.
   */
  const stopImpersonating = useCallback(async () => {
    const savedSession = getStorageItem(ADMIN_SESSION_KEY);
    if (!savedSession) throw new Error('No admin session to restore');

    let parsed;
    try {
      parsed = JSON.parse(savedSession);
    } catch {
      removeStorageItem(ADMIN_SESSION_KEY);
      throw new Error('Corrupted admin session — please sign in again');
    }

    await supabase.auth.setSession({
      access_token: parsed.access_token,
      refresh_token: parsed.refresh_token,
    });
    removeStorageItem(ADMIN_SESSION_KEY);
  }, []);

  const isAdmin = !!user?.app_metadata?.is_admin;
  const isImpersonating = !!getStorageItem(ADMIN_SESSION_KEY);

  return (
    <AuthContext.Provider
      value={{
        user,
        session,
        loading,
        isAdmin,
        isImpersonating,
        signIn,
        signUp,
        signInWithGoogle,
        signInWithGoogleIdToken,
        signOut,
        impersonate,
        stopImpersonating,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

/**
 * Hook to access authentication context.
 * Must be used within an AuthProvider.
 * @returns Authentication context with user, session, loading state, and auth methods
 * @throws Error if used outside of AuthProvider
 */
// eslint-disable-next-line react-refresh/only-export-components
export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { useAuth } from './useAuth';
import { featureFlagService } from '@/services/featureFlagService';
import type { FeatureFlags, FeatureFlagKey } from '@/types/feature-flags';

interface FeatureFlagsContextType {
  flags: FeatureFlags | null;
  loading: boolean;
  error: Error | null;
  isFeatureEnabled: (key: FeatureFlagKey) => boolean;
  refreshFlags: () => Promise<void>;
}

const FeatureFlagsContext = createContext<FeatureFlagsContextType | undefined>(undefined);

// Auto-refresh interval (5 minutes)
const REFRESH_INTERVAL_MS = 5 * 60 * 1000;

export function FeatureFlagsProvider({ children }: { children: React.ReactNode }) {
  const { user } = useAuth();
  const [flags, setFlags] = useState<FeatureFlags | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  // Fetch feature flags with current user context
  const fetchFlags = useCallback(async () => {
    try {
      const context = user?.id ? { userId: user.id } : undefined;
      const fetchedFlags = await featureFlagService.fetchFeatureFlags(context);
      setFlags(fetchedFlags);
      setError(null);
    } catch (err) {
      const fetchError = err instanceof Error ? err : new Error('Failed to fetch feature flags');
      setError(fetchError);
      // Don't clear flags on refresh errors if we already have them cached
      // This allows the app to keep working with stale flags during transient errors
    } finally {
      setLoading(false);
    }
  }, [user?.id]);

  // Initial fetch on mount and when user changes
  useEffect(() => {
    setLoading(true);
    fetchFlags();
  }, [fetchFlags]);

  // Set up auto-refresh polling
  useEffect(() => {
    const intervalId = setInterval(() => {
      fetchFlags();
    }, REFRESH_INTERVAL_MS);

    return () => clearInterval(intervalId);
  }, [fetchFlags]);

  // Helper to check if a feature is enabled
  const isFeatureEnabled = useCallback(
    (key: FeatureFlagKey): boolean => {
      if (!flags) return false;
      return flags[key];
    },
    [flags]
  );

  // Manual refresh function
  const refreshFlags = useCallback(async () => {
    await fetchFlags();
  }, [fetchFlags]);

  return (
    <FeatureFlagsContext.Provider
      value={{
        flags,
        loading,
        error,
        isFeatureEnabled,
        refreshFlags,
      }}
    >
      {children}
    </FeatureFlagsContext.Provider>
  );
}

/**
 * Hook to access all feature flags
 * @returns Feature flags context with all flags and helper functions
 */
// eslint-disable-next-line react-refresh/only-export-components
export function useFeatureFlags(): FeatureFlagsContextType {
  const context = useContext(FeatureFlagsContext);
  if (context === undefined) {
    throw new Error('useFeatureFlags must be used within a FeatureFlagsProvider');
  }
  return context;
}

/**
 * Hook to check if a specific feature is enabled
 * @param key - Feature flag key to check
 * @returns Whether the feature is enabled (false if flags haven't loaded yet)
 */
// eslint-disable-next-line react-refresh/only-export-components
export function useFeatureFlag(key: FeatureFlagKey): boolean {
  const { flags, error } = useFeatureFlags();

  // If there's an error and no cached flags, throw to trigger error boundary
  if (error && !flags) {
    throw error;
  }

  // Return false while loading or if flag doesn't exist
  if (!flags) return false;
  return flags[key];
}

import { createContext, useContext, useEffect, useState, type ReactNode } from 'react';

export type FontSize = 'sm' | 'md' | 'lg';

export interface FontSizeConfig {
  sm: string;
  md: string;
  lg: string;
}

const FONT_SIZE_CONFIG: FontSizeConfig = {
  sm: '18px',
  md: '20px',
  lg: '22px',
};

const FONT_SIZE_LABELS: Record<FontSize, string> = {
  sm: 'Small',
  md: 'Medium',
  lg: 'Large',
};

interface FontSizeContextType {
  fontSize: FontSize;
  setFontSize: (size: FontSize) => void;
  fontSizeConfig: FontSizeConfig;
  fontSizeLabels: Record<FontSize, string>;
  getFontSizeValue: (size: FontSize) => string;
}

const FontSizeContext = createContext<FontSizeContextType | undefined>(undefined);

const STORAGE_KEY = 'font-size-preference';

export function FontSizeProvider({ children }: { children: ReactNode }) {
  const [fontSize, setFontSizeState] = useState<FontSize>('md');

  useEffect(() => {
    if (typeof window === 'undefined') return;
    try {
      const savedFontSize = window.localStorage.getItem(STORAGE_KEY) as FontSize | null;
      if (savedFontSize && Object.hasOwn(FONT_SIZE_CONFIG, savedFontSize)) {
        setFontSizeState(savedFontSize);
      }
    } catch {
      // localStorage may be unavailable (e.g., Safari private mode); fall back to defaults.
    }
  }, []);

  useEffect(() => {
    const root = document.documentElement;
    const sizeValue = FONT_SIZE_CONFIG[fontSize];

    root.style.setProperty('--font-size-base', sizeValue);
    root.style.setProperty('--font-size-xs', `calc(${sizeValue} * 0.75)`);
    root.style.setProperty('--font-size-sm', `calc(${sizeValue} * 0.875)`);
    root.style.setProperty('--font-size-base-exact', sizeValue);
    root.style.setProperty('--font-size-lg', `calc(${sizeValue} * 1.125)`);
    root.style.setProperty('--font-size-2xl', `calc(${sizeValue} * 1.5)`);
    root.style.setProperty('--font-size-3xl', `calc(${sizeValue} * 1.875)`);
  }, [fontSize]);

  const setFontSize = (size: FontSize) => {
    setFontSizeState(size);
    if (typeof window === 'undefined') return;
    try {
      window.localStorage.setItem(STORAGE_KEY, size);
    } catch {
      // Ignore write failures so UI updates still succeed when storage is blocked.
    }
  };

  const getFontSizeValue = (size: FontSize) => FONT_SIZE_CONFIG[size];

  const value: FontSizeContextType = {
    fontSize,
    setFontSize,
    fontSizeConfig: FONT_SIZE_CONFIG,
    fontSizeLabels: FONT_SIZE_LABELS,
    getFontSizeValue,
  };

  return <FontSizeContext.Provider value={value}>{children}</FontSizeContext.Provider>;
}

// eslint-disable-next-line react-refresh/only-export-components
export function useFontSize() {
  const context = useContext(FontSizeContext);
  if (context === undefined) {
    throw new Error('useFontSize must be used within a FontSizeProvider');
  }
  return context;
}

import { useState, useEffect, useCallback, useRef } from 'react';
import {
  notificationService,
  pushSubscriptionService,
  notificationPreferenceService,
} from '@/services';
import { useAuth } from '@/hooks/useAuth';
import { logError } from '@/lib/errorHandler';
import type { Notification, NotificationPreferences } from '@/types/notifications';

/**
 * Hook for managing notifications and push subscriptions.
 * Provides state for notifications list, unread count, and user preferences.
 * Handles real-time notification updates and push subscription management.
 * @returns Notification state, capabilities, and action methods
 */
export function useNotifications() {
  const { user } = useAuth();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [preferences, setPreferences] = useState<NotificationPreferences | null>(null);
  const [isSubscribed, setIsSubscribed] = useState(false);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  const unsubscribeRef = useRef<(() => void) | null>(null);
  const hasLoadedRef = useRef(false);

  const isSupported = pushSubscriptionService.isSupported();
  const isConfigured = pushSubscriptionService.isConfigured();

  useEffect(() => {
    if (!user) {
      setNotifications([]);
      setUnreadCount(0);
      setPreferences(null);
      setIsSubscribed(false);
      setLoading(false);
      hasLoadedRef.current = false;
      return;
    }

    let cancelled = false;

    const load = async () => {
      // Only show loading state on first load, not on refetches
      if (!hasLoadedRef.current) {
        setLoading(true);
      }
      setError(null);

      try {
        const [notifs, count, prefs, browserHasSubscription] = await Promise.all([
          notificationService.getNotifications(),
          notificationService.getUnreadCount(),
          notificationPreferenceService.getOrCreatePreferences(),
          pushSubscriptionService.isSubscribed(),
        ]);

        if (cancelled) return;

        setNotifications(notifs);
        setUnreadCount(count);
        setPreferences(prefs);
        setPermission(pushSubscriptionService.getPermissionStatus());

        const currentPermission = pushSubscriptionService.getPermissionStatus();

        // Set subscription state based on actual browser state
        // Don't auto-resubscribe here - let user explicitly enable via settings toggle
        if (browserHasSubscription && currentPermission === 'granted') {
          setIsSubscribed(true);
          // If browser has subscription but DB doesn't have push_enabled,
          // sync the DB to match (user previously enabled, just needs DB update)
          if (!prefs.push_enabled) {
            try {
              await pushSubscriptionService.subscribe();
              await notificationPreferenceService.updatePreferences({ push_enabled: true });
              // Update local state to reflect the sync
              if (!cancelled) {
                setPreferences({ ...prefs, push_enabled: true });
              }
            } catch {
              // If sync fails, still show as subscribed since browser has subscription
            }
          }
        } else {
          setIsSubscribed(false);
        }

        hasLoadedRef.current = true;
      } catch (err) {
        if (cancelled) return;
        setError(err instanceof Error ? err : new Error('Failed to load notifications'));
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };

    load();

    return () => {
      cancelled = true;
    };
  }, [user]);

  useEffect(() => {
    if (!user) {
      return;
    }

    if (unsubscribeRef.current) {
      unsubscribeRef.current();
      unsubscribeRef.current = null;
    }

    unsubscribeRef.current = notificationService.subscribeToNotifications(
      user.id,
      (notification) => {
        setNotifications((prev) => [notification, ...prev]);
        setUnreadCount((prev) => prev + 1);
      }
    );

    return () => {
      if (unsubscribeRef.current) {
        unsubscribeRef.current();
        unsubscribeRef.current = null;
      }
    };
  }, [user]);

  /** Refreshes notifications list and unread count from the server */
  const refresh = useCallback(async () => {
    if (!user) return;

    try {
      const [notifs, count] = await Promise.all([
        notificationService.getNotifications(),
        notificationService.getUnreadCount(),
      ]);
      setNotifications(notifs);
      setUnreadCount(count);
    } catch (err) {
      logError('Failed to refresh notifications', err);
    }
  }, [user]);

  /** Refreshes subscription state from browser - useful after navigation */
  const refreshSubscriptionState = useCallback(async () => {
    try {
      const [browserHasSubscription, prefs] = await Promise.all([
        pushSubscriptionService.isSubscribed(),
        notificationPreferenceService.getOrCreatePreferences(),
      ]);

      const currentPermission = pushSubscriptionService.getPermissionStatus();
      setPermission(currentPermission);
      setPreferences(prefs);

      if (browserHasSubscription && currentPermission === 'granted') {
        setIsSubscribed(true);
      } else {
        setIsSubscribed(false);
      }
    } catch (err) {
      logError('Failed to refresh subscription state', err);
    }
  }, []);

  /** Requests permission and subscribes to push notifications */
  const subscribe = useCallback(async () => {
    try {
      const perm = await pushSubscriptionService.requestPermission();
      setPermission(perm);

      if (perm === 'granted') {
        const subscription = await pushSubscriptionService.subscribe();
        if (subscription) {
          setIsSubscribed(true);
        }
      }

      return perm;
    } catch (err) {
      logError('Failed to subscribe to push', err);
      throw err;
    }
  }, []);

  /** Unsubscribes from push notifications */
  const unsubscribe = useCallback(async () => {
    try {
      await pushSubscriptionService.unsubscribe();
      setIsSubscribed(false);
    } catch (err) {
      logError('Failed to unsubscribe from push', err);
      throw err;
    }
  }, []);

  /** Marks a single notification as read */
  const markAsRead = useCallback(async (notificationId: string) => {
    try {
      await notificationService.markAsRead(notificationId);
      setNotifications((prev) =>
        prev.map((n) => (n.id === notificationId ? { ...n, read_at: new Date().toISOString() } : n))
      );
      setUnreadCount((prev) => Math.max(0, prev - 1));
    } catch (err) {
      logError('Failed to mark notification as read', err, { notificationId });
      throw err;
    }
  }, []);

  /** Marks all notifications as read */
  const markAllAsRead = useCallback(async () => {
    try {
      await notificationService.markAllAsRead();
      setNotifications((prev) => prev.map((n) => ({ ...n, read_at: new Date().toISOString() })));
      setUnreadCount(0);
    } catch (err) {
      logError('Failed to mark all as read', err);
      throw err;
    }
  }, []);

  /** Deletes a notification and updates unread count if needed */
  const deleteNotification = useCallback(
    async (notificationId: string) => {
      try {
        const notification = notifications.find((n) => n.id === notificationId);
        await notificationService.deleteNotification(notificationId);
        setNotifications((prev) => prev.filter((n) => n.id !== notificationId));
        if (notification && !notification.read_at) {
          setUnreadCount((prev) => Math.max(0, prev - 1));
        }
      } catch (err) {
        logError('Failed to delete notification', err, { notificationId });
        throw err;
      }
    },
    [notifications]
  );

  /** Updates user notification preferences */
  const updatePreferences = useCallback(async (updates: Partial<NotificationPreferences>) => {
    try {
      const updated = await notificationPreferenceService.updatePreferences(updates);
      setPreferences(updated);
      return updated;
    } catch (err) {
      logError('Failed to update preferences', err);
      throw err;
    }
  }, []);

  return {
    notifications,
    unreadCount,
    preferences,
    isSubscribed,
    permission,
    loading,
    error,
    isSupported,
    isConfigured,
    subscribe,
    unsubscribe,
    markAsRead,
    markAllAsRead,
    deleteNotification,
    updatePreferences,
    refresh,
    refreshSubscriptionState,
  };
}

import { useState, useCallback } from 'react';
import { z } from 'zod';
import { errorHandler } from '@/lib/errorHandler';

/** Validation error with field path and message */
export interface ValidationError {
  field: string;
  message: string;
}

/** Return type for useFormValidation hook */
export interface UseFormValidationResult<T> {
  errors: ValidationError[];
  isValid: boolean;
  validate: (data: T) => boolean;
  validateField: (field: keyof T, value: unknown) => boolean;
  clearErrors: () => void;
  clearFieldError: (field: keyof T) => void;
  getFieldError: (field: keyof T) => string | undefined;
}

/**
 * Hook for validating form data against a Zod schema.
 * Tracks validation errors and provides methods for full and field-level validation.
 * @param schema - Zod schema to validate against
 * @returns Validation state and methods
 */
export function useFormValidation<T>(schema: z.ZodSchema<T>): UseFormValidationResult<T> {
  const [errors, setErrors] = useState<ValidationError[]>([]);

  /** Validates all data against the schema */
  const validate = useCallback(
    (data: T): boolean => {
      try {
        schema.parse(data);
        setErrors([]);
        return true;
      } catch (error) {
        if (error instanceof z.ZodError) {
          const validationErrors: ValidationError[] = error.issues.map((err: z.ZodIssue) => ({
            field: err.path.join('.'),
            message: err.message,
          }));
          setErrors(validationErrors);
          return false;
        }

        errorHandler.handle(error, { action: 'formValidation' });
        return false;
      }
    },
    [schema]
  );

  /** Validates a single field value against its schema */
  const validateField = useCallback(
    (field: keyof T, value: unknown): boolean => {
      try {
        const fieldSchema = (schema as z.ZodObject<z.ZodRawShape>).shape?.[field as string];
        if (!fieldSchema) {
          return true;
        }

        (fieldSchema as z.ZodType).parse(value);

        setErrors((prev) => prev.filter((error) => error.field !== String(field)));
        return true;
      } catch (error) {
        if (error instanceof z.ZodError) {
          const fieldError: ValidationError = {
            field: String(field),
            message: (error as z.ZodError).issues[0]?.message || 'Invalid value',
          };

          setErrors((prev) => [
            ...prev.filter((error) => error.field !== String(field)),
            fieldError,
          ]);
          return false;
        }

        return true;
      }
    },
    [schema]
  );

  /** Clears all validation errors */
  const clearErrors = useCallback(() => {
    setErrors([]);
  }, []);

  /** Clears error for a specific field */
  const clearFieldError = useCallback((field: keyof T) => {
    setErrors((prev) => prev.filter((error) => error.field !== String(field)));
  }, []);

  /** Gets the error message for a specific field */
  const getFieldError = useCallback(
    (field: keyof T): string | undefined => {
      const error = errors.find((error) => error.field === String(field));
      return error?.message;
    },
    [errors]
  );

  return {
    errors,
    isValid: errors.length === 0,
    validate,
    validateField,
    clearErrors,
    clearFieldError,
    getFieldError,
  };
}

/**
 * Convenience hook combining form data state with validation.
 * Provides field update methods that automatically validate on change.
 * @param initialData - Initial form data
 * @param schema - Zod schema to validate against
 * @returns Form data state, update methods, and validation methods
 */
export function useValidatedForm<T>(initialData: T, schema: z.ZodSchema<T>) {
  const [data, setData] = useState<T>(initialData);
  const validation = useFormValidation(schema);

  /** Updates a field value and validates it */
  const updateField = useCallback(
    (field: keyof T, value: T[keyof T]) => {
      setData((prev) => ({ ...prev, [field]: value }));
      validation.validateField(field, value);
    },
    [validation]
  );

  /** Validates all form data */
  const validateAll = useCallback(() => {
    return validation.validate(data);
  }, [data, validation]);

  /** Resets form data to initial values and clears errors */
  const reset = useCallback(() => {
    setData(initialData);
    validation.clearErrors();
  }, [initialData, validation]);

  return {
    data,
    setData,
    updateField,
    validateAll,
    reset,
    ...validation,
  };
}

import { useState, useCallback } from 'react';
import type { CustomField } from '@/types/app.types';

/**
 * Hook for managing custom form fields in event forms.
 * Provides add, update, and remove operations for custom fields.
 *
 * @param initialFields - Optional initial custom fields array
 * @returns Custom fields state and management functions
 */
export function useCustomFields(initialFields: CustomField[] = []) {
  const [customFields, setCustomFields] = useState<CustomField[]>(initialFields);

  const addCustomField = useCallback(() => {
    const newField: CustomField = {
      id: Date.now().toString(),
      label: '',
      type: 'text',
      required: false,
    };
    setCustomFields((prev) => [...prev, newField]);
  }, []);

  const updateCustomField = useCallback((id: string, updates: Partial<CustomField>) => {
    setCustomFields((prev) =>
      prev.map((field) => (field.id === id ? { ...field, ...updates } : field))
    );
  }, []);

  const removeCustomField = useCallback((id: string) => {
    setCustomFields((prev) => prev.filter((field) => field.id !== id));
  }, []);

  const resetCustomFields = useCallback((fields: CustomField[]) => {
    setCustomFields(fields);
  }, []);

  return {
    customFields,
    addCustomField,
    updateCustomField,
    removeCustomField,
    resetCustomFields,
  };
}

import { useState, useCallback, useEffect } from 'react';
import { errorHandler } from '@/lib/errorHandler';

export interface LoadingState<T = unknown> {
  isLoading: boolean;
  error: string | null;
  data: T | null;
}

export interface UseLoadingStateResult<T> {
  isLoading: boolean;
  error: string | null;
  data: T | null;
  execute: (asyncFn: () => Promise<T>) => Promise<T | null>;
  reset: () => void;
  setLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;
  setData: (data: T | null) => void;
}

export function useLoadingState<T = unknown>(
  initialData: T | null = null
): UseLoadingStateResult<T> {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [data, setData] = useState<T | null>(initialData);

  const execute = useCallback(async (asyncFn: () => Promise<T>): Promise<T | null> => {
    try {
      setIsLoading(true);
      setError(null);

      const result = await asyncFn();
      setData(result);
      return result;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'An error occurred';
      setError(errorMessage);
      errorHandler.handle(err);
      return null;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const reset = useCallback(() => {
    setIsLoading(false);
    setError(null);
    setData(initialData);
  }, [initialData]);

  const setLoadingWrapper = useCallback((loading: boolean) => {
    setIsLoading(loading);
  }, []);

  const setErrorWrapper = useCallback((error: string | null) => {
    setError(error);
  }, []);

  const setDataWrapper = useCallback((data: T | null) => {
    setData(data);
  }, []);

  return {
    isLoading,
    error,
    data,
    execute,
    reset,
    setLoading: setLoadingWrapper,
    setError: setErrorWrapper,
    setData: setDataWrapper,
  };
}

// Hook for managing multiple loading states (useful for forms with multiple actions)
export function useMultipleLoadingStates<T extends Record<string, unknown>>(
  keys: (keyof T)[]
): Record<keyof T, UseLoadingStateResult<unknown>> {
  const states = {} as Record<keyof T, UseLoadingStateResult<unknown>>;

  for (const key of keys) {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    states[key] = useLoadingState();
  }

  return states;
}

// Hook for async operations with automatic loading state management
export function useAsyncOperation<T>(operation: () => Promise<T>, dependencies: unknown[] = []) {
  const { isLoading, error, data, execute } = useLoadingState<T>();

  const run = useCallback(() => {
    return execute(operation);
  }, [execute, operation]);

  // Auto-run on mount if dependencies are provided
  useEffect(() => {
    if (dependencies.length > 0) {
      run();
    }
  }, dependencies); // eslint-disable-line react-hooks/exhaustive-deps

  return {
    isLoading,
    error,
    data,
    run,
  };
}

import { renderHook, waitFor } from '@testing-library/react';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import type { ReactNode } from 'react';
import { BrowserRouter } from 'react-router-dom';

// Mock user for testing
const mockUser = {
  id: 'user-123',
  email: 'test@example.com',
};

// Mock services
const mockGetNotifications = vi.fn();
const mockGetUnreadCount = vi.fn();
const mockGetOrCreatePreferences = vi.fn();
const mockUpdatePreferences = vi.fn();
const mockIsSubscribed = vi.fn();
const mockSubscribe = vi.fn();
const mockGetPermissionStatus = vi.fn();
const mockIsSupported = vi.fn();
const mockIsConfigured = vi.fn();
const mockSubscribeToNotifications = vi.fn();

vi.mock('@/services', () => ({
  notificationService: {
    getNotifications: () => mockGetNotifications(),
    getUnreadCount: () => mockGetUnreadCount(),
    subscribeToNotifications: (...args: unknown[]) => mockSubscribeToNotifications(...args),
    markAsRead: vi.fn(),
    markAllAsRead: vi.fn(),
    deleteNotification: vi.fn(),
  },
  notificationPreferenceService: {
    getOrCreatePreferences: () => mockGetOrCreatePreferences(),
    updatePreferences: (updates: unknown) => mockUpdatePreferences(updates),
  },
  pushSubscriptionService: {
    isSupported: () => mockIsSupported(),
    isConfigured: () => mockIsConfigured(),
    isSubscribed: () => mockIsSubscribed(),
    subscribe: () => mockSubscribe(),
    getPermissionStatus: () => mockGetPermissionStatus(),
    requestPermission: vi.fn(),
    unsubscribe: vi.fn(),
  },
}));

// Mock useAuth
const mockUseAuth = vi.fn();
vi.mock('@/hooks/useAuth', () => ({
  useAuth: () => mockUseAuth(),
}));

vi.mock('@/lib/errorHandler', () => ({
  logError: vi.fn(),
}));

import { useNotifications } from '../useNotifications';

function wrapper({ children }: { children: ReactNode }) {
  return <BrowserRouter>{children}</BrowserRouter>;
}

describe('useNotifications', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockSubscribeToNotifications.mockReturnValue(() => {});
    mockIsSupported.mockReturnValue(true);
    mockIsConfigured.mockReturnValue(true);
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe('auto-resubscribe on sign in', () => {
    it('should auto-resubscribe when browser has existing subscription and permission is granted', async () => {
      // Scenario: User signed out, signed back in on same device (Android PWA or browser)
      // Browser still has push subscription from before
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: false });
      mockIsSubscribed.mockResolvedValue(true); // Browser HAS subscription
      mockGetPermissionStatus.mockReturnValue('granted'); // Permission was previously granted
      mockSubscribe.mockResolvedValue({ endpoint: 'https://example.com/push' });
      mockUpdatePreferences.mockResolvedValue({ push_enabled: true });

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // Should have called subscribe to register with database for current user
      expect(mockSubscribe).toHaveBeenCalled();
      // Should have updated database preference to enabled
      expect(mockUpdatePreferences).toHaveBeenCalledWith({ push_enabled: true });
      // Should show as subscribed
      expect(result.current.isSubscribed).toBe(true);
    });

    it('should NOT auto-subscribe for new users without existing browser subscription', async () => {
      // Scenario: Brand new user, first time enabling notifications
      // Browser has no push subscription yet
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: false });
      mockIsSubscribed.mockResolvedValue(false); // Browser has NO subscription
      mockGetPermissionStatus.mockReturnValue('default'); // Never prompted

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // Should NOT auto-subscribe - let user opt-in via settings
      expect(mockSubscribe).not.toHaveBeenCalled();
      expect(mockUpdatePreferences).not.toHaveBeenCalled();
      expect(result.current.isSubscribed).toBe(false);
    });

    it('should NOT auto-subscribe when permission is not granted even with browser subscription', async () => {
      // Edge case: Browser has subscription but permission changed to denied
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: true });
      mockIsSubscribed.mockResolvedValue(true); // Browser has subscription
      mockGetPermissionStatus.mockReturnValue('denied'); // But permission is now denied

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // Should NOT try to subscribe when permission is denied
      expect(mockSubscribe).not.toHaveBeenCalled();
      expect(result.current.isSubscribed).toBe(false);
    });

    it('should handle auto-resubscribe failure gracefully', async () => {
      // Scenario: Auto-resubscribe fails (e.g., network error)
      // Browser has subscription but DB is out of sync (push_enabled: false)
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: false }); // DB out of sync
      mockIsSubscribed.mockResolvedValue(true);
      mockGetPermissionStatus.mockReturnValue('granted');
      mockSubscribe.mockRejectedValue(new Error('Network error'));

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // Should have attempted to subscribe to sync with DB
      expect(mockSubscribe).toHaveBeenCalled();
      // Should still show as subscribed since browser has subscription
      // (sync failure shouldn't affect UI state)
      expect(result.current.isSubscribed).toBe(true);
      // Should not have updated database preferences since subscribe failed
      expect(mockUpdatePreferences).not.toHaveBeenCalled();
    });
  });

  describe('iOS PWA scenario (separate storage context)', () => {
    it('should not auto-subscribe when iOS PWA has no browser subscription', async () => {
      // Scenario: User enabled notifications in browser, then installed PWA on iOS
      // iOS PWA has separate storage - no browser subscription exists in PWA context
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      // Database preference is enabled (from browser session)
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: true });
      // But iOS PWA has no browser subscription (separate storage)
      mockIsSubscribed.mockResolvedValue(false);
      mockGetPermissionStatus.mockReturnValue('default'); // New context, never prompted

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // Should NOT auto-subscribe - user needs to re-enable in PWA settings
      expect(mockSubscribe).not.toHaveBeenCalled();
      expect(result.current.isSubscribed).toBe(false);
      // Note: Database preference remains enabled, but UI toggle should show OFF
      // because isSubscribed is false (no browser subscription)
    });
  });

  describe('Android PWA scenario (shared storage context)', () => {
    it('should show as subscribed when Android PWA shares browser subscription', async () => {
      // Scenario: User enabled notifications in browser, then installed PWA on Android
      // Android PWA shares storage with browser - subscription persists
      // DB already has push_enabled: true, so no sync needed
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: true });
      // Android PWA shares browser subscription
      mockIsSubscribed.mockResolvedValue(true);
      mockGetPermissionStatus.mockReturnValue('granted');

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // Should show as subscribed without needing to call subscribe
      // (DB and browser are already in sync)
      expect(mockSubscribe).not.toHaveBeenCalled();
      expect(result.current.isSubscribed).toBe(true);
    });
  });

  describe('account switching', () => {
    it('should reset subscription state when user changes', async () => {
      // Start with User A subscribed
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: true });
      mockIsSubscribed.mockResolvedValue(true);
      mockGetPermissionStatus.mockReturnValue('granted');
      mockSubscribe.mockResolvedValue({ endpoint: 'https://example.com/push' });
      mockUpdatePreferences.mockResolvedValue({ push_enabled: true });

      const { result, rerender } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
        expect(result.current.isSubscribed).toBe(true);
      });

      // User signs out (user becomes null)
      mockUseAuth.mockReturnValue({
        user: null,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      rerender();

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // State should be reset
      expect(result.current.notifications).toEqual([]);
      expect(result.current.unreadCount).toBe(0);
      expect(result.current.preferences).toBeNull();
    });

    it('should re-evaluate subscription when new user signs in', async () => {
      // User B signs in after User A signed out
      const userB = { id: 'user-456', email: 'userb@example.com' };
      mockUseAuth.mockReturnValue({
        user: userB,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: false }); // User B has different preferences
      mockIsSubscribed.mockResolvedValue(true); // Browser still has subscription
      mockGetPermissionStatus.mockReturnValue('granted');
      mockSubscribe.mockResolvedValue({ endpoint: 'https://example.com/push' });
      mockUpdatePreferences.mockResolvedValue({ push_enabled: true });

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      // Should auto-resubscribe for User B since browser has subscription
      expect(mockSubscribe).toHaveBeenCalled();
      expect(result.current.isSubscribed).toBe(true);
    });
  });

  describe('no user signed in', () => {
    it('should not load anything when no user is signed in', async () => {
      mockUseAuth.mockReturnValue({
        user: null,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      expect(mockGetNotifications).not.toHaveBeenCalled();
      expect(mockIsSubscribed).not.toHaveBeenCalled();
      expect(result.current.notifications).toEqual([]);
      expect(result.current.unreadCount).toBe(0);
      expect(result.current.preferences).toBeNull();
    });
  });

  describe('push notification support', () => {
    it('should report correct support status', async () => {
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: false });
      mockIsSubscribed.mockResolvedValue(false);
      mockGetPermissionStatus.mockReturnValue('default');
      mockIsSupported.mockReturnValue(true);
      mockIsConfigured.mockReturnValue(true);

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      expect(result.current.isSupported).toBe(true);
      expect(result.current.isConfigured).toBe(true);
    });

    it('should report unsupported when browser lacks push API', async () => {
      mockUseAuth.mockReturnValue({
        user: mockUser,
        isAdmin: false,
        isImpersonating: false,
        impersonate: vi.fn(),
        stopImpersonating: vi.fn(),
      });
      mockGetNotifications.mockResolvedValue([]);
      mockGetUnreadCount.mockResolvedValue(0);
      mockGetOrCreatePreferences.mockResolvedValue({ push_enabled: false });
      mockIsSubscribed.mockResolvedValue(false);
      mockGetPermissionStatus.mockReturnValue('default');
      mockIsSupported.mockReturnValue(false); // Browser doesn't support push
      mockIsConfigured.mockReturnValue(true);

      const { result } = renderHook(() => useNotifications(), { wrapper });

      await waitFor(() => {
        expect(result.current.loading).toBe(false);
      });

      expect(result.current.isSupported).toBe(false);
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, act } from '@testing-library/react';
import { z } from 'zod';
import { useFormValidation, useValidatedForm } from '../useFormValidation';

// Mock error handler
vi.mock('@/lib/errorHandler', () => ({
  logError: vi.fn(),
  errorHandler: {
    handle: vi.fn(),
  },
  throwIfSupabaseError: vi.fn((result) => {
    if (result.error) throw new Error(result.error.message);
    return result.data;
  }),
  requireData: vi.fn((data, operation) => {
    if (data === null || data === undefined) {
      throw new Error(`Failed to ${operation}`);
    }
    return data;
  }),
}));

import { errorHandler } from '@/lib/errorHandler';

const mockErrorHandler = vi.mocked(errorHandler);

describe('useFormValidation', () => {
  const testSchema = z.object({
    name: z.string().min(1, 'Name is required'),
    email: z.string().email('Invalid email format'),
    age: z.number().min(18, 'Must be at least 18'),
  });

  type TestData = z.infer<typeof testSchema>;

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('initial state', () => {
    it('should initialize with empty errors', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      expect(result.current.errors).toEqual([]);
      expect(result.current.isValid).toBe(true);
    });
  });

  describe('validate', () => {
    it('should return true and clear errors for valid data', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      let isValid: boolean;
      act(() => {
        isValid = result.current.validate({
          name: 'John',
          email: 'john@example.com',
          age: 25,
        });
      });

      expect(isValid!).toBe(true);
      expect(result.current.errors).toEqual([]);
      expect(result.current.isValid).toBe(true);
    });

    it('should return false and set errors for invalid data', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      let isValid: boolean;
      act(() => {
        isValid = result.current.validate({
          name: '',
          email: 'invalid',
          age: 15,
        });
      });

      expect(isValid!).toBe(false);
      expect(result.current.errors).toHaveLength(3);
      expect(result.current.isValid).toBe(false);
    });

    it('should set correct error messages', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      act(() => {
        result.current.validate({
          name: '',
          email: 'invalid',
          age: 15,
        });
      });

      const nameError = result.current.errors.find((e) => e.field === 'name');
      const emailError = result.current.errors.find((e) => e.field === 'email');
      const ageError = result.current.errors.find((e) => e.field === 'age');

      expect(nameError?.message).toBe('Name is required');
      expect(emailError?.message).toBe('Invalid email format');
      expect(ageError?.message).toBe('Must be at least 18');
    });

    it('should handle nested field paths', () => {
      const nestedSchema = z.object({
        user: z.object({
          profile: z.object({
            name: z.string().min(1, 'Name required'),
          }),
        }),
      });

      const { result } = renderHook(() => useFormValidation(nestedSchema));

      act(() => {
        result.current.validate({
          user: {
            profile: {
              name: '',
            },
          },
        });
      });

      expect(result.current.errors[0].field).toBe('user.profile.name');
    });

    it('should call errorHandler for non-Zod errors', () => {
      // Create a schema that throws a non-Zod error
      const brokenSchema = {
        parse: () => {
          throw new Error('Unexpected error');
        },
      } as unknown as z.ZodSchema<TestData>;

      const { result } = renderHook(() => useFormValidation(brokenSchema));

      let isValid: boolean;
      act(() => {
        isValid = result.current.validate({
          name: 'test',
          email: 'test@test.com',
          age: 20,
        });
      });

      expect(isValid!).toBe(false);
      expect(mockErrorHandler.handle).toHaveBeenCalled();
    });
  });

  describe('validateField', () => {
    it('should return true for valid field value', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      let isValid: boolean;
      act(() => {
        isValid = result.current.validateField('name', 'John');
      });

      expect(isValid!).toBe(true);
    });

    it('should return false and set error for invalid field value', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      let isValid: boolean;
      act(() => {
        isValid = result.current.validateField('email', 'invalid');
      });

      expect(isValid!).toBe(false);
      expect(result.current.errors).toHaveLength(1);
      expect(result.current.errors[0].field).toBe('email');
    });

    it('should remove existing error for field when valid', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      // First, create an error
      act(() => {
        result.current.validateField('email', 'invalid');
      });

      expect(result.current.errors).toHaveLength(1);

      // Then fix it
      act(() => {
        result.current.validateField('email', 'valid@example.com');
      });

      expect(result.current.errors).toHaveLength(0);
    });

    it('should replace existing error for same field', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      act(() => {
        result.current.validateField('email', 'invalid1');
      });

      act(() => {
        result.current.validateField('email', 'invalid2');
      });

      // Should still have only one error for email
      expect(result.current.errors).toHaveLength(1);
      expect(result.current.errors[0].field).toBe('email');
    });

    it('should return true for unknown field', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      let isValid: boolean;
      act(() => {
        isValid = result.current.validateField('unknownField' as keyof TestData, 'value');
      });

      expect(isValid!).toBe(true);
    });

    it('should preserve errors for other fields', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      act(() => {
        result.current.validateField('name', '');
        result.current.validateField('email', 'invalid');
      });

      expect(result.current.errors).toHaveLength(2);

      act(() => {
        result.current.validateField('name', 'Valid Name');
      });

      // Email error should still exist
      expect(result.current.errors).toHaveLength(1);
      expect(result.current.errors[0].field).toBe('email');
    });
  });

  describe('clearErrors', () => {
    it('should clear all errors', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      act(() => {
        result.current.validate({
          name: '',
          email: 'invalid',
          age: 10,
        });
      });

      expect(result.current.errors.length).toBeGreaterThan(0);

      act(() => {
        result.current.clearErrors();
      });

      expect(result.current.errors).toEqual([]);
      expect(result.current.isValid).toBe(true);
    });
  });

  describe('clearFieldError', () => {
    it('should clear error for specific field', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      act(() => {
        result.current.validate({
          name: '',
          email: 'invalid',
          age: 10,
        });
      });

      const initialErrorCount = result.current.errors.length;

      act(() => {
        result.current.clearFieldError('name');
      });

      expect(result.current.errors.length).toBe(initialErrorCount - 1);
      expect(result.current.errors.find((e) => e.field === 'name')).toBeUndefined();
    });

    it('should do nothing if field has no error', () => {
      const { result } = renderHook(() => useFormValidation(testSchema));

      act(() => {
        result.current.validateField('name', '');
      });

      const errorCount = result.current.errors.length;

      act(() => {
        result.current.clearFieldError('email'); // email has no error
      });

      expect(result.current.errors.length).toBe(errorCount);
    });
  });

  // Note: getFieldError is a trivial array.find - tested implicitly through validateField tests
});

describe('useValidatedForm', () => {
  const testSchema = z.object({
    name: z.string().min(1, 'Name is required'),
    email: z.string().email('Invalid email'),
  });

  const initialData = {
    name: '',
    email: '',
  };

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('initial state', () => {
    it('should initialize with initial data', () => {
      const { result } = renderHook(() => useValidatedForm(initialData, testSchema));

      expect(result.current.data).toEqual(initialData);
      expect(result.current.errors).toEqual([]);
    });
  });

  describe('updateField', () => {
    it('should update field value and validate', () => {
      const { result } = renderHook(() => useValidatedForm(initialData, testSchema));

      act(() => {
        result.current.updateField('name', 'John');
      });

