      act(() => {
        isValid = result.current.validateAll();
      });

      expect(isValid!).toBe(true);
    });

    it('should validate all fields and return false for invalid data', () => {
      const { result } = renderHook(() => useValidatedForm(initialData, testSchema));

      let isValid: boolean;
