/** Global type augmentation for Google Identity Services */
declare global {
  interface Window {
    google?: {
      accounts: {
        id: {
          initialize: (config: GoogleIdConfiguration) => void;
          renderButton: (parent: HTMLElement, options: GoogleButtonConfiguration) => void;
          prompt: () => void;
        };
      };
    };
  }
}

/** Configuration for Google Identity Services initialization */
interface GoogleIdConfiguration {
  client_id: string;
  callback: (response: CredentialResponse) => void;
  auto_select?: boolean;
  use_fedcm_for_prompt?: boolean;
}

/** Configuration for Google Sign-In button rendering */
interface GoogleButtonConfiguration {
  type?: 'standard' | 'icon';
  theme?: 'outline' | 'filled_blue' | 'filled_black';
  size?: 'large' | 'medium' | 'small';
  text?: 'signin_with' | 'signup_with' | 'continue_with' | 'signin';
  shape?: 'rectangular' | 'pill' | 'circle' | 'square';
  logo_alignment?: 'left' | 'center';
  width?: number;
}

/** Response from Google credential callback */
interface CredentialResponse {
  credential: string;
  select_by?: string;
}

/**
 * Initialize and render Google Sign-In button
 * @param containerId - The ID of the HTML element to render the button in
 * @param onSuccess - Callback function when sign-in succeeds, receives the ID token
 * @param onError - Callback function when sign-in fails
 */
export function initializeGoogleButton(
  containerId: string,
  onSuccess: (idToken: string) => void,
  onError: (error: Error) => void
): void {
  const clientId = import.meta.env.VITE_GOOGLE_CLIENT_ID;

  if (!clientId) {
    onError(new Error('Google Client ID is not configured'));
    return;
  }

  const MAX_RETRIES = 50; // 5 seconds max wait (50 * 100ms)
  let retryCount = 0;

  const initializeWhenReady = () => {
    if (window.google?.accounts?.id) {
      try {
        window.google.accounts.id.initialize({
          client_id: clientId,
          callback: (response: CredentialResponse) => {
            onSuccess(response.credential);
          },
          auto_select: false,
          use_fedcm_for_prompt: true,
        });

        const buttonContainer = document.getElementById(containerId);
        if (buttonContainer) {
          window.google.accounts.id.renderButton(buttonContainer, {
            type: 'standard',
            theme: 'outline',
            size: 'large',
            text: 'continue_with',
            shape: 'rectangular',
            logo_alignment: 'left',
          });
        } else {
          onError(new Error(`Container with id "${containerId}" not found`));
        }
      } catch (err) {
        onError(err instanceof Error ? err : new Error('Failed to initialize Google Sign-In'));
      }
    } else {
      retryCount++;
      if (retryCount >= MAX_RETRIES) {
        onError(
          new Error('Google Sign-In SDK failed to load. Please check your internet connection.')
        );
        return;
      }
      setTimeout(initializeWhenReady, 100);
    }
  };

  initializeWhenReady();
}

/**
 * Safe localStorage utilities that handle errors gracefully.
 * Prevents crashes in Safari private mode and other restricted environments.
 */

/**
 * Safely retrieves a value from localStorage.
 * @param key - The storage key to retrieve
 * @returns The stored value or null if not found/unavailable
 */
export function getStorageItem(key: string): string | null {
  try {
    return localStorage.getItem(key);
  } catch {
    return null;
  }
}

/**
 * Safely stores a value in localStorage.
 * @param key - The storage key
 * @param value - The value to store
 * @returns true if successful, false otherwise
 */
export function setStorageItem(key: string, value: string): boolean {
  try {
    localStorage.setItem(key, value);
    return true;
  } catch {
    return false;
  }
}

/**
 * Safely removes a value from localStorage.
 * @param key - The storage key to remove
 * @returns true if successful, false otherwise
 */
export function removeStorageItem(key: string): boolean {
  try {
    localStorage.removeItem(key);
    return true;
  } catch {
    return false;
  }
}

/**
 * Safely retrieves and parses a JSON value from localStorage.
 * @param key - The storage key to retrieve
 * @param defaultValue - Default value if not found or parse fails
 * @returns The parsed value or default
 */
export function getStorageJson<T>(key: string, defaultValue: T): T {
  try {
    const stored = localStorage.getItem(key);
    if (stored === null) return defaultValue;
    return JSON.parse(stored) as T;
  } catch {
    return defaultValue;
  }
}

/**
 * Safely stores a JSON value in localStorage.
 * @param key - The storage key
 * @param value - The value to store (will be JSON.stringify'd)
 * @returns true if successful, false otherwise
 */
export function setStorageJson<T>(key: string, value: T): boolean {
  try {
    localStorage.setItem(key, JSON.stringify(value));
    return true;
  } catch {
    return false;
  }
}

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';
import { formatDistanceToNow } from 'date-fns';
import type { User } from '@supabase/supabase-js';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/**
 * Formats a timestamp as a human-friendly relative time string.
 * Examples: "less than a minute ago", "5 minutes ago", "3 hours ago", "2 days ago"
 */
export function formatTimeAgo(dateString: string): string {
  return formatDistanceToNow(new Date(dateString), { addSuffix: true })
    .replace('minutes', 'mins')
    .replace('minute', 'min');
}

/**
 * Converts an ISO datetime string to local datetime-local input format (YYYY-MM-DDTHH:mm)
 * This is needed for datetime-local inputs which expect local time, not UTC
 * @param iso ISO datetime string (e.g., "2024-12-01T14:00:00Z")
 * @returns Local datetime string for datetime-local input (e.g., "2024-12-01T09:00" for EST)
 */
export function toLocalInputValue(iso: string): string {
  const d = new Date(iso);
  const pad = (n: number) => String(n).padStart(2, '0');
  const year = d.getFullYear();
  const month = pad(d.getMonth() + 1);
  const day = pad(d.getDate());
  const hours = pad(d.getHours());
  const minutes = pad(d.getMinutes());
  return `${year}-${month}-${day}T${hours}:${minutes}`;
}

/**
 * Converts a datetime-local input value to ISO format preserving local timezone
 * This prevents timezone conversion issues when storing datetime-local values
 * @param localValue Local datetime string from datetime-local input (e.g., "2024-12-01T09:00")
 * @returns ISO datetime string in local timezone (e.g., "2024-12-01T09:00:00-05:00")
 */
export function fromLocalInputValue(localValue: string): string {
  if (!localValue) return '';
  // Create date from local value (interpreted as local time)
  const d = new Date(localValue);
  // Return ISO string which includes timezone offset
  return d.toISOString();
}

/**
 * Formats a date to consistent display format: "Tue, Sep 30, 2:00 PM"
 * @param date Date string or Date object
 * @returns Formatted date string (e.g., "Tue, Sep 30, 2:00 PM")
 */
export function formatEventDateTime(date: string | Date): string {
  const d = typeof date === 'string' ? new Date(date) : date;
  return d.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  });
}

/**
 * Checks if an event is in the past based on its datetime
 * @param datetime Event datetime string or null
 * @returns True if event is in the past, false otherwise
 */
export function isEventInPast(datetime: string | null): boolean {
  if (!datetime) return false;
  return new Date(datetime) < new Date();
}

/**
 * Checks if an event has been completed based on its end datetime or start datetime
 * An event is considered completed only after its end time has passed.
 * If no end time is specified, falls back to checking the start datetime.
 * @param datetime Event start datetime string or null
 * @param endDatetime Event end datetime string or null
 * @returns True if event has completed, false otherwise
 */
export function isEventCompleted(datetime: string | null, endDatetime?: string | null): boolean {
  // If there's an end datetime, use that to determine completion
  if (endDatetime) {
    return new Date(endDatetime) < new Date();
  }
  // Otherwise fall back to start datetime
  return isEventInPast(datetime);
}

/**
 * Gets the display name from a Supabase user, preferring the user-edited
 * custom_name over the OAuth-provided full_name. This prevents Google OAuth
 * from overwriting names that users have manually set in their profile.
 */
export function getUserDisplayName(user: User | null, fallback = 'User'): string {
  if (!user) return fallback;
  return user.user_metadata?.custom_name || user.user_metadata?.full_name || fallback;
}

export function canUserClaimSpot({
  hasUser,
  isOrganizer,
  isFirstEmptySlot,
  showGuestRegistration,
}: {
  hasUser: boolean;
  isOrganizer: boolean;
  isFirstEmptySlot: boolean;
  showGuestRegistration: boolean;
}): boolean {
  return hasUser && isOrganizer && isFirstEmptySlot && showGuestRegistration;
}

import { toast } from 'sonner';

import { supabase } from './supabase';
import { setStorageItem } from './storage';

/**
 * Validates the current user session and redirects to login if invalid
 * @returns The validated user object or null if session is invalid
 */
export async function validateSession() {
  const {
    data: { session },
    error,
  } = await supabase.auth.getSession();

  if (error || !session || !session.user) {
    // Session is invalid or expired
    toast.error('Your session has expired. Please sign in again.');

    // Store current path to return after login
    const currentPath = window.location.pathname;
    if (currentPath !== '/auth/login' && currentPath !== '/auth/register') {
      setStorageItem('returnUrl', currentPath);
    }

    // Redirect to login
    window.location.href = '/auth/login';
    return null;
  }

  return session.user;
}

/**
 * Validates session and throws error if invalid
 * Use this in service methods that require authentication
 */
export async function requireValidSession() {
  const user = await validateSession();
  if (!user) {
    throw new Error('Session expired');
  }
  return user;
}

import { toast } from 'sonner';
import type { FieldErrors, FieldValues } from 'react-hook-form';

/**
 * Display toast error for the first validation error.
 * Useful for mobile forms where inline errors may be less visible.
 */
export function showFormErrors<T extends FieldValues>(errors: FieldErrors<T>): void {
  const firstError = Object.values(errors)[0];
  if (firstError?.message && typeof firstError.message === 'string') {
    toast.error(firstError.message);
  }
}

