      expect(result[0].label).toBe('Valid Field');
      expect(result[1].label).toBe('Another Valid');
    });

    it('should validate all supported field types', () => {
      const fields = [
        { label: 'Text', type: 'text', required: false },
        { label: 'Email', type: 'email', required: false },
        { label: 'Phone', type: 'tel', required: false },
        { label: 'Number', type: 'number', required: false },
        { label: 'Select', type: 'select', required: false, options: ['A', 'B'] },
      ];

      const result = validateCustomFields(fields);
      expect(result).toHaveLength(5);
    });
  });

  describe('validateResponses helper', () => {
    it('should return empty object for invalid input', () => {
      expect(validateResponses(null, [])).toEqual({});
      expect(validateResponses(undefined, [])).toEqual({});
      expect(validateResponses({ field: 'value' }, [])).toEqual({});
    });

    it('should validate responses against custom fields', () => {
      const customFields: CustomField[] = [
        { id: 'field1', label: 'Name', type: 'text', required: true },
        { id: 'field2', label: 'Age', type: 'number', required: false },
      ];

      const responses = {
        field1: 'John Doe',
        field2: 25,
        unknownField: 'ignored',
      };

      const result = validateResponses(responses, customFields);
      expect(result).toEqual({
        field1: 'John Doe',
        field2: 25,
      });
    });

    it('should filter out invalid response values', () => {
      const customFields: CustomField[] = [
        { id: 'field1', label: 'Name', type: 'text', required: true },
        { id: 'field2', label: 'Bio', type: 'text', required: false },
      ];

      const responses = {
        field1: 'John Doe',
        field2: 'a'.repeat(1001), // Too long (max 1000 chars)
      };

      const result = validateResponses(responses, customFields);
      expect(result).toEqual({
        field1: 'John Doe',
      });
    });

    it('should handle arrays with validation', () => {
      const customFields: CustomField[] = [
        { id: 'field1', label: 'Options', type: 'select', required: false },
      ];

      // Valid array
      expect(validateResponses({ field1: ['tag1', 'tag2'] }, customFields)).toEqual({
        field1: ['tag1', 'tag2'],
      });

      // Array with invalid item (too long)
      expect(validateResponses({ field1: ['valid', 'a'.repeat(101)] }, customFields)).toEqual({});
    });
  });
});

import { useState, useEffect, useCallback } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { useAuth } from '@/hooks/useAuth';
import { UserMinus, AlertTriangle } from 'lucide-react';
import { TopNav } from '@/components/TopNav';
import { UserAvatar } from '@/components/UserAvatar';
import { groupService, type Group } from '@/services';
import type { GroupParticipant } from '@/services/groupService';
import { errorHandler } from '@/lib/errorHandler';
import { LoadingSpinner } from '@/components/LoadingStates';
import { ActionButton } from '@/components/ActionButton';

interface MemberWithProtection extends GroupParticipant {
  isProtected: boolean;
  role: 'owner' | 'admin' | 'member';
}

export function RemoveMembersPage() {
  const navigate = useNavigate();
  const { groupId } = useParams<{ groupId: string }>();
  const { user, loading: authLoading } = useAuth();
  const [initialLoading, setInitialLoading] = useState(true);
  const [isAdmin, setIsAdmin] = useState(false);
  const [adminLoading, setAdminLoading] = useState(true);
  const [removing, setRemoving] = useState(false);
  const [group, setGroup] = useState<Group | null>(null);
  const [members, setMembers] = useState<MemberWithProtection[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedMemberIds, setSelectedMemberIds] = useState<Set<string>>(new Set());
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);

  const loadData = useCallback(async () => {
    if (!groupId || !user) return;

    try {
      setInitialLoading(true);

      // Check admin status
      const adminStatus = await groupService.isGroupAdmin(groupId, user.id);
      setIsAdmin(adminStatus);
      setAdminLoading(false);

      if (!adminStatus) {
        errorHandler.handle(new Error('Unauthorized'), {
          userId: user.id,
          action: 'loadRemoveMembersPage',
        });
        navigate(`/groups/${groupId}/participants`, { replace: true });
        return;
      }

      // Load group data
      const groupData = await groupService.getGroupById(groupId);
      setGroup(groupData);

      // Load admins to determine protected users
      const adminsData = await groupService.getGroupAdmins(groupId);
      const adminUserIds = new Set(adminsData.map((a) => a.user_id));

      // Load all members
      const membersData = await groupService.getGroupParticipants(groupId);

      // Mark protected members (owner and admins)
      const membersWithProtection: MemberWithProtection[] = membersData.map((member) => {
        const isOwner = member.user_id === groupData.organizer_id;
        const isAdminMember = member.user_id ? adminUserIds.has(member.user_id) : false;
        const isProtected = isOwner || isAdminMember;

        return {
          ...member,
          isProtected,
          role: isOwner ? 'owner' : isAdminMember ? 'admin' : 'member',
        };
      });

      setMembers(membersWithProtection);
    } catch (error) {
      errorHandler.handle(error, {
        userId: user.id,
        action: 'loadRemoveMembersPage',
      });
      navigate(`/groups/${groupId}/participants`, { replace: true });
    } finally {
      setInitialLoading(false);
    }
  }, [groupId, user, navigate]);

  useEffect(() => {
    if (user) {
      loadData();
    }
  }, [user, loadData]);

  const handleToggleMember = (memberId: string, checked: boolean) => {
    const newSelected = new Set(selectedMemberIds);
    if (checked) {
      newSelected.add(memberId);
    } else {
      newSelected.delete(memberId);
    }
    setSelectedMemberIds(newSelected);
  };

  const handleRemoveMembers = async () => {
    if (!groupId || selectedMemberIds.size === 0) return;

    setRemoving(true);
    try {
      // Get selected member IDs as array
      const memberIds = Array.from(selectedMemberIds);

      // Use atomic batch RPC operation
      const result = await groupService.removeParticipantsFromGroupBatch(groupId, memberIds);

      // Close dialog first
      setShowConfirmDialog(false);

      // Report results to user
      if (result.failed === 0) {
        // All succeeded
        errorHandler.success(
          `Removed ${result.removed} ${result.removed === 1 ? 'member' : 'members'} from the group`
        );
        // Clear selection and reload data
        setSelectedMemberIds(new Set());
        await loadData();
      } else if (result.removed === 0) {
        // All failed
        errorHandler.handle(
          new Error(
            `Failed to remove all ${result.failed} selected ${result.failed === 1 ? 'member' : 'members'}`
          ),
          {
            userId: user?.id,
            action: 'removeMembers',
          }
        );
      } else {
        // Partial success
        errorHandler.success(
          `Removed ${result.removed} ${result.removed === 1 ? 'member' : 'members'} successfully`
        );
        if (result.failed > 0) {
          errorHandler.handle(
            new Error(
              `Failed to remove ${result.failed} ${result.failed === 1 ? 'member' : 'members'}`
            ),
            {
              userId: user?.id,
              action: 'removeMembers',
            }
          );
        }
        // Clear selection and reload since we can't identify which specific ones failed
        setSelectedMemberIds(new Set());
        await loadData();
      }
    } catch (error) {
      errorHandler.handle(error, {
        userId: user?.id,
        action: 'removeMembers',
      });
      setShowConfirmDialog(false);
    } finally {
      setRemoving(false);
    }
  };

  // Filter out protected members (owner and admins) and apply search query
  const removableMembers = members.filter((m) => !m.isProtected);
  const filteredMembers = removableMembers.filter(
    (m) =>
      m.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (m.email ?? '').toLowerCase().includes(searchQuery.toLowerCase()) ||
      (m.phone ?? '').includes(searchQuery)
  );
  const selectedCount = selectedMemberIds.size;

  // Loading state
  if (authLoading || adminLoading || initialLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <LoadingSpinner />
      </div>
    );
  }

  // Unauthenticated state
  if (!user) {
    return (
      <div className="min-h-screen bg-background pb-14 flex items-center justify-center p-4">
        <div className="text-center">
          <h1 className="text-lg font-semibold mb-2">Sign In Required</h1>
          <p className="text-sm text-muted-foreground mb-4">
            Please sign in to remove group members
          </p>
          <Button size="sm" onClick={() => navigate('/auth/login')}>
            Sign In
          </Button>
        </div>
      </div>
    );
  }

  // Unauthorized state
  if (!isAdmin || !group) {
    return (
      <div className="min-h-screen bg-background pb-14 flex items-center justify-center p-4">
        <div className="text-center">
          <h1 className="text-lg font-semibold mb-2">Unauthorized</h1>
          <p className="text-sm text-muted-foreground mb-4">
            You don't have permission to remove members from this group
          </p>
          <Button size="sm" onClick={() => navigate(-1)}>
            Go Back
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background pb-32">
      <TopNav showCloseButton sticky />

      <div className="p-3 space-y-3">
        <div className="bg-card rounded-lg border overflow-hidden">
          <div className="p-3 border-b bg-muted">
            <h2 className="text-sm font-medium">
              Remove Members {removableMembers.length > 0 && `(${removableMembers.length})`}
            </h2>
          </div>
          {removableMembers.length === 0 ? (
            <div className="p-3">
              <div className="flex items-start gap-2">
                <AlertTriangle className="h-4 w-4 text-muted-foreground mt-0.5" />
                <div>
                  <p className="text-sm font-medium">No Members to Remove</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    All current members are either the owner or admins
                  </p>
                </div>
              </div>
            </div>
          ) : (
            <>
              <div className="p-3 border-b">
                <Input
                  id="search"
                  type="search"
                  placeholder="Search by name, email, or phone..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="h-9 text-sm"
                />
              </div>

              {filteredMembers.length === 0 ? (
                <div className="p-6 text-center">
                  <p className="text-xs text-muted-foreground">No members found</p>
                </div>
              ) : (
                <div className="divide-y">
                  {filteredMembers.map((member) => (
                    <label
                      key={member.id}
                      className="flex items-center gap-3 p-3 hover:bg-muted cursor-pointer"
                    >
                      <Checkbox
                        checked={selectedMemberIds.has(member.id)}
                        onCheckedChange={(checked) =>
                          handleToggleMember(member.id, checked === true)
                        }
                      />
                      <UserAvatar name={member.name} size="sm" />
                      <div className="flex-1 min-w-0">
                        <div className="text-sm font-medium truncate">{member.name}</div>
                      </div>
                    </label>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      </div>

      {/* Remove Button */}
      {removableMembers.length > 0 && (
        <ActionButton
          loading={removing}
          loadingText="Removing..."
          onClick={() => setShowConfirmDialog(true)}
          disabled={selectedCount === 0}
        >
          <UserMinus className="h-4 w-4 mr-2" />
          Remove {selectedCount > 0 ? selectedCount : ''}{' '}
          {selectedCount === 1 ? 'Member' : 'Members'}
        </ActionButton>
      )}

      {/* Confirmation Dialog */}
      <Dialog open={showConfirmDialog} onOpenChange={setShowConfirmDialog}>
        <DialogContent className="w-[calc(100vw-2rem)] max-w-md">
          <DialogHeader>
            <DialogTitle>
              Remove {selectedCount} {selectedCount === 1 ? 'Member' : 'Members'}?
            </DialogTitle>
            <DialogDescription className="text-xs text-left">
              {selectedCount === 1 ? 'This member' : 'These members'} can be re-added later.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter className="flex-col gap-2 sm:flex-row">
            <Button
              variant="outline"
              onClick={() => setShowConfirmDialog(false)}
              disabled={removing}
              className="w-full sm:w-auto"
            >
              Cancel
            </Button>
            <Button
              variant="destructive"
              onClick={handleRemoveMembers}
              disabled={removing}
              className="w-full sm:w-auto"
            >
              {removing ? 'Removing...' : 'Remove'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { useAuth } from '@/hooks/useAuth';
import { Search, ArrowUpDown, UsersRound, UserMinus, UserCog, LogOut } from 'lucide-react';
import { TopNav } from '@/components/TopNav';
import { UserAvatar } from '@/components/UserAvatar';
import { groupService, type GroupParticipant, type Group } from '@/services';
import { errorHandler } from '@/lib/errorHandler';
import { useLoadingState } from '@/hooks/useLoadingState';
import { ParticipantsPageSkeleton } from '@/components/ParticipantsPageSkeleton';
import { SortDrawer, type SortOption } from '@/components/SortDrawer';

const SORT_OPTIONS: SortOption[] = [
  { value: 'latest', label: 'Latest Join Date' },
  { value: 'earliest', label: 'Earliest Join Date' },
  { value: 'nameAsc', label: 'Name A-Z' },
  { value: 'nameDesc', label: 'Name Z-A' },
  { value: 'eventAsc', label: 'Event A-Z' },
  { value: 'eventDesc', label: 'Event Z-A' },
];

export function GroupParticipantsPage() {
  const navigate = useNavigate();
  const { groupId } = useParams<{ groupId: string }>();
  const { user, loading: authLoading } = useAuth();
  const [group, setGroup] = useState<Group | null>(null);
  const [groupLoading, setGroupLoading] = useState(true);
  const [isAdmin, setIsAdmin] = useState(false);
  const [adminLoading, setAdminLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSearchBar, setShowSearchBar] = useState(false);
  const [showSortDrawer, setShowSortDrawer] = useState(false);
  const [sortOption, setSortOption] = useState('latest');
  const [leavingGroup, setLeavingGroup] = useState(false);
  const [showLeaveDialog, setShowLeaveDialog] = useState(false);
  const loadingRef = useRef(false);
  const {
    isLoading: participantsLoading,
    data: participants,
    execute: loadParticipants,
  } = useLoadingState<GroupParticipant[]>([]);

  const loadGroup = useCallback(async () => {
    if (!groupId || loadingRef.current) return false;

    try {
      loadingRef.current = true;
      setGroupLoading(true);
      const groupData = await groupService.getGroupById(groupId);
      setGroup(groupData);
      return true;
    } catch (error) {
      errorHandler.handle(error, { action: 'load group' });
      navigate('/groups', { replace: true });
      return false;
    } finally {
      setGroupLoading(false);
      loadingRef.current = false;
    }
  }, [groupId, navigate]);

  const loadParticipantsCallback = useCallback(async () => {
    if (!groupId) return [];
    return await groupService.getGroupParticipants(groupId);
  }, [groupId]);

  const checkAdminStatus = useCallback(async () => {
    if (!groupId || !user?.id) {
      setIsAdmin(false);
      setAdminLoading(false);
      return;
    }

    try {
      setAdminLoading(true);
      const adminStatus = await groupService.isGroupAdmin(groupId, user.id);
      setIsAdmin(adminStatus);
    } catch {
      // Silently fail admin check - user just won't see admin features
      setIsAdmin(false);
    } finally {
      setAdminLoading(false);
    }
  }, [groupId, user?.id]);

  const confirmLeaveGroup = useCallback(async () => {
    if (!groupId || !user?.id || !group) return;

    // Don't allow organizer to leave their own group
    if (group.organizer_id === user.id) {
      errorHandler.handle(new Error('You cannot leave a group you created'));
      return;
    }

    setLeavingGroup(true);
    try {
      await groupService.leaveGroup(groupId, user.id);
      errorHandler.success('You have left the group');
      setShowLeaveDialog(false);
      navigate('/groups', { replace: true });
    } catch (error) {
      errorHandler.handle(error, { action: 'leave group' });
    } finally {
      setLeavingGroup(false);
    }
  }, [groupId, user?.id, group, navigate]);

  useEffect(() => {
    if (user) {
      // Only load participants and check admin status if group loads successfully
      loadGroup().then((success) => {
        if (success) {
          loadParticipants(loadParticipantsCallback);
          checkAdminStatus();
        }
      });
    }
  }, [user, loadGroup, loadParticipants, loadParticipantsCallback, checkAdminStatus]);

  const sortedParticipants = (participants: GroupParticipant[]) => {
    const sorted = [...participants];
    switch (sortOption) {
      case 'earliest':
        return sorted.sort(
          (a, b) => new Date(a.group_joined_at).getTime() - new Date(b.group_joined_at).getTime()
        );
      case 'latest':
        return sorted.sort(
          (a, b) => new Date(b.group_joined_at).getTime() - new Date(a.group_joined_at).getTime()
        );
      case 'nameAsc':
        return sorted.sort((a, b) => a.name.localeCompare(b.name));
      case 'nameDesc':
        return sorted.sort((a, b) => b.name.localeCompare(a.name));
      case 'eventAsc':
        return sorted.sort((a, b) => (a.event?.name ?? '').localeCompare(b.event?.name ?? ''));
      case 'eventDesc':
        return sorted.sort((a, b) => (b.event?.name ?? '').localeCompare(a.event?.name ?? ''));
      default:
        return sorted;
    }
  };

  const filteredParticipants = sortedParticipants(
    participants?.filter(
      (p) =>
        p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (p.email ?? '').toLowerCase().includes(searchQuery.toLowerCase()) ||
        (p.phone ?? '').includes(searchQuery) ||
        (p.event?.name ?? '').toLowerCase().includes(searchQuery.toLowerCase())
    ) || []
  );

  if (authLoading || groupLoading || adminLoading) {
    return <ParticipantsPageSkeleton />;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-background pb-14 flex items-center justify-center p-4">
        <div className="text-center">
          <h1 className="text-lg font-semibold mb-2">Sign In Required</h1>
          <p className="text-sm text-muted-foreground mb-4">Please sign in to view group members</p>
          <Button size="sm" onClick={() => navigate('/auth/login')}>
            Sign In
          </Button>
        </div>
      </div>
    );
  }

  if (!group) {
    return (
      <div className="min-h-screen bg-background pb-14 flex items-center justify-center p-4">
        <div className="text-center">
          <h1 className="text-lg font-semibold mb-2">Group Not Found</h1>
          <p className="text-sm text-muted-foreground mb-4">
            The group you're looking for doesn't exist
          </p>
          <Button size="sm" onClick={() => navigate('/groups')}>
            Back to Groups
          </Button>
        </div>
      </div>
    );
  }

  if (participantsLoading) {
    return <ParticipantsPageSkeleton />;
  }

  return (
    <div className="min-h-screen bg-background pb-14">
      <TopNav sticky />

      <div className="p-3 space-y-3">
        {/* Group Name Header */}
        <div className="pb-3 border-b">
          <h2 className="text-base font-semibold break-words">{group.name}</h2>
        </div>
        {/* Quick Actions - Only visible to admins */}
        {isAdmin && (
          <div className="bg-card rounded-lg p-3 border">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-sm font-medium">Quick Actions</h2>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <Button
                variant="outline"
                size="sm"
                className="h-20 flex-col gap-2"
                onClick={() => navigate(`/groups/${groupId}/manage-roles`)}
              >
                <UserCog className="h-5 w-5" />
                <span className="text-xs">Manage</span>
              </Button>
              <Button
                variant="outline"
                size="sm"
                className="h-20 flex-col gap-2"
                onClick={() => navigate(`/groups/${groupId}/remove-members`)}
                disabled={!participants || participants.length === 0}
              >
                <UserMinus className="h-5 w-5" />
                <span className="text-xs">Remove</span>
              </Button>
            </div>
          </div>
        )}

        {!participants || participants.length === 0 ? (
          <div className="bg-card rounded-lg p-6 border text-center">
            <UsersRound className="h-12 w-12 mx-auto text-muted-foreground mb-3" />
            <h2 className="text-base font-medium mb-2">No Members Yet</h2>
            <p className="text-xs text-muted-foreground">
              Members will appear here once people sign up for events in this group
            </p>
          </div>
        ) : (
          <>
            <div className="bg-card rounded-lg border overflow-hidden">
              {/* Header */}
              <div className="p-3 border-b flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium">
                    {filteredParticipants.length}{' '}
                    {filteredParticipants.length === 1 ? 'member' : 'members'}
                  </p>
                </div>
                <div className="flex border border-border rounded">
                  <Button
                    size="sm"
                    variant="ghost"
                    className={`h-7 px-2 rounded-r-none border-0 border-r border-border ${
                      showSearchBar ? 'bg-muted' : ''
                    }`}
                    onClick={() => setShowSearchBar(!showSearchBar)}
                    disabled={participants.length === 0}
                  >
                    <Search className="h-3 w-3" />
                  </Button>
                  <Button
                    size="sm"
                    variant="ghost"
                    className="h-7 px-2 rounded-l-none border-0"
                    onClick={() => setShowSortDrawer(true)}
                    disabled={participants.length === 0}
                  >
                    <ArrowUpDown className="h-3 w-3" />
                  </Button>
                </div>
              </div>
              {/* Search Bar */}
              {showSearchBar && (
                <div className="p-3 border-b bg-muted">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                      type="search"
                      placeholder="Search by name, email, phone, or event..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="pl-9 h-8 text-sm"
                    />
                  </div>
                </div>
              )}
              {/* Participants List */}
              <div className="divide-y">
                {filteredParticipants.length === 0 ? (
                  <div className="p-6 text-center">
                    <p className="text-sm text-muted-foreground">No members found</p>
                  </div>
                ) : (
                  filteredParticipants.map((participant) => {
                    const isCurrentUser = participant.user_id === user?.id;
                    const isOrganizer = group?.organizer_id === user?.id;
                    const canLeave = isCurrentUser && !isOrganizer;

                    return (
                      <div key={participant.id} className="w-full p-3">
                        <div className="flex items-center gap-3">
                          <UserAvatar
                            name={participant.name}
                            avatarUrl={participant.avatar_url}
                            size="sm"
                          />
                          <div className="flex-1 min-w-0">
                            <div className="text-sm font-medium truncate">{participant.name}</div>
                          </div>
                          {canLeave && (
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => setShowLeaveDialog(true)}
                              disabled={leavingGroup}
                              className="text-destructive hover:text-destructive hover:bg-destructive/10 h-8 px-2"
                            >
                              <LogOut className="h-4 w-4 mr-1" />
                              <span className="text-xs">Leave</span>
                            </Button>
                          )}
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            </div>
          </>
        )}
      </div>

      {/* Sort Drawer */}
      <SortDrawer
        open={showSortDrawer}
        onOpenChange={setShowSortDrawer}
        options={SORT_OPTIONS}
        selectedValue={sortOption}
        onSelect={setSortOption}
      />

      {/* Leave Group Confirmation Dialog */}
      <Dialog open={showLeaveDialog} onOpenChange={setShowLeaveDialog}>
        <DialogContent className="w-[calc(100vw-2rem)] max-w-md">
          <DialogHeader>
            <DialogTitle>Leave Group</DialogTitle>
            <DialogDescription className="text-xs text-left">
              You'll need to be re-invited to rejoin this group.
            </DialogDescription>
          </DialogHeader>

          <DialogFooter className="flex-col gap-2 sm:flex-row">
            <Button
              variant="destructive"
              onClick={confirmLeaveGroup}
              disabled={leavingGroup}
              className="w-full sm:w-auto"
            >
              {leavingGroup ? 'Leaving...' : 'Leave Group'}
            </Button>
            <Button
              variant="outline"
              onClick={() => setShowLeaveDialog(false)}
              disabled={leavingGroup}
              className="w-full sm:w-auto"
            >
              Cancel
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

