export function EventsPage() {
  const navigate = useNavigate();
  const { user, loading } = useAuth();
  const {
    isLoading: isLoadingOrganizing,
    data: organizingEvents,
    execute: loadOrganizingEvents,
  } = useLoadingState<Event[]>([]);
  const {
    isLoading: isLoadingJoined,
    data: joinedEvents,
    execute: loadJoinedEvents,
  } = useLoadingState<Event[]>([]);
  const {
    isLoading: isLoadingArchived,
    data: archivedEvents,
    execute: loadArchivedEvents,
  } = useLoadingState<Event[]>([]);
  const [duplicatingEvent, setDuplicatingEvent] = useState<Event | null>(null);
  const [duplicatingEventId, setDuplicatingEventId] = useState<string | null>(null);
  const [paymentFilter, setPaymentFilter] = useState<PaymentFilter>('all');
  const [paymentSummaries, setPaymentSummaries] = useState<Map<string, PaymentSummary>>(new Map());
  const isEventDuplicationEnabled = useFeatureFlag('event_duplication');
  const hasLoadedRef = useRef(false);

  const loadOrganizingEventsCallback = useCallback(async () => {
    if (!user) return [];
    const allEvents = await eventService.getEventsByOrganizer(user.id);
    return allEvents.filter((event) => !isEventCompleted(event.datetime, event.end_datetime));
  }, [user]);

  const loadJoinedEventsCallback = useCallback(async () => {
    if (!user) return [];
    const allEvents = await eventService.getEventsByParticipant(user.id);
    return allEvents.filter((event) => !isEventCompleted(event.datetime, event.end_datetime));
  }, [user]);

  const loadArchivedEventsCallback = useCallback(async () => {
    if (!user) return [];
    const allEvents = await eventService.getEventsByOrganizer(user.id);
    const archived = allEvents.filter((event) =>
      isEventCompleted(event.datetime, event.end_datetime)
    );

    // Fetch payment summaries for archived events
    if (archived.length > 0) {
      const eventIds = archived.map((e) => e.id);
      const summaries = await participantService.getPaymentSummariesBatch(eventIds);
      setPaymentSummaries(summaries);
    } else {
      setPaymentSummaries(new Map());
    }

    return archived;
  }, [user]);

  useEffect(() => {
    if (user && !hasLoadedRef.current) {
      hasLoadedRef.current = true;
      loadOrganizingEvents(loadOrganizingEventsCallback);
      loadJoinedEvents(loadJoinedEventsCallback);
      loadArchivedEvents(loadArchivedEventsCallback);
    }
  }, [
    user,
    loadOrganizingEvents,
    loadJoinedEvents,
    loadArchivedEvents,
    loadOrganizingEventsCallback,
    loadJoinedEventsCallback,
    loadArchivedEventsCallback,
  ]);

  // Filter archived events based on payment status
  const filteredArchivedEvents = useMemo(() => {
    if (!archivedEvents || paymentFilter === 'all') return archivedEvents;

    return archivedEvents.filter((event) => {
      const summary = paymentSummaries.get(event.id);
      if (!summary || summary.total === 0) {
        // Events with no participants - show in "all" and "fully_paid" (nothing to pay)
        return paymentFilter === 'fully_paid';
      }

      const isFullyPaid = summary.pending === 0;
      return paymentFilter === 'fully_paid' ? isFullyPaid : !isFullyPaid;
    });
  }, [archivedEvents, paymentFilter, paymentSummaries]);

  const openDuplicateDrawer = (event: Event) => {
    setDuplicatingEvent(event);
  };

  const confirmDuplicate = async (
    name: string,
    datetime: string | null,
    endDatetime: string | null
  ) => {
    if (!user || !duplicatingEvent) return;

    setDuplicatingEventId(duplicatingEvent.id);
    try {
      const result = await eventService.duplicateEvent(duplicatingEvent.id, user.id, {
        name,
        datetime,
        end_datetime: endDatetime,
      });
      if (result) {
        errorHandler.success(`"${duplicatingEvent.name}" has been duplicated successfully`);
        setDuplicatingEvent(null);
        loadOrganizingEvents(loadOrganizingEventsCallback);
      }
    } catch {
      // Error handling is done by errorHandler in the service
    } finally {
      setDuplicatingEventId(null);
    }
  };

  if (loading) {
    return <EventListSkeleton />;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-background pb-32 flex items-center justify-center p-4">
        <div className="text-center">
          <h1 className="text-lg font-semibold mb-2">Sign In Required</h1>
          <p className="text-sm text-muted-foreground mb-4">Please sign in to view your events</p>
          <Button size="sm" onClick={() => navigate('/auth/login')}>
            Sign In
          </Button>
        </div>
      </div>
    );
  }

  const renderEventList = (
    events: Event[] | null,
    isLoading: boolean,
    showDuplicate: boolean,
    emptyState?: { title: string; description: string; icon?: React.ReactNode },
    showPaymentStatus?: boolean
  ) => {
    if (isLoading) {
      return <EventListSkeleton count={3} />;
    }

    if (!events || events.length === 0) {
      const title = emptyState?.title || (showDuplicate ? 'No Events Yet' : 'No Joined Events');
      const description =
        emptyState?.description ||
        (showDuplicate
          ? 'Create your first event to start managing registrations'
          : "You haven't joined any events yet");

      return (
        <div className="bg-card rounded-lg p-3 border">
          {emptyState?.icon ? (
            <>
              <h2 className="text-base font-medium mb-2 flex items-center justify-center gap-2">
                {title}
                {emptyState.icon}
              </h2>
              <p className="text-xs text-muted-foreground mb-4">{description}</p>
            </>
          ) : (
            <div className="text-center">
              <Calendar className="h-12 w-12 mx-auto text-muted-foreground mb-3" />
              <h2 className="text-base font-medium mb-2">{title}</h2>
              <p className="text-xs text-muted-foreground mb-4">{description}</p>
            </div>
          )}
        </div>
      );
    }

    return (
      <div className="space-y-3">
        {events.map((event) => {
          const summary = showPaymentStatus ? paymentSummaries.get(event.id) : null;
          const isFullyPaid = summary && summary.total > 0 && summary.pending === 0;

          return (
            <div key={event.id} className="bg-card border rounded-lg overflow-hidden relative">
              <button
                onClick={() => navigate(`/signup/${event.id}`)}
                className="w-full p-3 text-left hover:bg-muted transition-colors"
              >
                <div className="pr-8 mb-3">
                  <h3 className="text-sm font-semibold truncate leading-tight">{event.name}</h3>
                  {event.group_name && (
                    <p className="text-xs text-muted-foreground leading-tight">
                      {event.group_name}
                    </p>
                  )}
                </div>
                <div className="flex items-center justify-between text-xs text-muted-foreground">
                  {event.datetime && (
                    <div className="flex items-center gap-1.5">
                      <Calendar className="h-3 w-3 flex-shrink-0" />
                      <span>{formatEventDateTime(event.datetime)}</span>
                    </div>
                  )}
                  <div className="flex items-center gap-3">
                    {showPaymentStatus && summary && summary.total > 0 && (
                      <div
                        className={`flex items-center gap-1 ${isFullyPaid ? 'text-green-600' : 'text-amber-600'}`}
                      >
                        {isFullyPaid ? (
                          <>
                            <CheckCircle className="h-3 w-3" />
                            <span className="font-medium">Paid</span>
                          </>
                        ) : (
                          <>
                            <Clock className="h-3 w-3" />
                            <span className="font-medium">
                              {summary.paid}/{summary.total}
                            </span>
                          </>
                        )}
                      </div>
                    )}
                    <div className="flex items-center gap-1 text-muted-foreground">
                      <Users className="h-3 w-3" />
                      <span className="font-medium">{event.participant_count || 0}</span>
                    </div>
                  </div>
                </div>
              </button>
              {showDuplicate && (
                <Button
                  size="sm"
                  variant="ghost"
                  className="absolute top-2 right-2 h-6 w-6 p-0 hover:bg-muted-foreground/10"
                  disabled={duplicatingEventId === event.id}
                  onClick={(e) => {
                    e.stopPropagation();
                    openDuplicateDrawer(event);
                  }}
                >
                  {duplicatingEventId === event.id ? (
                    <LoadingSpinner size="sm" />
                  ) : (
                    <Copy className="h-3 w-3" />
                  )}
                </Button>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-background pb-32">
      <Tabs defaultValue="joined" className="w-full">
        <div className="sticky top-0 z-20 bg-background">
          <TopNav />
          <div className="bg-card border-b px-3 py-2 flex justify-center">
            <TabsList className="h-8 p-0.5 bg-background border">
              <TabsTrigger value="joined" className="h-7 px-3 text-xs">
                Joined
              </TabsTrigger>
              <TabsTrigger value="organizing" className="h-7 px-3 text-xs">
                Organizing
              </TabsTrigger>
              <TabsTrigger value="archive" className="h-7 px-3 text-xs">
                Archive
              </TabsTrigger>
            </TabsList>
          </div>
        </div>
        <TabsContent value="joined" className="p-3 space-y-3 mt-0">
          {renderEventList(joinedEvents, isLoadingJoined, false, {
            title: 'Welcome to Roster!',
            description:
              'Join an event using a link from your organizer, or create your own with the button below.',
            icon: <span>🎉</span>,
          })}
          {(!joinedEvents || joinedEvents.length === 0) && !isLoadingJoined && (
            <Alert className="border-violet-500/30 bg-violet-500/10 [&>svg]:text-violet-500">
              <Lightbulb className="h-4 w-4 text-violet-500" />
              <AlertTitle className="text-xs font-medium text-violet-700 dark:text-violet-300">
                Tip
              </AlertTitle>
              <AlertDescription className="text-xs text-violet-700 dark:text-violet-300">
                Add Roster to your home screen for quick access — tap the share button in your
                browser and select "Add to Home Screen".
              </AlertDescription>
            </Alert>
          )}
        </TabsContent>

        <TabsContent value="organizing" className="p-3 space-y-3 mt-0 pb-24">
          {renderEventList(organizingEvents, isLoadingOrganizing, isEventDuplicationEnabled)}
        </TabsContent>

        <TabsContent value="archive" className="p-3 space-y-3 mt-0">
          <div className="flex items-center gap-2">
            <span className="text-xs text-muted-foreground">Payment:</span>
            <Select
              value={paymentFilter}
              onValueChange={(value) => setPaymentFilter(value as PaymentFilter)}
            >
              <SelectTrigger className="h-8 w-[140px] text-xs">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Events</SelectItem>
                <SelectItem value="fully_paid">Fully Paid</SelectItem>
                <SelectItem value="has_unpaid">Has Unpaid</SelectItem>
              </SelectContent>
            </Select>
          </div>
          {renderEventList(
            filteredArchivedEvents,
            isLoadingArchived,
            false,
            {
              title:
                paymentFilter === 'all'
                  ? 'No Archived Events'
                  : paymentFilter === 'fully_paid'
                    ? 'No Fully Paid Events'
                    : 'No Events with Unpaid',
              description:
                paymentFilter === 'all'
                  ? 'Past events will appear here once their date has passed'
                  : 'No archived events match this filter',
            },
            true
          )}
        </TabsContent>
      </Tabs>

      <button
        onClick={() => navigate('/events/new')}
        className="fixed bottom-20 right-4 z-40 h-12 w-12 rounded-full bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white shadow-lg drop-shadow-md flex items-center justify-center font-medium transition-all"
        aria-label="Create Event"
      >
        <Plus className="h-5 w-5" />
      </button>

      <DuplicateEventDrawer
        open={!!duplicatingEvent}
        onOpenChange={(open) => !open && setDuplicatingEvent(null)}
        eventName={duplicatingEvent?.name || ''}
        datetime={duplicatingEvent?.datetime || null}
        endDatetime={duplicatingEvent?.end_datetime || null}
        submitting={!!duplicatingEventId}
        onConfirm={confirmDuplicate}
      />
    </div>
  );
}

import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { useAuth } from '@/hooks/useAuth';
import { FullScreenDrawer } from '@/components/ui/full-screen-drawer';
import { groupService } from '@/services';
import { errorHandler } from '@/lib/errorHandler';
import { Plus } from 'lucide-react';
import { groupFormSchema, type GroupFormData } from '@/lib/validation';
import { showFormErrors } from '@/lib/formUtils';

export function NewGroupPage() {
  const navigate = useNavigate();
  const { user } = useAuth();

  const handleClose = () => {
    if (window.history.state && window.history.state.idx > 0) {
      navigate(-1);
    } else {
      navigate('/groups');
    }
  };

  const {
    register,
    handleSubmit,
    watch,
    formState: { isSubmitting, errors },
  } = useForm<GroupFormData>({
    resolver: zodResolver(groupFormSchema),
    defaultValues: {
      name: '',
      description: '',
    },
  });

  const nameValue = watch('name');
  const descriptionValue = watch('description');

  const onSubmit = async (data: GroupFormData) => {
    if (!user) {
      errorHandler.handle(new Error('You must be signed in to create a group'));
      return;
    }

    try {
      const group = await groupService.createGroup({
        organizer_id: user.id,
        name: data.name.trim(),
        description: data.description?.trim() || null,
      });

      errorHandler.success('Group created successfully!');
      navigate(`/groups/${group.id}`, { replace: true });
    } catch (error) {
      errorHandler.handle(error, { userId: user?.id, action: 'create group' });
    }
  };

  if (!user) {
    return (
      <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
        <div className="flex-1 flex items-center justify-center p-4">
          <div className="text-center">
            <h1 className="text-lg font-semibold mb-2">Sign In Required</h1>
            <p className="text-sm text-muted-foreground mb-4">Please sign in to create a group</p>
            <Button size="sm" onClick={() => navigate('/auth/login')}>
              Sign In
            </Button>
          </div>
        </div>
      </FullScreenDrawer>
    );
  }

  return (
    <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
      <form
        id="create-group-form"
        onSubmit={handleSubmit(onSubmit, showFormErrors)}
        className="flex-1 flex flex-col overflow-y-auto p-3 bg-background"
      >
        {/* Group Name */}
        <div className="space-y-2">
          <Label htmlFor="name" className="text-sm">
            Group Name *
          </Label>
          <Input
            {...register('name')}
            id="name"
            type="text"
            placeholder="Enter group name"
            className={`h-10 text-sm ${errors.name ? 'border-destructive' : ''}`}
            maxLength={200}
            autoComplete="off"
          />
          {errors.name && <p className="text-sm text-destructive">{errors.name.message}</p>}
          <p className="text-xs text-muted-foreground">{nameValue?.length || 0}/200 characters</p>
        </div>

        {/* Description - fills remaining space */}
        <div className="flex-1 flex flex-col space-y-2 mt-4 min-h-0">
          <Label htmlFor="description" className="text-sm">
            Description
          </Label>
          <Textarea
            {...register('description')}
            id="description"
            placeholder="Describe your group (optional)"
            className={`flex-1 text-sm resize-none min-h-[100px] ${errors.description ? 'border-destructive' : ''}`}
            maxLength={2000}
          />
          {errors.description && (
            <p className="text-sm text-destructive">{errors.description.message}</p>
          )}
          <p className="text-xs text-muted-foreground">
            {descriptionValue?.length || 0}/2000 characters
          </p>
        </div>

        <div className="border-t mt-4" />

        {/* Create Group Button */}
        <Button
          type="submit"
          disabled={isSubmitting}
          className="w-full mt-4 bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white shadow-lg"
        >
          {isSubmitting ? (
            'Creating Group...'
          ) : (
            <>
              <Plus className="h-4 w-4 mr-2" />
              Create Group
            </>
          )}
        </Button>
      </form>
    </FullScreenDrawer>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Checkbox } from '@/components/ui/checkbox';
import { useAuth } from '@/hooks/useAuth';
import { Shield, X, UserPlus } from 'lucide-react';
import { TopNav } from '@/components/TopNav';
import { UserAvatar } from '@/components/UserAvatar';
import { groupService, organizerService, type Group } from '@/services';
import type { GroupParticipant, GroupAdmin } from '@/services/groupService';
import { errorHandler } from '@/lib/errorHandler';
import { LoadingSpinner } from '@/components/LoadingStates';
import { ActionButton } from '@/components/ActionButton';

interface AdminWithDetails extends GroupAdmin {
  displayName: string;
}

interface MemberWithRole extends GroupParticipant {
  isOwner: boolean;
  isAdmin: boolean;
}

export function ManageRolesPage() {
  const navigate = useNavigate();
  const { groupId } = useParams<{ groupId: string }>();
  const { user, loading: authLoading } = useAuth();
  const [initialLoading, setInitialLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [group, setGroup] = useState<Group | null>(null);
  const [ownerName, setOwnerName] = useState<string>('Unknown');
  const [admins, setAdmins] = useState<AdminWithDetails[]>([]);
  const [members, setMembers] = useState<MemberWithRole[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedMemberIds, setSelectedMemberIds] = useState<Set<string>>(new Set());
  const [removingAdminId, setRemovingAdminId] = useState<string | null>(null);

  const loadData = useCallback(async () => {
    if (!groupId || !user) return;

    try {
      setInitialLoading(true);

      // Load group and verify ownership
      const groupData = await groupService.getGroupById(groupId);

      if (groupData.organizer_id !== user.id) {
        errorHandler.handle(new Error('Unauthorized'), {
          userId: user.id,
          action: 'loadManageRolesPage',
        });
        navigate('/groups', { replace: true });
        return;
      }

      setGroup(groupData);

      // Load owner display name
      const ownerDisplayName = await organizerService.getOrganizerDisplayName(
        groupData.organizer_id
      );
      setOwnerName(ownerDisplayName);

      // Load current admins with their display names
      const adminsData = await groupService.getGroupAdmins(groupId);
      const adminsWithDetails = await Promise.all(
        adminsData.map(async (admin) => {
          const displayName = await organizerService.getOrganizerDisplayName(admin.user_id);
          return { ...admin, displayName };
        })
      );
      setAdmins(adminsWithDetails);

      // Load all group members
      const membersData = await groupService.getGroupParticipants(groupId);

      // Filter out owner and existing admins, mark their roles
      const adminUserIds = new Set(adminsData.map((a) => a.user_id));
      const membersWithRoles: MemberWithRole[] = membersData.map((member) => ({
        ...member,
        isOwner: member.user_id === groupData.organizer_id,
        isAdmin: member.user_id ? adminUserIds.has(member.user_id) : false,
      }));

      setMembers(membersWithRoles);
    } catch (error) {
      errorHandler.handle(error, {
        userId: user.id,
        action: 'loadManageRolesPage',
      });
      navigate('/groups', { replace: true });
    } finally {
      setInitialLoading(false);
    }
  }, [groupId, user, navigate]);

  useEffect(() => {
    if (user) {
      loadData();
    }
  }, [user, loadData]);

  const handleToggleMember = (memberId: string, checked: boolean) => {
    const newSelected = new Set(selectedMemberIds);
    if (checked) {
      newSelected.add(memberId);
    } else {
      newSelected.delete(memberId);
    }
    setSelectedMemberIds(newSelected);
  };

  const handlePromoteToAdmin = async () => {
    if (!groupId || selectedMemberIds.size === 0) return;

    setSaving(true);
    try {
      // Get user_ids from selected members
      const selectedMembers = members.filter((m) => selectedMemberIds.has(m.id) && m.user_id);

      // Promote each member to admin
      for (const member of selectedMembers) {
        if (member.user_id) {
          await groupService.addGroupAdmin(groupId, member.user_id);
        }
      }

      errorHandler.success(
        `Promoted ${selectedMembers.length} ${selectedMembers.length === 1 ? 'member' : 'members'} to admin`
      );

      // Clear selection and reload data
      setSelectedMemberIds(new Set());
      await loadData();
    } catch (error) {
      errorHandler.handle(error, {
        userId: user?.id,
        action: 'promoteToAdmin',
      });
    } finally {
      setSaving(false);
    }
  };

  const handleRemoveAdmin = async (adminId: string, userId: string) => {
    if (!groupId) return;

    setRemovingAdminId(adminId);
    try {
      await groupService.removeGroupAdmin(groupId, userId);
      errorHandler.success('Admin role removed');
      await loadData();
    } catch (error) {
      errorHandler.handle(error, {
        userId: user?.id,
        action: 'removeAdmin',
      });
    } finally {
      setRemovingAdminId(null);
    }
  };

  // Filter eligible members (not owner, not already admin, has user_id)
  const eligibleMembers = members.filter(
    (m) => !m.isOwner && !m.isAdmin && m.user_id && !m.claimed_by_user_id
  );

  // Filter by search query
  const filteredMembers = eligibleMembers.filter(
    (m) =>
      m.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (m.email ?? '').toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Loading state
  if (authLoading || initialLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <LoadingSpinner />
      </div>
    );
  }

  // Unauthenticated state
  if (!user) {
    return (
      <div className="min-h-screen bg-background pb-14 flex items-center justify-center p-4">
        <div className="text-center">
          <h1 className="text-lg font-semibold mb-2">Sign In Required</h1>
          <p className="text-sm text-muted-foreground mb-4">Please sign in to manage group roles</p>
          <Button size="sm" onClick={() => navigate('/auth/login')}>
            Sign In
          </Button>
        </div>
      </div>
    );
  }

  // Unauthorized state
  if (!group) {
    return (
      <div className="min-h-screen bg-background pb-14 flex items-center justify-center p-4">
        <div className="text-center">
          <h1 className="text-lg font-semibold mb-2">Unauthorized</h1>
          <p className="text-sm text-muted-foreground mb-4">
            You don't have permission to manage roles for this group
          </p>
          <Button size="sm" onClick={() => navigate(-1)}>
            Go Back
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background pb-32">
      <TopNav showCloseButton sticky />

      <div className="p-3 space-y-3">
        {/* Group Owner Card */}
        <div className="bg-card rounded-lg border overflow-hidden">
          <div className="p-3 border-b bg-muted flex items-center gap-2">
            <Shield className="h-4 w-4 text-primary" />
            <h2 className="text-sm font-medium">Group Owner</h2>
          </div>
          <div className="p-3">
            <div className="flex items-center justify-between">
              <div>
                <div className="text-sm font-medium">{ownerName}</div>
                <div className="text-xs text-muted-foreground">Full access to group</div>
              </div>
              <Badge variant="default">Owner</Badge>
            </div>
          </div>
        </div>

        {/* Current Admins Card */}
        <div className="bg-card rounded-lg border overflow-hidden">
          <div className="p-3 border-b bg-muted">
            <h2 className="text-sm font-medium">
              Current Admins {admins.length > 0 && `(${admins.length})`}
            </h2>
          </div>
          {admins.length === 0 ? (
            <div className="p-3 text-xs text-muted-foreground">
              No admins yet. Promote members below to help manage this group.
            </div>
          ) : (
            <div className="divide-y">
              {admins.map((admin) => (
                <div key={admin.id} className="p-3 flex items-center gap-3">
                  <UserAvatar name={admin.displayName} size="sm" />
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium truncate">{admin.displayName}</div>
                    <div className="text-xs text-muted-foreground">
                      Can manage members and events
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <Badge variant="secondary">Admin</Badge>
                    <Button
                      variant="ghost"
                      size="sm"
                      className="h-8 w-8 p-0"
                      onClick={() => handleRemoveAdmin(admin.id, admin.user_id)}
                      disabled={removingAdminId === admin.id}
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Promote Members Card */}
        <div className="bg-card rounded-lg border overflow-hidden">
          <div className="p-3 border-b bg-muted">
            <h2 className="text-sm font-medium">
              Promote Members to Admin {eligibleMembers.length > 0 && `(${eligibleMembers.length})`}
            </h2>
          </div>
          {eligibleMembers.length === 0 ? (
            <div className="p-3 text-xs text-muted-foreground">
              No eligible members to promote. Only registered members with accounts can become
              admins.
            </div>
          ) : (
            <>
              <div className="p-3 border-b">
                <Input
                  id="search"
                  type="search"
                  placeholder="Search by name or email..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="h-9 text-sm"
                />
              </div>

              {filteredMembers.length === 0 ? (
                <div className="p-6 text-center">
                  <p className="text-xs text-muted-foreground">No members found</p>
                </div>
              ) : (
                <div className="divide-y">
                  {filteredMembers.map((member) => (
                    <label
                      key={member.id}
                      className="flex items-center gap-3 p-3 hover:bg-muted cursor-pointer"
                    >
                      <Checkbox
                        checked={selectedMemberIds.has(member.id)}
                        onCheckedChange={(checked) =>
                          handleToggleMember(member.id, checked === true)
                        }
                      />
                      <UserAvatar name={member.name} size="sm" />
                      <div className="flex-1 min-w-0">
                        <div className="text-sm font-medium truncate">{member.name}</div>
                      </div>
                    </label>
                  ))}
