import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { useAuth } from '@/hooks/useAuth';
import { FullScreenDrawer } from '@/components/ui/full-screen-drawer';
import { groupService } from '@/services';
import { errorHandler } from '@/lib/errorHandler';
import { LoadingSpinner } from '@/components/LoadingStates';
import { Save, Trash2 } from 'lucide-react';
import type { Group } from '@/services/groupService';
import { groupFormSchema, type GroupFormData } from '@/lib/validation';
import { showFormErrors } from '@/lib/formUtils';

export function EditGroupPage() {
  const { groupId } = useParams<{ groupId: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [deleting, setDeleting] = useState(false);
  const [initialLoading, setInitialLoading] = useState(true);
  const [group, setGroup] = useState<Group | null>(null);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  const handleClose = () => {
    if (window.history.state && window.history.state.idx > 0) {
      navigate(-1);
    } else {
      navigate('/groups');
    }
  };

  const {
    register,
    handleSubmit,
    watch,
    reset,
    formState: { isSubmitting, errors },
  } = useForm<GroupFormData>({
    resolver: zodResolver(groupFormSchema),
    defaultValues: {
      name: '',
      description: '',
    },
  });

  const nameValue = watch('name');
  const descriptionValue = watch('description');

  useEffect(() => {
    if (!groupId) {
      setInitialLoading(false);
      return;
    }

    if (!user) {
      setInitialLoading(false);
      return;
    }

    setInitialLoading(true);

    // Create cancellation flag to prevent stale fetches from updating state
    let cancelled = false;

    const loadGroup = async () => {
      if (!groupId || !user) {
        if (!cancelled) setInitialLoading(false);
        return;
      }

      try {
        const data = await groupService.getGroupById(groupId);

        // Check if this fetch was cancelled before updating state
        if (cancelled) return;

        // Handle missing group
        if (!data) {
          if (!cancelled) {
            setGroup(null);
            setInitialLoading(false);
          }
          return;
        }

        // Verify ownership
        if (data.organizer_id !== user.id) {
          errorHandler.handle(new Error('Unauthorized'), {
            userId: user.id,
            action: 'loadGroupForEdit',
          });
          if (!cancelled) {
            setInitialLoading(false);
            navigate('/groups', { replace: true });
          }
          return;
        }

        if (!cancelled) {
          setGroup(data);
          reset({
            name: data.name,
            description: data.description || '',
          });
          setInitialLoading(false);
        }
      } catch (error) {
        if (!cancelled) {
          errorHandler.handle(error, {
            userId: user?.id,
            action: 'loadGroupForEdit',
          });
          setInitialLoading(false);
          navigate('/groups', { replace: true });
        }
      }
    };

    loadGroup();

    // Cleanup function to cancel the fetch if dependencies change
    return () => {
      cancelled = true;
    };
  }, [groupId, user, reset, navigate]);

  const onSubmit = async (data: GroupFormData) => {
    if (!group || !user) return;

    try {
      await groupService.updateGroup(group.id, {
        name: data.name.trim(),
        description: data.description?.trim() || null,
      });

      errorHandler.success('Group updated successfully!');
      navigate(`/groups/${group.id}`, { replace: true });
    } catch (error) {
      errorHandler.handle(error, {
        userId: user.id,
        action: 'updateGroup',
        metadata: { groupId: group.id },
      });
    }
  };

  const confirmDelete = async () => {
    if (!group || !user) return;

    setDeleting(true);
    try {
      await groupService.deleteGroup(group.id, true);

      errorHandler.success('Group deleted successfully');

      // Close dialog before navigate to avoid setState on unmounted component
      setShowDeleteDialog(false);
      navigate('/groups', { replace: true });
    } catch (error) {
      errorHandler.handle(error, {
        userId: user.id,
        action: 'deleteGroup',
        metadata: { groupId: group.id, groupName: group.name },
      });
    } finally {
      setDeleting(false);
    }
  };

  if (initialLoading) {
    return (
      <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
        <div className="flex-1 flex items-center justify-center p-4">
          <LoadingSpinner />
        </div>
      </FullScreenDrawer>
    );
  }

  if (!user) {
    return (
      <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
        <div className="flex-1 flex items-center justify-center p-4">
          <div className="text-center">
            <h1 className="text-lg font-semibold mb-2">Sign In Required</h1>
            <p className="text-sm text-muted-foreground mb-4">Please sign in to edit this group</p>
            <Button size="sm" onClick={() => navigate('/auth/login')}>
              Sign In
            </Button>
          </div>
        </div>
      </FullScreenDrawer>
    );
  }

  if (!group) {
    return (
      <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
        <div className="flex-1 flex items-center justify-center p-4">
          <div className="text-center">
            <h1 className="text-lg font-semibold mb-2">Group Not Found</h1>
            <p className="text-sm text-muted-foreground">
              This group doesn't exist or you don't have permission to edit it.
            </p>
          </div>
        </div>
      </FullScreenDrawer>
    );
  }

  return (
    <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
      <form
        id="edit-group-form"
        onSubmit={handleSubmit(onSubmit, showFormErrors)}
        className="flex-1 flex flex-col overflow-y-auto p-3 bg-background"
      >
        {/* Group Name */}
        <div className="space-y-2">
          <Label htmlFor="name">Group Name *</Label>
          <Input
            {...register('name')}
            id="name"
            type="text"
            placeholder="Enter group name"
            className={errors.name ? 'border-destructive' : ''}
            maxLength={200}
            autoComplete="off"
          />
          {errors.name && <p className="text-sm text-destructive">{errors.name.message}</p>}
          <p className="text-xs text-muted-foreground">{nameValue?.length || 0}/200 characters</p>
        </div>

        {/* Description - fills remaining space */}
        <div className="flex-1 flex flex-col space-y-2 mt-4 min-h-0">
          <Label htmlFor="description">Description</Label>
          <Textarea
            {...register('description')}
            id="description"
            placeholder="Describe your group (optional)"
            className={`flex-1 resize-none min-h-[100px] ${errors.description ? 'border-destructive' : ''}`}
            maxLength={2000}
          />
          {errors.description && (
            <p className="text-sm text-destructive">{errors.description.message}</p>
          )}
          <p className="text-xs text-muted-foreground">
            {descriptionValue?.length || 0}/2000 characters
          </p>
        </div>

        <div className="border-t mt-4" />

        {/* Delete Group Button */}
        <Button
          variant="outline"
          className="w-full mt-4 text-destructive hover:text-destructive hover:bg-destructive/10"
          onClick={() => setShowDeleteDialog(true)}
          disabled={isSubmitting || deleting}
          type="button"
        >
          <Trash2 className="h-4 w-4 mr-2" />
          Delete Group
        </Button>

        {/* Save Changes Button */}
        <Button
          type="submit"
          disabled={isSubmitting || deleting}
          className="w-full mt-2 bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white shadow-lg"
        >
          {isSubmitting ? (
            <>
              <LoadingSpinner size="sm" />
              Saving...
            </>
          ) : (
            <>
              <Save className="h-4 w-4 mr-2" />
              Save Changes
            </>
          )}
        </Button>
      </form>

      {/* Delete Confirmation Dialog */}
      <Dialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <DialogContent className="w-[calc(100vw-2rem)] max-w-md">
          <DialogHeader>
            <DialogTitle>Delete Group</DialogTitle>
            <DialogDescription className="text-xs text-left">
              This will delete all events and participant data in this group.
            </DialogDescription>
          </DialogHeader>

          <DialogFooter className="flex-col gap-2 sm:flex-row">
            <Button
              variant="destructive"
              onClick={confirmDelete}
              disabled={deleting}
              className="w-full sm:w-auto"
            >
              {deleting ? 'Deleting...' : 'Delete Group'}
            </Button>
            <Button
              variant="outline"
              onClick={() => setShowDeleteDialog(false)}
              disabled={deleting}
              className="w-full sm:w-auto"
            >
              Cancel
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </FullScreenDrawer>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useForm, Controller } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { useAuth } from '@/hooks/useAuth';
import { useFeatureFlag } from '@/hooks/useFeatureFlags';
import { useCustomFields } from '@/hooks/useCustomFields';
import { Trash2, Save } from 'lucide-react';
import { FullScreenDrawer } from '@/components/ui/full-screen-drawer';
import { eventService } from '@/services';
import { errorHandler, ValidationError } from '@/lib/errorHandler';
import { showFormErrors } from '@/lib/formUtils';
import { editEventFormSchema, type EditEventFormData } from '@/lib/validation';
import { EditEventPageSkeleton } from '@/components/EditEventPageSkeleton';
import { MaxParticipantsInput } from '@/components/MaxParticipantsInput';
import { toLocalInputValue, fromLocalInputValue } from '@/lib/utils';
import { CustomFieldsEditor } from '@/components/CustomFieldsEditor';
import { PrivacyToggle } from '@/components/PrivacyToggle';
import { TbdDateTimeField } from '@/components/TbdDateTimeField';
import { Checkbox } from '@/components/ui/checkbox';
import type { CustomField } from '@/types/app.types';

interface EventData {
  id: string;
  name: string;
  description: string | null;
  datetime: string | null;
  end_datetime: string | null;
  location: string | null;
  max_participants: number | null;
  is_paid: boolean;
  is_private: boolean | null;
  custom_fields: CustomField[];
  group_id: string | null;
}

/**
 * Render the Edit Event page for an event organizer to view and modify an event.
 *
 * The page loads event data, verifies ownership, and provides controls to edit
 * name, description, date/time, location, max participants, privacy, and custom
 * participant fields. It also supports saving updates and permanently deleting
 * the event, with loading states and error handling.
 *
 * @returns The rendered Edit Event page as JSX
 */
export function EditEventPage() {
  const { eventId } = useParams<{ eventId: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [loading, setLoading] = useState(false);
  const showEventPrivacy = useFeatureFlag('event_privacy');
  const showRegistrationForm = useFeatureFlag('registration_form');
  const [initialLoading, setInitialLoading] = useState(true);
  const [event, setEvent] = useState<EventData | null>(null);

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    reset,
    control,
    formState: { errors },
  } = useForm<EditEventFormData>({
    resolver: zodResolver(editEventFormSchema),
    defaultValues: {
      name: '',
      description: '',
      datetime: '',
      end_datetime: '',
      location: '',
      is_paid: true,
      is_private: false,
      datetimeTbd: false,
      endDatetimeTbd: false,
      locationTbd: false,
      max_participants: 10,
    },
  });

  const formData = watch();

  const { customFields, addCustomField, updateCustomField, removeCustomField, resetCustomFields } =
    useCustomFields();
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  // Store previous values when TBD is checked so we can restore them
  const [previousValues, setPreviousValues] = useState({
    datetime: '',
    end_datetime: '',
    location: '',
  });

  useEffect(() => {
    if (eventId && user) {
      loadEvent();
    }
  }, [eventId, user]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadEvent = async () => {
    if (!eventId || !user) return;

    try {
      const data = await eventService.getEventById(eventId);

      // Verify ownership
      if (data.organizer_id !== user.id) {
        errorHandler.handle(new Error('Unauthorized'), {
          userId: user.id,
          action: 'loadEventForEdit',
        });
        navigate('/events', { replace: true });
        return;
      }

      setEvent({
        ...data,
        custom_fields: data.custom_fields || [],
      });
      reset({
        name: data.name,
        description: data.description || '',
        datetime: data.datetime ? toLocalInputValue(data.datetime) : '',
        end_datetime: data.end_datetime ? toLocalInputValue(data.end_datetime) : '',
        location: data.location || '',
        is_paid: data.is_paid ?? true,
        is_private: data.is_private ?? false,
        datetimeTbd: !data.datetime,
        endDatetimeTbd: !data.end_datetime,
        locationTbd: !data.location,
        max_participants: data.max_participants || 10,
      });
      resetCustomFields(data.custom_fields || []);
    } catch (error) {
      errorHandler.handle(error, {
        userId: user?.id,
        action: 'loadEventForEdit',
      });
      navigate('/events', { replace: true });
    } finally {
      setInitialLoading(false);
    }
  };

  const onSubmit = async (data: EditEventFormData) => {
    if (!event || !user) return;

    // Client-side validation for past dates
    const now = new Date();
    if (data.datetime) {
      const startDate = new Date(data.datetime);
      if (startDate < now) {
        errorHandler.handle(
          new ValidationError('Start date validation failed', 'Start date cannot be in the past'),
          {
            userId: user.id,
            action: 'validateEventDates',
          }
        );
        return;
      }
    }

    if (data.end_datetime) {
      const endDate = new Date(data.end_datetime);
      if (endDate < now) {
        errorHandler.handle(
          new ValidationError('End date validation failed', 'End date cannot be in the past'),
          {
            userId: user.id,
            action: 'validateEventDates',
          }
        );
        return;
      }
    }

    // Client-side validation for end date
    if (data.datetime && data.end_datetime) {
      const startDate = new Date(data.datetime);
      const endDate = new Date(data.end_datetime);
      if (endDate <= startDate) {
        errorHandler.handle(
          new ValidationError('Date range validation failed', 'End date must be after start date'),
          {
            userId: user.id,
            action: 'validateEventDates',
          }
        );
        return;
      }
    }

    setLoading(true);
    try {
      await eventService.updateEvent(event.id, {
        name: data.name,
        description: data.description || null,
        datetime: data.datetime ? fromLocalInputValue(data.datetime) : null,
        end_datetime: data.end_datetime ? fromLocalInputValue(data.end_datetime) : null,
        location: data.location || null,
        max_participants: data.max_participants,
        is_paid: data.is_paid,
        is_private: data.is_private,
        custom_fields: customFields
          .filter((f) => f.label)
          .map((f) => ({
            ...f,
            options: f.type === 'select' ? f.options : undefined,
          })),
      });

      errorHandler.success('Event updated successfully!');
      navigate(`/signup/${event.id}`, { replace: true });
    } catch (error) {
      const errorMessage =
        error instanceof Error
          ? error.message
          : typeof error === 'object' && error !== null && 'message' in error
            ? String((error as { message: unknown }).message)
            : String(error);
      if (errorMessage.includes('Cannot reduce capacity')) {
        errorHandler.info(
          'Cannot reduce capacity below current registrations. Remove some participants first.'
        );
      } else {
        errorHandler.handle(error, {
          userId: user.id,
          action: 'updateEvent',
          metadata: { eventId: event.id },
        });
      }
    } finally {
      setLoading(false);
    }
  };

  const confirmDelete = async () => {
    if (!event || !user) return;

    setLoading(true);
    try {
      await eventService.deleteEvent(event.id);

      errorHandler.success('Event deleted successfully');
      navigate(event.group_id ? `/groups/${event.group_id}` : '/events', { replace: true });
    } catch (error) {
      errorHandler.handle(error, {
        userId: user.id,
        action: 'deleteEvent',
        metadata: { eventId: event.id, eventName: event.name },
      });
    } finally {
      setLoading(false);
      setShowDeleteDialog(false);
    }
  };

  const handleClose = () => {
    if (window.history.state && window.history.state.idx > 0) {
      navigate(-1);
    } else {
      navigate(event?.group_id ? `/groups/${event.group_id}` : '/events');
    }
  };

  if (initialLoading) {
    return (
      <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
        <EditEventPageSkeleton />
      </FullScreenDrawer>
    );
  }

  if (!event) {
    return (
      <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
        <div className="flex-1 bg-background flex items-center justify-center p-4">
          <div className="text-center">
            <h1 className="text-lg font-semibold mb-2">Event Not Found</h1>
            <p className="text-sm text-muted-foreground">
              This event doesn't exist or you don't have permission to edit it.
            </p>
          </div>
        </div>
      </FullScreenDrawer>
    );
  }

  return (
    <FullScreenDrawer open={true} onOpenChange={(open) => !open && handleClose()}>
      <form
        onSubmit={handleSubmit(onSubmit, showFormErrors)}
        className="flex-1 overflow-y-auto p-3 space-y-4 bg-background"
      >
        <div className="space-y-2">
          <Label htmlFor="name" className="text-sm">
            Event Name *
          </Label>
          <Input
            id="name"
            type="text"
            {...register('name')}
            className={`h-10 text-sm ${errors.name ? 'border-destructive' : ''}`}
            autoComplete="off"
          />
          {errors.name && <p className="text-xs text-destructive">{errors.name.message}</p>}
        </div>

        <div className="space-y-2">
          <Label htmlFor="description" className="text-sm">
            Description
          </Label>
          <Textarea
            id="description"
            {...register('description')}
            className="text-sm resize-none"
            rows={3}
          />
        </div>

        <div className="border-t" />

        <TbdDateTimeField
          id="datetime"
          label="Start Date & Time"
          value={formData.datetime || ''}
          isTbd={formData.datetimeTbd}
          onValueChange={(value) => {
            setValue('datetime', value);
            if (
              value &&
              !formData.endDatetimeTbd &&
              (!formData.end_datetime || value >= formData.end_datetime)
            ) {
              setValue('end_datetime', value);
            }
          }}
          onTbdChange={(isTbd, prevValue) => {
            if (isTbd) {
              setPreviousValues((prev) => ({ ...prev, datetime: prevValue }));
              setValue('datetimeTbd', true);
              setValue('datetime', '');
            } else {
              setValue('datetimeTbd', false);
              setValue('datetime', previousValues.datetime);
            }
          }}
          type="datetime"
        />

        <TbdDateTimeField
          id="end_datetime"
          label="End Date & Time"
          value={formData.end_datetime || ''}
          isTbd={formData.endDatetimeTbd}
          onValueChange={(value) => setValue('end_datetime', value)}
          onTbdChange={(isTbd, prevValue) => {
            if (isTbd) {
              setPreviousValues((prev) => ({ ...prev, end_datetime: prevValue }));
              setValue('endDatetimeTbd', true);
              setValue('end_datetime', '');
            } else {
              setValue('endDatetimeTbd', false);
              setValue('end_datetime', previousValues.end_datetime);
            }
          }}
          type="datetime"
          error={
            !!(
              formData.datetime &&
              formData.end_datetime &&
              formData.end_datetime <= formData.datetime
            )
          }
        />

        <TbdDateTimeField
          id="location"
          label="Location"
          value={formData.location || ''}
          isTbd={formData.locationTbd}
          onValueChange={(value) => setValue('location', value)}
          onTbdChange={(isTbd, prevValue) => {
            if (isTbd) {
              setPreviousValues((prev) => ({ ...prev, location: prevValue }));
              setValue('locationTbd', true);
              setValue('location', '');
            } else {
              setValue('locationTbd', false);
              setValue('location', previousValues.location);
            }
          }}
          type="text"
        />

        <div className="border-t" />

        <Controller
          name="max_participants"
          control={control}
          render={({ field }) => (
            <MaxParticipantsInput value={field.value} onChange={field.onChange} />
          )}
        />

        <div className="flex items-center space-x-2">
          <Controller
            name="is_paid"
            control={control}
            render={({ field }) => (
              <Checkbox id="is_paid" checked={field.value} onCheckedChange={field.onChange} />
            )}
          />
          <label htmlFor="is_paid" className="text-sm cursor-pointer">
            Paid event
          </label>
        </div>

        {showEventPrivacy && (
          <PrivacyToggle
            isPrivate={formData.is_private}
            onChange={(isPrivate) => setValue('is_private', isPrivate)}
          />
        )}

        {showRegistrationForm && (
          <>
            <div className="border-t" />
            <CustomFieldsEditor
              customFields={customFields}
              onAdd={addCustomField}
              onUpdate={updateCustomField}
              onRemove={removeCustomField}
            />
          </>
        )}

        {/* Delete Event Button */}
        <Button
          type="button"
          variant="outline"
          className="w-full text-destructive hover:text-destructive hover:bg-destructive/10"
          onClick={() => setShowDeleteDialog(true)}
          disabled={loading}
        >
          <Trash2 className="h-4 w-4 mr-2" />
          Delete Event
        </Button>

        {/* Save Changes Button */}
        <Button
          type="submit"
          disabled={loading}
          className="w-full bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white shadow-lg"
        >
          <Save className="h-4 w-4 mr-2" />
          {loading ? 'Saving...' : 'Save Changes'}
        </Button>
      </form>

      {/* Delete Confirmation Dialog */}
      <Dialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <DialogContent className="w-[calc(100vw-2rem)] max-w-md">
          <DialogHeader>
            <DialogTitle>Delete Event</DialogTitle>
            <DialogDescription className="text-xs text-left">
              This will permanently delete this event and all its data.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter className="flex-col gap-2 sm:flex-row">
            <Button
              variant="outline"
              onClick={() => setShowDeleteDialog(false)}
              disabled={loading}
              className="w-full sm:w-auto"
            >
              Cancel
            </Button>
            <Button
              variant="destructive"
              onClick={confirmDelete}
              disabled={loading}
              className="w-full sm:w-auto"
            >
              {loading ? 'Deleting...' : 'Delete Event'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </FullScreenDrawer>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { useAuth } from '@/hooks/useAuth';
import { eventService, groupService } from '@/services';
import type { Event } from '@/services/eventService';
import type { Group } from '@/services/groupService';
import { EventDetailSkeleton } from '@/components/EventDetailSkeleton';
import { formatEventDateTime } from '@/lib/utils';
import { errorHandler } from '@/lib/errorHandler';
import { Calendar, Users, UserPlus } from 'lucide-react';

type InviteType = 'event' | 'group';

export function InviteConfirmationPage() {
  const { type, id } = useParams<{ type: InviteType; id: string }>();
  const navigate = useNavigate();
  const { user, loading: authLoading } = useAuth();

  const [loading, setLoading] = useState(true);
  const [eventData, setEventData] = useState<Event | null>(null);
  const [groupData, setGroupData] = useState<Group | null>(null);
  const loadingRef = useRef(false);
  const errorHandledRef = useRef(false);

  useEffect(() => {
    // Reset refs on mount/remount
    loadingRef.current = false;
    errorHandledRef.current = false;

    if (!type || !id) {
      if (!errorHandledRef.current) {
        errorHandledRef.current = true;
        errorHandler.handle(new Error('Invalid invite link'));
        navigate('/', { replace: true });
      }
      return;
    }

    if (type !== 'event' && type !== 'group') {
      if (!errorHandledRef.current) {
        errorHandledRef.current = true;
        errorHandler.handle(new Error('Invalid invite type'));
        navigate('/', { replace: true });
      }
      return;
    }

    loadInviteData();

    return () => {
      // Prevent duplicate error handling on unmount
      loadingRef.current = true;
    };
  }, [type, id, user]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadInviteData = async () => {
    if (!type || !id || loadingRef.current) return;

    try {
      loadingRef.current = true;
      setLoading(true);

      if (type === 'event') {
        const event = await eventService.getEventById(id);
        setEventData(event);

        // Auto-redirect logged-in users to the event detail page
        if (user) {
          navigate(`/signup/${id}`, { replace: true });
          return;
        }
      } else if (type === 'group') {
        const group = await groupService.getGroupById(id);
        setGroupData(group);

        // Auto-join and redirect logged-in users to the group page
        if (user) {
          const isGroupMember = await groupService.checkUserGroupMembership(user.id, id);
          if (!isGroupMember) {
            // Auto-join the group when user lands on invite page after signing in
            try {
              await groupService.addUserToGroup(id, user.id);
            } catch (joinErr) {
              // Still redirect, they can try manual join from group page
              errorHandler.handle(joinErr, { action: 'auto-join group' });
            }
          }
          navigate(`/groups/${id}`, { replace: true });
          return;
        }
      }
    } catch (err) {
      // Prevent duplicate error toasts
      if (!errorHandledRef.current) {
        errorHandledRef.current = true;
        errorHandler.handle(err, { action: 'load invite' });
        navigate('/', { replace: true });
      }
      setLoading(false);
      return;
    }
    setLoading(false);
    loadingRef.current = false;
  };

  const handleSignInClick = () => {
    if (!type || !id) return;

    // Return to invite page after login so user can complete the join action
    const targetUrl = `/invite/${type}/${id}`;

    // Navigate to login with returnUrl pointing back to invite page
    navigate(`/auth/login?returnUrl=${encodeURIComponent(targetUrl)}`);
  };

  if (loading || authLoading) {
    return <EventDetailSkeleton />;
  }

  // Event Invite UI
  if (type === 'event' && eventData) {
    return (
      <div className="min-h-screen bg-background pb-20">
        <div className="bg-card border-b">
          <div className="flex items-center justify-center px-4 py-3">
            <h1 className="text-lg font-semibold">Event Invitation</h1>
          </div>
        </div>

        <div className="p-3 space-y-3">
          {/* Event Info Card */}
          <div className="bg-card rounded-lg border overflow-hidden">
            <div>
              {/* Event Name */}
              <div className="p-3 border-b border-border">
                <h2 className="text-lg font-semibold">{eventData.name}</h2>
                {eventData.is_private && (
                  <Badge variant="secondary" className="text-xs mt-1">
                    Private
                  </Badge>
                )}
              </div>

              {/* Top row: Start and End times */}
              {(eventData.datetime || eventData.end_datetime) && (
                <div className="grid grid-cols-2 divide-x divide-border">
                  <div className="text-sm text-muted-foreground p-3">
                    <div className="font-medium text-foreground">Start</div>
                    <div>
                      {eventData.datetime ? formatEventDateTime(eventData.datetime) : 'Not set'}
                    </div>
                  </div>
                  <div className="text-sm text-muted-foreground p-3">
                    <div className="font-medium text-foreground">End</div>
                    <div>
                      {eventData.end_datetime
                        ? formatEventDateTime(eventData.end_datetime)
                        : 'Not set'}
                    </div>
                  </div>
                </div>
              )}

              {/* Registration Deadline section */}
              {(eventData.datetime || eventData.end_datetime) && (
                <>
                  <div className="border-t border-border"></div>
                  <div className="text-sm text-muted-foreground p-3">
                    <div className="font-medium text-foreground">Registration Deadline</div>
                    <div>None</div>
                  </div>
                </>
              )}

              {/* Horizontal divider between registration deadline and location */}
              {(eventData.datetime || eventData.end_datetime) && eventData.location && (
                <div className="border-t border-border"></div>
              )}

              {/* Location */}
              {eventData.location && (
                <div className="text-sm text-muted-foreground p-3">
                  <div className="font-medium text-foreground">Location</div>
                  <div>{eventData.location}</div>
                </div>
              )}

              {/* Horizontal divider */}
              {eventData.location && eventData.max_participants && (
                <div className="border-t border-border"></div>
              )}

              {/* Capacity */}
              {eventData.max_participants && (
                <div className="text-sm text-muted-foreground p-3">
                  <div className="font-medium text-foreground">Capacity</div>
                  <div>
                    {eventData.participant_count || 0} / {eventData.max_participants} participants
                  </div>
                </div>
              )}

              {/* Horizontal divider */}
              {(eventData.location || eventData.max_participants) && eventData.description && (
                <div className="border-t border-border"></div>
              )}

              {/* Description */}
              {eventData.description && (
                <div className="text-sm text-foreground p-3">
                  <div className="font-medium text-foreground mb-1">Description</div>
                  <p className="leading-relaxed">{eventData.description}</p>
                </div>
              )}
            </div>
          </div>

          {/* Action Card - only shown for unauthenticated users (authenticated users are auto-redirected) */}
          <div className="bg-card rounded-lg border p-4">
            <div className="text-center space-y-3">
              <p className="text-sm text-muted-foreground">Sign in to RSVP for this event</p>
              <Button onClick={handleSignInClick} className="w-full">
                Sign in to RSVP
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Group Invite UI
  if (type === 'group' && groupData) {
    return (
      <div className="min-h-screen bg-background pb-20">
        <div className="bg-card border-b">
          <div className="flex items-center justify-center px-4 py-3">
            <h1 className="text-lg font-semibold">Group Invitation</h1>
          </div>
        </div>

        <div className="p-3 space-y-3">
          {/* Group Info Card */}
          <div className="bg-card rounded-lg border overflow-hidden">
            <div className="p-4 space-y-3">
              <div>
                <h2 className="text-lg font-semibold mb-1">{groupData.name}</h2>
              </div>

              {groupData.description && (
                <p className="text-sm text-muted-foreground leading-relaxed">
                  {groupData.description}
                </p>
              )}

              <div className="flex items-center gap-4 text-sm text-muted-foreground pt-2 border-t">
                <div className="flex items-center gap-1">
                  <Calendar className="h-4 w-4" />
                  <span>{groupData.event_count || 0} events</span>
                </div>
                <div className="flex items-center gap-1">
                  <Users className="h-4 w-4" />
                  <span>{groupData.participant_count || 0} members</span>
                </div>
              </div>
            </div>
          </div>

          {/* Action Card - only shown for unauthenticated users (authenticated users are auto-redirected) */}
          <div className="bg-card rounded-lg border p-4">
            <div className="text-center space-y-3">
              <p className="text-sm text-muted-foreground">
                Sign in to view this group and join its events
              </p>
              <Button onClick={handleSignInClick} className="w-full">
                <UserPlus className="h-4 w-4 mr-2" />
                Sign in to join
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return null;
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Calendar, Users, CreditCard, Bookmark, UsersRound } from 'lucide-react';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/lib/supabase';
import { TopNav } from '@/components/TopNav';
import { type Participant } from '@/services/participantService';
import { UpcomingEventsListSkeleton } from '@/components/LoadingStates';
import { formatEventDateTime } from '@/lib/utils';
import { errorHandler } from '@/lib/errorHandler';

interface UpcomingEvent {
  id: string;
  name: string;
  datetime: string | null;
  location: string | null;
  isOrganizer: boolean;
  participantCount?: number;
}

export function HomePage() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [upcomingEvents, setUpcomingEvents] = useState<UpcomingEvent[]>([]);
  const [loading, setLoading] = useState(false);
  const [timePeriod, setTimePeriod] = useState<'all' | 'week' | 'month' | 'year'>('all');

  useEffect(() => {
    if (user) {
      loadUpcomingEvents();
    }
  }, [user, timePeriod]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadUpcomingEvents = async () => {
    setLoading(true);
    try {
      const now = new Date();
      let startDate: Date;
      let endDate: Date;

      if (timePeriod === 'all') {
        // For 'all', just use current time as start date and far future as end date
        startDate = new Date(now);
        endDate = new Date('2099-12-31'); // Far future date
      } else if (timePeriod === 'week') {
        // Get start and end of current week
        startDate = new Date(now);
        startDate.setDate(now.getDate() - now.getDay()); // Sunday
        startDate.setHours(0, 0, 0, 0);

        endDate = new Date(startDate);
        endDate.setDate(startDate.getDate() + 6); // Saturday
        endDate.setHours(23, 59, 59, 999);
      } else if (timePeriod === 'month') {
        // Get start and end of current month
        startDate = new Date(now.getFullYear(), now.getMonth(), 1);
        startDate.setHours(0, 0, 0, 0);

        endDate = new Date(now.getFullYear(), now.getMonth() + 1, 0);
        endDate.setHours(23, 59, 59, 999);
      } else {
        // Get start and end of current year
        startDate = new Date(now.getFullYear(), 0, 1);
        startDate.setHours(0, 0, 0, 0);

        endDate = new Date(now.getFullYear() + 1, 0, 0); // Last day of current year
        endDate.setHours(23, 59, 59, 999);
      }

      const events: UpcomingEvent[] = [];

      // Get events the user organized with participant counts in a single query
      const { data: organizedEventsWithCounts } = await supabase
        .from('events')
        .select(
          `
          id,
          name,
          datetime,
          location,
          participants!left(id)
        `
        )
        .eq('organizer_id', user?.id || '')
        .gte('datetime', now.toISOString()) // Only future events
        .lte('datetime', endDate.toISOString())
        .order('datetime', { ascending: true });

      if (organizedEventsWithCounts) {
        // Add organized events with their participant counts
        for (const event of organizedEventsWithCounts) {
          events.push({
            id: event.id,
            name: event.name,
            datetime: event.datetime,
            location: event.location,
            isOrganizer: true,
            participantCount: (event.participants as Participant[])?.length || 0,
          });
        }
      }

      // Get events the user signed up for as a participant (if they have user_id stored)
      const { data: participantEvents } = await supabase
        .from('participants')
        .select(
          `
          events!inner (
            id,
            name,
            datetime,
            location,
            organizer_id
          )
        `
        )
        .eq('user_id', user?.id || '')
        .gte('events.datetime', now.toISOString()) // Only future events
        .lte('events.datetime', endDate.toISOString());

      if (participantEvents) {
        for (const participantEvent of participantEvents) {
          const eventData = participantEvent.events as any; // eslint-disable-line @typescript-eslint/no-explicit-any
          const event = Array.isArray(eventData) ? eventData[0] : eventData;
          // Don't duplicate events the user is organizing
          if (event?.organizer_id !== user?.id) {
            events.push({
              id: event.id,
              name: event.name,
              datetime: event.datetime,
              location: event.location,
              isOrganizer: false,
            });
          }
        }
      }

      // Sort all events by datetime
      events.sort((a, b) => {
        if (!a.datetime) return 1;
        if (!b.datetime) return -1;
        return new Date(a.datetime).getTime() - new Date(b.datetime).getTime();
      });

      setUpcomingEvents(events);
    } catch (error) {
      errorHandler.handle(error, { userId: user?.id, action: 'load upcoming events' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-background pb-14">
      <TopNav sticky />

      <div className="p-3 space-y-3">
        {user ? (
          <>
            <div className="bg-card rounded-lg p-3 border">
              <div className="flex items-center justify-between mb-3">
                <h2 className="text-sm font-medium">Quick Actions</h2>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  className="h-20 flex-col gap-2"
                  onClick={() => navigate('/groups/new')}
                >
                  <UsersRound className="h-5 w-5" />
                  <span className="text-xs">Create Group</span>
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  className="h-20 flex-col gap-2"
                  onClick={() => navigate('/events/new')}
                >
                  <Calendar className="h-5 w-5" />
                  <span className="text-xs">Create Event</span>
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  className="h-20 flex-col gap-2"
                  onClick={() => navigate('/payments')}
                >
                  <CreditCard className="h-5 w-5" />
                  <span className="text-xs">Payments</span>
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  className="h-20 flex-col gap-2"
                  onClick={() => navigate('/bookmarked')}
                >
                  <Bookmark className="h-5 w-5" />
                  <span className="text-xs">Bookmarked</span>
                </Button>
              </div>
            </div>

            <div className="bg-card rounded-lg border overflow-hidden">
              <div className="p-3 border-b">
                <div className="flex items-center justify-between">
                  <h2 className="text-sm font-medium">Upcoming Events</h2>
                  <Select
                    value={timePeriod}
                    onValueChange={(value: 'all' | 'week' | 'month' | 'year') =>
                      setTimePeriod(value)
                    }
                  >
                    <SelectTrigger className="w-20 h-7 text-xs">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="min-w-0 w-20">
                      <SelectItem value="all" className="text-xs py-1 px-2">
                        All
                      </SelectItem>
                      <SelectItem value="week" className="text-xs py-1 px-2">
                        Week
                      </SelectItem>
                      <SelectItem value="month" className="text-xs py-1 px-2">
                        Month
                      </SelectItem>
                      <SelectItem value="year" className="text-xs py-1 px-2">
                        Year
                      </SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {loading ? (
                <UpcomingEventsListSkeleton count={3} />
              ) : upcomingEvents.length === 0 ? (
                <div className="p-3 text-xs text-muted-foreground text-center">
                  No events{' '}
                  {timePeriod === 'all'
                    ? 'found'
                    : timePeriod === 'week'
                      ? 'this week'
                      : timePeriod === 'month'
                        ? 'this month'
                        : 'this year'}
                </div>
              ) : (
                <div className="divide-y">
                  {upcomingEvents.map((event) => (
                    <button
                      key={event.id}
                      onClick={() => navigate(`/signup/${event.id}`)}
                      className="w-full p-3 text-left hover:bg-muted transition-colors"
                    >
                      <div className="flex flex-col">
                        <div className="flex items-start justify-between mb-2">
                          <h3 className="text-sm font-semibold truncate flex-1 min-w-0 pr-2">
                            {event.name}
                          </h3>
                          <Badge
                            variant={event.isOrganizer ? 'default' : 'secondary'}
                            className="text-xs h-5 px-2 flex-shrink-0"
                          >
                            {event.isOrganizer ? 'Organizer' : 'Attending'}
                          </Badge>
                        </div>
                        <div className="flex items-end justify-between">
                          <div className="space-y-1 flex-1 min-w-0">
                            {event.datetime && (
                              <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                                <Calendar className="h-3 w-3 flex-shrink-0" />
                                <span>{formatEventDateTime(event.datetime)}</span>
                              </div>
                            )}
                            {event.location && (
                              <div className="text-xs text-muted-foreground truncate">
                                📍 {event.location}
                              </div>
                            )}
                          </div>
                          {event.isOrganizer && event.participantCount !== undefined && (
                            <div className="flex items-center gap-1 text-xs text-muted-foreground bg-muted px-2 py-1 rounded-full">
                              <Users className="h-3 w-3" />
                              <span className="font-medium">{event.participantCount}</span>
                            </div>
                          )}
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </>
        ) : (
          <>
            {/* Hero Section */}
            <div className="bg-gradient-to-b from-primary/5 to-background rounded-lg p-6 border text-center">
              <div className="mb-4">
                <h1 className="text-2xl font-bold mb-3">Stop Managing. Start Organizing.</h1>
                <p className="text-sm text-muted-foreground">
                  The mobile-first app that turns event chaos into seamless coordination
                </p>
              </div>
              <div className="space-y-2">
                <Button className="w-full" size="lg" onClick={() => navigate('/auth/register')}>
                  Get Started Free
                </Button>
                <p className="text-sm text-muted-foreground">
                  Already have an account?{' '}
                  <button
                    onClick={() => navigate('/auth/login')}
                    className="text-primary font-medium hover:underline"
                  >
                    Sign in
                  </button>
                </p>
              </div>
              <p className="text-xs text-muted-foreground mt-3">No credit card required</p>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

import { useEffect } from 'react';
import { useNavigate, Link, useSearchParams } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useAuth } from '@/hooks/useAuth';
import { initializeGoogleButton } from '@/lib/googleAuth';
import { TopNav } from '@/components/TopNav';
import { registerFormSchema, type RegisterFormData } from '@/lib/validation';
import { showFormErrors } from '@/lib/formUtils';

export function RegisterPage() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { signUp, signInWithGoogleIdToken } = useAuth();

  const {
    register,
    handleSubmit,
    setError,
    formState: { isSubmitting, errors },
  } = useForm<RegisterFormData>({
    resolver: zodResolver(registerFormSchema),
    defaultValues: {
      fullName: '',
      email: '',
      password: '',
    },
  });

  const returnUrl = searchParams?.get('returnUrl') || '/';

  const onSubmit = async (data: RegisterFormData) => {
    try {
      await signUp(data.email, data.password, data.fullName);
