import { supabase } from '@/lib/supabase';
import { logError } from '@/lib/errorHandler';
import type { Tables, Json } from '@/types/supabase';

export type ParticipantActivityType =
  | 'joined'
  | 'withdrew'
  | 'payment_updated'
  | 'info_updated'
  | 'label_added'
  | 'label_removed';

export type ParticipantActivity = Tables<'participant_activity_log'> & {
  activity_type: ParticipantActivityType;
  details: Record<string, unknown>;
};

const TABLE_NAME = 'participant_activity_log' as const;

/** Helper to insert activity log entry via RPC (bypasses RLS for cross-user logging) */
async function insertActivity(
  participantId: string | null,
  eventId: string,
  activityType: ParticipantActivityType,
  participantName: string,
  details: Record<string, unknown>
): Promise<void> {
  const { error } = await supabase.rpc('log_participant_activity', {
    p_participant_id: participantId,
    p_event_id: eventId,
    p_activity_type: activityType,
    p_participant_name: participantName,
    p_details: details as Json,
  });

  if (error) {
    logError('Failed to log participant activity', error, { participantId, eventId, activityType });
  }
}

export const participantActivityService = {
  /**
   * Get all activity for an event (for event-wide activity view)
   */
  async getEventActivity(eventId: string, limit = 100): Promise<ParticipantActivity[]> {
    const { data, error } = await supabase
      .from(TABLE_NAME)
      .select('*')
      .eq('event_id', eventId)
      .order('created_at', { ascending: false })
      .limit(limit);

    if (error) throw error;
    return (data || []) as ParticipantActivity[];
  },

  /**
   * Get activity history for a single participant
   */
  async getParticipantActivity(participantId: string, limit = 50): Promise<ParticipantActivity[]> {
    const { data, error } = await supabase
      .from(TABLE_NAME)
      .select('*')
      .eq('participant_id', participantId)
      .order('created_at', { ascending: false })
      .limit(limit);

    if (error) throw error;
    return (data || []) as ParticipantActivity[];
  },

  // ============================================================================
  // Activity Logging Functions (moved from DB triggers)
  // ============================================================================

  /**
   * Log when a participant joins an event
   */
  async logJoined(params: {
    participantId: string;
    eventId: string;
    participantName: string;
  }): Promise<void> {
    await insertActivity(
      params.participantId,
      params.eventId,
      'joined',
      params.participantName,
      {}
    );
  },

  /**
   * Log when a participant withdraws from an event
   */
  async logWithdrew(params: {
    participantId: string;
    eventId: string;
    participantName: string;
    paymentStatus: string;
  }): Promise<void> {
    await insertActivity(params.participantId, params.eventId, 'withdrew', params.participantName, {
      payment_status: params.paymentStatus,
    });
  },

  /**
   * Log when a participant's payment status changes
   */
  async logPaymentUpdated(params: {
    participantId: string;
    eventId: string;
    participantName: string;
    fromStatus: string;
    toStatus: string;
  }): Promise<void> {
    await insertActivity(
      params.participantId,
      params.eventId,
      'payment_updated',
      params.participantName,
      {
        from: params.fromStatus,
        to: params.toStatus,
      }
    );
  },

  /**
   * Log when a participant's info is updated
   */
  async logInfoUpdated(params: {
    participantId: string;
    eventId: string;
    participantName: string;
    changes: {
      name?: { from: string | null; to: string | null };
      email?: { from: string | null; to: string | null };
      phone?: { from: string | null; to: string | null };
      notes?: { from: string | null; to: string | null };
    };
  }): Promise<void> {
    const details: Record<string, unknown> = {};
    if (params.changes.name) details.name = params.changes.name;
    if (params.changes.email) details.email = params.changes.email;
    if (params.changes.phone) details.phone = params.changes.phone;
    if (params.changes.notes) details.notes = params.changes.notes;

    // Only log if there are actual changes
    if (Object.keys(details).length === 0) return;

    await insertActivity(
      params.participantId,
      params.eventId,
      'info_updated',
      params.participantName,
      details
    );
  },

  /**
   * Log when a label is added to a participant
   */
  async logLabelAdded(params: {
    participantId: string;
    eventId: string;
    participantName: string;
    labelId: string;
    labelName: string;
  }): Promise<void> {
    await insertActivity(
      params.participantId,
      params.eventId,
      'label_added',
      params.participantName,
      {
        label_id: params.labelId,
        label_name: params.labelName,
      }
    );
  },

  /**
   * Log when a label is removed from a participant
   */
  async logLabelRemoved(params: {
    participantId: string;
    eventId: string;
    participantName: string;
    labelId: string;
    labelName: string;
  }): Promise<void> {
    await insertActivity(
      params.participantId,
      params.eventId,
      'label_removed',
      params.participantName,
      {
        label_id: params.labelId,
        label_name: params.labelName,
      }
    );
  },
};

import { supabase } from '@/lib/supabase';
import type { Tables, TablesInsert, TablesUpdate } from '@/types/supabase';
import { throwIfSupabaseError, requireData, ValidationError } from '@/lib/errorHandler';
import { requireValidSession } from '@/lib/sessionValidator';

/** Extended Group type with computed event and participant counts */
export interface Group extends Tables<'groups'> {
  event_count?: number;
  participant_count?: number;
}

export interface GroupParticipant
  extends Omit<Tables<'participants'>, 'event_id' | 'payment_status' | 'checked_in_at'> {
  event_id: string | null;
  payment_status: string | null;
  checked_in_at: string | null;
  event: {
    id: string;
    name: string;
  } | null;
  group_joined_at: string;
  avatar_url: string | null;
}

export interface GroupContact {
  id: string;
  name: string;
  email: string | null;
  user_id: string | null;
  first_seen: string;
}

/** Internal interface for nested Supabase query results */
interface EventWithParticipants extends Tables<'events'> {
  participants: Array<{ id: string } | null>;
}

interface GroupQueryResult {
  groups: Tables<'groups'> | Array<Tables<'groups'>>;
}

export interface GroupStats {
  event_count: number;
  participant_count: number;
  total_registrations: number;
}

export type GroupAdmin = Tables<'group_admins'>;

/**
 * Validates group data before create or update operations.
 * @param group - Partial group data to validate
 * @throws ValidationError if name is empty, too long, or description is too long
 */
function validateGroupData(group: Partial<Group>): void {
  if (group.name !== undefined) {
    if (!group.name || group.name.trim().length === 0) {
      throw new ValidationError('Group name is required', 'Please enter a group name');
    }
    if (group.name.length > 200) {
      throw new ValidationError(
        'Group name is too long',
        'Group name must be 200 characters or less'
      );
    }
  }

  if (group.description !== undefined && group.description !== null) {
    if (group.description.length > 2000) {
      throw new ValidationError(
        'Group description is too long',
        'Description must be 2000 characters or less'
      );
    }
  }
}

export const groupService = {
  /**
   * Retrieves all groups created by an organizer with event and member counts.
   * @param organizerId - UUID of the organizer
   * @returns Groups with event_count and participant_count populated
   * @throws Error if database query fails
   */
  async getGroupsByOrganizer(organizerId: string): Promise<Group[]> {
    const { data, error } = await supabase.rpc('get_groups_with_counts', {
      p_organizer_id: organizerId,
    });

    const groups = throwIfSupabaseError({ data, error });

    if (!groups) return [];

    return groups.map((group) => ({
      id: group.id,
      organizer_id: group.organizer_id,
      name: group.name,
      description: group.description,
      created_at: group.created_at,
      event_count: Number(group.event_count),
      participant_count: Number(group.participant_count),
    }));
  },

  /**
   * Retrieves a single group by ID with event and member counts.
   * @param groupId - UUID of the group
   * @returns Group with computed counts
   * @throws Error if group not found or query fails
   */
  async getGroupById(groupId: string): Promise<Group> {
    const { data, error } = await supabase.rpc('get_group_by_id_with_counts', {
      p_group_id: groupId,
    });

    const result = throwIfSupabaseError({ data, error });
    if (!result || result.length === 0) {
      throw new Error('Group not found');
    }

    const group = result[0];
    return {
      id: group.id,
      organizer_id: group.organizer_id,
      name: group.name,
      description: group.description,
      created_at: group.created_at,
      event_count: Number(group.event_count),
      participant_count: Number(group.participant_count),
    };
  },

  /**
   * Creates a new group and adds the organizer as a member.
   * Requires an authenticated session. ID is auto-generated.
   * @param group - Group data without id, created_at, or computed counts
   * @returns The created group
   * @throws ValidationError if group data is invalid
   * @throws Error if session is invalid or creation fails
   */
  async createGroup(
    group: Omit<Group, 'id' | 'created_at' | 'event_count' | 'participant_count'>
  ): Promise<Group> {
    await requireValidSession();
    validateGroupData(group);

    const insertData: TablesInsert<'groups'> = {
      organizer_id: group.organizer_id,
      name: group.name.trim(),
      description: group.description,
    };

    const { data, error } = await supabase.from('groups').insert(insertData).select().single();

    throwIfSupabaseError({ data, error });
    const created = requireData(data, 'create group');

    await supabase.from('group_participants').insert({
      group_id: created.id,
      user_id: group.organizer_id,
    });

    return created;
  },

  /**
   * Updates an existing group with partial data.
   * Requires an authenticated session.
   * @param groupId - UUID of the group to update
   * @param updates - Partial group data (name and/or description)
   * @returns The updated group
   * @throws ValidationError if update data is invalid
   * @throws Error if session invalid or group not found
   */
  async updateGroup(groupId: string, updates: Partial<Group>): Promise<Group> {
    await requireValidSession();
    validateGroupData(updates);

    const updateData: TablesUpdate<'groups'> = {};

    if (updates.name !== undefined) updateData.name = updates.name.trim();
    if (updates.description !== undefined) updateData.description = updates.description;

    const { data, error } = await supabase
      .from('groups')
      .update(updateData)
      .eq('id', groupId)
      .select()
      .single();

    throwIfSupabaseError({ data, error });
    return requireData(data, 'update group');
  },

  /**
   * Deletes a group atomically via RPC.
   * Optionally deletes associated events or unlinks them from the group.
   * Requires an authenticated session.
   * @param groupId - UUID of the group to delete
   * @param deleteEvents - If true, delete events; if false, unlink them
   * @throws Error if session invalid or deletion fails
   */
  async deleteGroup(groupId: string, deleteEvents: boolean = false): Promise<void> {
    await requireValidSession();

    const { data, error } = await supabase.rpc('delete_group_atomic', {
      p_group_id: groupId,
      p_delete_events: deleteEvents,
    });

    throwIfSupabaseError({ data, error });
  },

  /**
   * Retrieves all events belonging to a group with participant counts.
   * @param groupId - UUID of the group
   * @returns Events sorted by datetime with participant_count populated
   * @throws Error if database query fails
   */
  async getGroupEvents(
    groupId: string
  ): Promise<Array<Tables<'events'> & { participant_count?: number }>> {
    const { data: eventsData, error: eventsError } = await supabase
      .from('events')
      .select(
        `
        *,
        participants!left(id)
      `
      )
      .eq('group_id', groupId)
      .order('datetime', { ascending: true });

    throwIfSupabaseError({ data: eventsData, error: eventsError });

    if (!eventsData) return [];

    return eventsData.map((event: EventWithParticipants) => {
      const participantCount = Array.isArray(event.participants)
        ? event.participants.filter((p) => p !== null).length
        : 0;

      const { participants, ...eventWithoutParticipants } = event;
      void participants;

      return {
        ...eventWithoutParticipants,
        participant_count: participantCount,
      };
    });
  },

  /**
   * Retrieves all members of a group with their user info from auth.users.
   * @param groupId - UUID of the group
   * @returns Array of group participants with avatar URLs and names
   * @throws Error if database query fails
   */
  async getGroupParticipants(groupId: string): Promise<GroupParticipant[]> {
    const { data: membersData, error: membersError } = await supabase.rpc(
      'get_group_members_with_user_info',
      { p_group_id: groupId }
    );

    const members = throwIfSupabaseError({ data: membersData, error: membersError });
    if (!members || members.length === 0) return [];

    return members.map((member) => ({
      id: member.user_id,
      user_id: member.user_id,
      name: member.full_name || member.email || 'Group Member',
      email: member.email,
      phone: null,
      responses: {},
      event_id: null,
      created_at: member.joined_at,
      group_joined_at: member.joined_at,
      event: {
        id: '',
        name: '',
      },
      claimed_by_user_id: null,
      notes: null,
      payment_marked_at: null,
      payment_notes: null,
      payment_status: null,
      checked_in_at: null,
      avatar_url: member.avatar_url || null,
    }));
  },

  /**
   * Gets statistics for a group: event count, member count, and total registrations.
   * @param groupId - UUID of the group
   * @returns Object with event_count, participant_count, and total_registrations
   * @throws Error if any database query fails
   */
  async getGroupStats(groupId: string): Promise<GroupStats> {
    const { count: eventCount, error: eventError } = await supabase
      .from('events')
      .select('*', { count: 'exact', head: true })
      .eq('group_id', groupId);

    throwIfSupabaseError({ data: eventCount, error: eventError });

    const { count: memberCount, error: memberError } = await supabase
      .from('group_participants')
      .select('*', { count: 'exact', head: true })
      .eq('group_id', groupId);

    throwIfSupabaseError({ data: memberCount, error: memberError });

    const { count: totalRegistrations, error: registrationsError } = await supabase
      .from('participants')
      .select('event_id, events!inner(group_id)', { count: 'exact', head: true })
      .eq('events.group_id', groupId);

    throwIfSupabaseError({ data: totalRegistrations, error: registrationsError });

    return {
      event_count: eventCount || 0,
      participant_count: memberCount || 0,
      total_registrations: totalRegistrations || 0,
    };
  },

  /**
   * Adds a participant to a group via their user_id.
   * Only participants with linked user accounts can be added. Idempotent.
   * @param groupId - UUID of the group
   * @param participantId - UUID of the participant record
   * @throws Error if participant not found or insertion fails
   */
  async addParticipantToGroup(groupId: string, participantId: string): Promise<void> {
    const { data: participantData, error: participantError } = await supabase
      .from('participants')
      .select('user_id')
      .eq('id', participantId)
      .single();

    throwIfSupabaseError({ data: participantData, error: participantError });
    const participant = requireData(participantData, 'get participant');

    if (!participant.user_id) {
      return;
    }

    const insertData: TablesInsert<'group_participants'> = {
      group_id: groupId,
      user_id: participant.user_id,
    };

    const { error } = await supabase.from('group_participants').insert(insertData);

    if (error) {
      if (error.code !== '23505') {
        throwIfSupabaseError({ data: null, error });
      }
    }
  },

  /**
   * Gets all unique contacts from all groups owned by an organizer.
   * Deduplicates by user_id and returns contact details.
   * @param organizerId - UUID of the organizer
   * @returns Unique contacts sorted alphabetically by name
   * @throws Error if database query fails
   */
  async getAllContactsFromGroups(organizerId: string): Promise<GroupContact[]> {
    const { data: groups, error: groupsError } = await supabase
      .from('groups')
      .select('id')
      .eq('organizer_id', organizerId);

    const groupsData = throwIfSupabaseError({ data: groups, error: groupsError });
    if (!groupsData || groupsData.length === 0) return [];

    const groupIds = groupsData.map((g) => g.id);

    const { data: groupMembersData, error: membersError } = await supabase
      .from('group_participants')
      .select('user_id, joined_at')
      .in('group_id', groupIds)
      .order('joined_at', { ascending: true });

    const membersData = throwIfSupabaseError({ data: groupMembersData, error: membersError });
    if (!membersData || membersData.length === 0) return [];

    const contactsMap = new Map<string, GroupContact>();

    for (const member of membersData) {
      if (contactsMap.has(member.user_id)) continue;

      const { data: participantData } = await supabase
        .from('participants')
        .select('name, email')
        .eq('user_id', member.user_id)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

      contactsMap.set(member.user_id, {
        id: member.user_id,
        name: participantData?.name || 'Group Member',
        email: participantData?.email || null,
        user_id: member.user_id,
        first_seen: member.joined_at,
      });
    }

    return Array.from(contactsMap.values()).sort((a, b) => a.name.localeCompare(b.name));
  },

  /**
   * Removes a participant from a group via their user_id.
   * @param groupId - UUID of the group
   * @param participantId - UUID of the participant record
   * @throws Error if participant not found or deletion fails
   */
  async removeParticipantFromGroup(groupId: string, participantId: string): Promise<void> {
    const { data: participantData, error: participantError } = await supabase
      .from('participants')
      .select('user_id')
      .eq('id', participantId)
      .single();

    throwIfSupabaseError({ data: participantData, error: participantError });
    const participant = requireData(participantData, 'get participant');
    if (!participant.user_id) {
      throw new Error('Cannot remove participant: user not found');
    }

    const { data, error } = await supabase
      .from('group_participants')
      .delete()
      .eq('group_id', groupId)
      .eq('user_id', participant.user_id);

    throwIfSupabaseError({ data, error });
  },

  /**
   * Gets all groups that a participant belongs to via their user_id.
   * @param participantId - UUID of the participant record
   * @returns Array of groups the participant is a member of
   * @throws Error if participant not found or query fails
   */
  async getParticipantGroups(participantId: string): Promise<Group[]> {
    const { data: participantData, error: participantError } = await supabase
      .from('participants')
      .select('user_id')
      .eq('id', participantId)
      .single();

    throwIfSupabaseError({ data: participantData, error: participantError });
    if (!participantData || !participantData.user_id) return [];

    const { data: groupData, error: groupError } = await supabase
      .from('group_participants')
      .select(
        `
        groups!inner (*)
      `
      )
      .eq('user_id', participantData.user_id);

    const groups = throwIfSupabaseError({ data: groupData, error: groupError });

    if (!groups) return [];

    return groups.map((item: GroupQueryResult) => {
      const group = item.groups;
      return Array.isArray(group) ? group[0] : group;
    });
  },

  /**
   * Checks if a user is an admin of a group (either owner or in group_admins table).
   * @param groupId - UUID of the group
   * @param userId - UUID of the user to check
   * @returns True if user is owner or admin, false otherwise
   * @throws Error if database query fails
   */
  async isGroupAdmin(groupId: string, userId: string): Promise<boolean> {
    const { data: group, error: groupError } = await supabase
      .from('groups')
      .select('organizer_id')
      .eq('id', groupId)
      .single();

    throwIfSupabaseError({ data: group, error: groupError });
    if (!group) return false;

    if (group.organizer_id === userId) return true;

    const { data: adminRecord, error: adminError } = await supabase
      .from('group_admins')
      .select('id')
      .eq('group_id', groupId)
      .eq('user_id', userId)
      .maybeSingle();

    throwIfSupabaseError({ data: adminRecord, error: adminError });

    return adminRecord !== null;
  },

  /**
   * Adds a user as an admin of a group. Idempotent.
   * @param groupId - UUID of the group
   * @param userId - UUID of the user to make admin
   * @throws Error if insertion fails (except duplicates)
   */
  async addGroupAdmin(groupId: string, userId: string): Promise<void> {
    const { error } = await supabase.from('group_admins').insert({
      group_id: groupId,
      user_id: userId,
    });

    if (error) {
      if (error.code !== '23505') {
        throwIfSupabaseError({ data: null, error });
      }
    }
  },

  /**
   * Removes a user's admin privileges from a group.
   * @param groupId - UUID of the group
   * @param userId - UUID of the admin to remove
   * @throws Error if deletion fails
   */
  async removeGroupAdmin(groupId: string, userId: string): Promise<void> {
    const { data, error } = await supabase
      .from('group_admins')
      .delete()
      .eq('group_id', groupId)
      .eq('user_id', userId);

    throwIfSupabaseError({ data, error });
  },

  /**
   * Gets all admins for a group, sorted by creation date.
   * @param groupId - UUID of the group
   * @returns Array of group admin records
   * @throws Error if database query fails
   */
  async getGroupAdmins(groupId: string): Promise<GroupAdmin[]> {
    const { data, error } = await supabase
      .from('group_admins')
      .select('*')
      .eq('group_id', groupId)
      .order('created_at', { ascending: true });

    return throwIfSupabaseError({ data, error }) || [];
  },

  /**
   * Adds multiple participants to a group in batch via RPC.
   * @param groupId - UUID of the group
   * @param participantIds - Array of participant UUIDs to add
   * @returns Counts of added, skipped (already members), and failed
   * @throws Error if RPC call fails
   */
  async addParticipantsToGroupBatch(
    groupId: string,
    participantIds: string[]
  ): Promise<{ added: number; skipped: number; failed: number }> {
    const { data, error } = await supabase.rpc('add_participants_to_group', {
      p_group_id: groupId,
      p_participant_ids: participantIds,
    });

    const result = throwIfSupabaseError({ data, error });

    if (!result || result.length === 0) {
      return { added: 0, skipped: 0, failed: participantIds.length };
    }

    const first = result[0];
    return {
      added: first.added_count || 0,
      skipped: first.skipped_count || 0,
      failed: first.failed_count || 0,
    };
  },

  /**
   * Removes multiple participants from a group in batch via RPC.
   * @param groupId - UUID of the group
   * @param participantIds - Array of participant UUIDs to remove
   * @returns Counts of removed and failed
   * @throws Error if RPC call fails
   */
  async removeParticipantsFromGroupBatch(
    groupId: string,
    participantIds: string[]
  ): Promise<{ removed: number; failed: number }> {
    const { data, error } = await supabase.rpc('remove_participants_from_group', {
      p_group_id: groupId,
      p_participant_ids: participantIds,
    });

    const result = throwIfSupabaseError({ data, error });

    if (!result || result.length === 0) {
      return { removed: 0, failed: participantIds.length };
    }

    const first = result[0];
    return {
      removed: first.removed_count || 0,
      failed: first.failed_count || 0,
    };
  },

  /**
   * Checks if a user is a member of a group.
   * @param userId - UUID of the user
   * @param groupId - UUID of the group
   * @returns True if user is a member, false otherwise
   * @throws Error if database query fails
   */
  async checkUserGroupMembership(userId: string, groupId: string): Promise<boolean> {
    const { data, error } = await supabase
      .from('group_participants')
      .select('id')
      .eq('group_id', groupId)
      .eq('user_id', userId)
      .maybeSingle();

    throwIfSupabaseError({ data, error });

    return data !== null;
  },

  /**
   * Adds a user directly to a group by user ID. Idempotent.
   * @param groupId - UUID of the group
   * @param userId - UUID of the user to add
   * @throws Error if insertion fails (except duplicates)
   */
  async addUserToGroup(groupId: string, userId: string): Promise<void> {
    const alreadyMember = await this.checkUserGroupMembership(userId, groupId);
    if (alreadyMember) {
      return;
    }

    const insertData: TablesInsert<'group_participants'> = {
      group_id: groupId,
      user_id: userId,
    };

    const { error } = await supabase.from('group_participants').insert(insertData);

    if (error) {
      if (error.code !== '23505') {
        throwIfSupabaseError({ data: null, error });
      }
    }
  },

  /**
   * Gets all groups a user is a member of with event and member counts.
   * @param userId - UUID of the user
   * @returns Groups with computed counts
   * @throws Error if database query fails
   */
  async getGroupsByUser(userId: string): Promise<Group[]> {
    const { data, error } = await supabase.rpc('get_user_groups_with_counts', {
      p_user_id: userId,
    });

    const groups = throwIfSupabaseError({ data, error });

    if (!groups || groups.length === 0) return [];

    return groups.map((group) => ({
      id: group.id,
      organizer_id: group.organizer_id,
      name: group.name,
      description: group.description,
      created_at: group.created_at,
      event_count: Number(group.event_count),
      participant_count: Number(group.participant_count),
    }));
  },

  /**
   * Removes a user from a group (user leaving voluntarily).
   * @param groupId - UUID of the group
   * @param userId - UUID of the user leaving
   * @throws Error if deletion fails
   */
  async leaveGroup(groupId: string, userId: string): Promise<void> {
    const { data, error } = await supabase
      .from('group_participants')
      .delete()
      .eq('group_id', groupId)
      .eq('user_id', userId);

    throwIfSupabaseError({ data, error });
  },
};

import { supabase } from '@/lib/supabase';
import type { Tables, TablesInsert, TablesUpdate } from '@/types/app.types';
import { throwIfSupabaseError, requireData } from '@/lib/errorHandler';

export type Label = Tables<'labels'>;

export const labelService = {
  /**
   * Retrieves all labels for an event, sorted alphabetically by name.
   * @param eventId - UUID of the event
   * @returns Array of labels for the event
   * @throws Error if database query fails
   */
  async getLabelsByEventId(eventId: string): Promise<Label[]> {
    const { data, error } = await supabase
      .from('labels')
      .select('*')
      .eq('event_id', eventId)
      .order('name');

    return throwIfSupabaseError({ data, error }) || [];
  },

  /**
   * Creates a new label for an event.
   * @param label - Label data without id (event_id, name, color)
   * @returns The created label with generated id
   * @throws Error if creation fails
   */
  async createLabel(label: Omit<Label, 'id'>): Promise<Label> {
    const insertData: TablesInsert<'labels'> = {
      event_id: label.event_id,
      name: label.name,
      color: label.color,
    };

    const { data, error } = await supabase.from('labels').insert(insertData).select().single();

    throwIfSupabaseError({ data, error });
    return requireData(data, 'create label');
  },

  /**
   * Updates an existing label with partial data.
   * @param labelId - UUID of the label to update
   * @param updates - Partial label data (name and/or color)
   * @returns The updated label
   * @throws Error if label not found or update fails
   */
  async updateLabel(labelId: string, updates: Partial<Label>): Promise<Label> {
    const updateData: TablesUpdate<'labels'> = {};

    if (updates.name !== undefined) updateData.name = updates.name;
    if (updates.color !== undefined) updateData.color = updates.color;

    const { data, error } = await supabase
      .from('labels')
      .update(updateData)
      .eq('id', labelId)
      .select()
      .single();

    throwIfSupabaseError({ data, error });
    return requireData(data, 'update label');
  },

  /**
   * Deletes a label by ID. Cascades to participant_labels associations.
   * @param labelId - UUID of the label to delete
   * @throws Error if deletion fails
   */
  async deleteLabel(labelId: string): Promise<void> {
    const { data, error } = await supabase.from('labels').delete().eq('id', labelId);

    throwIfSupabaseError({ data, error });
  },
};

import { supabase } from '@/lib/supabase';
import type { PushSubscription } from '@/types/notifications';
import { throwIfSupabaseError, logError } from '@/lib/errorHandler';

const VAPID_PUBLIC_KEY = import.meta.env.VITE_VAPID_PUBLIC_KEY;

/**
 * Validate that a string is a valid URL-safe base64 encoded VAPID key
 * VAPID public keys should be 65 bytes when decoded (uncompressed P-256 point)
 */
function isValidVapidKey(key: string | undefined): key is string {
  if (!key || typeof key !== 'string') return false;

  // VAPID public key should be ~88 characters in base64
  if (key.length < 80 || key.length > 100) return false;

  // Check for valid URL-safe base64 characters
  const urlSafeBase64Regex = /^[A-Za-z0-9_-]+$/;
  return urlSafeBase64Regex.test(key);
}

/**
 * Convert a base64 string to Uint8Array for Web Push
 */
function urlBase64ToUint8Array(base64String: string): Uint8Array {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

/**
 * Store VAPID public key in IndexedDB for service worker access
 */
async function storeVapidKeyForServiceWorker(vapidKey: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('push-config', 1);

    request.onerror = () => reject(request.error);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains('config')) {
        db.createObjectStore('config');
      }
    };

    request.onsuccess = () => {
      const db = request.result;
      const tx = db.transaction('config', 'readwrite');
      const store = tx.objectStore('config');
      store.put(vapidKey, 'vapidPublicKey');
      tx.oncomplete = () => {
        db.close();
        resolve();
      };
      tx.onerror = () => reject(tx.error);
    };
  });
}

export const pushSubscriptionService = {
  /**
   * Check if push notifications are supported in this browser
   */
  isSupported(): boolean {
    return 'serviceWorker' in navigator && 'PushManager' in window && 'Notification' in window;
  },

  /**
   * Get current notification permission status
   */
  getPermissionStatus(): NotificationPermission {
    if (!('Notification' in window)) return 'denied';
    return Notification.permission;
  },

  /**
   * Request notification permission from the user
   */
  async requestPermission(): Promise<NotificationPermission> {
    if (!('Notification' in window)) return 'denied';
    const permission = await Notification.requestPermission();
    return permission;
  },

  /**
   * Check if VAPID key is properly configured
   */
  isConfigured(): boolean {
    return isValidVapidKey(VAPID_PUBLIC_KEY);
  },

  /**
   * Subscribe to push notifications
   * Returns the subscription or null if failed
   */
  async subscribe(): Promise<PushSubscriptionJSON | null> {
    if (!this.isSupported()) {
      console.warn('Push notifications not supported');
      return null;
    }

    if (!isValidVapidKey(VAPID_PUBLIC_KEY)) {
      console.warn('VAPID public key not configured or invalid');
      return null;
    }

    try {
      // Get current user
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) throw new Error('Not authenticated');

      const registration = await navigator.serviceWorker.getRegistration();
      if (!registration) {
        throw new Error('No service worker registered. Please refresh the page.');
      }

      const subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
      });

      const subscriptionJson = subscription.toJSON();

      // Store VAPID key for service worker re-subscription
      await storeVapidKeyForServiceWorker(VAPID_PUBLIC_KEY);

      // Save to database using RPC function that handles cross-user endpoint conflicts
      const { data, error } = await supabase.rpc('upsert_push_subscription', {
        p_endpoint: subscriptionJson.endpoint!,
        p_p256dh_key: subscriptionJson.keys?.p256dh || '',
        p_auth_key: subscriptionJson.keys?.auth || '',
        p_user_agent: navigator.userAgent,
      });

      throwIfSupabaseError({ data, error });

      return subscriptionJson;
    } catch (error) {
      logError('Failed to subscribe to push notifications', error);
      throw error;
    }
  },

  /**
   * Unsubscribe from push notifications (both database and browser)
   * Use this when user explicitly disables notifications in settings
   */
  async unsubscribe(): Promise<void> {
    if (!this.isSupported()) return;

    try {
      const registration = await navigator.serviceWorker.getRegistration();
      if (!registration) return;

      const subscription = await registration.pushManager.getSubscription();

      if (subscription) {
        // Remove from database
        await supabase.from('push_subscriptions').delete().eq('endpoint', subscription.endpoint);

        // Unsubscribe from browser
        await subscription.unsubscribe();
      }
    } catch (error) {
      logError('Failed to unsubscribe from push notifications', error);
      throw error;
    }
  },

  /**
   * Remove subscription from database only (keeps browser subscription intact)
   * Use this on sign out to prevent notification leaks while preserving
   * browser permission for easier re-subscription on next sign in
   */
  async removeSubscriptionFromDatabase(): Promise<void> {
    if (!this.isSupported()) return;

    try {
      const registration = await navigator.serviceWorker.getRegistration();
      if (!registration) return;

      const subscription = await registration.pushManager.getSubscription();

      if (subscription) {
        // Only remove from database, keep browser subscription
        await supabase.from('push_subscriptions').delete().eq('endpoint', subscription.endpoint);
      }
    } catch (error) {
      logError('Failed to remove push subscription from database', error);
      throw error;
    }
  },

  /**
   * Check if currently subscribed to push notifications
   */
  async isSubscribed(): Promise<boolean> {
    if (!this.isSupported()) return false;

    try {
      const registration = await navigator.serviceWorker.getRegistration();
      if (!registration) return false;
      const subscription = await registration.pushManager.getSubscription();
      return subscription !== null;
    } catch {
      return false;
    }
  },

  /**
   * Get all push subscriptions for the current user
   */
  async getSubscriptions(): Promise<PushSubscription[]> {
    const { data, error } = await supabase
      .from('push_subscriptions')
      .select('*')
      .eq('active', true)
      .order('created_at', { ascending: false });

    return (throwIfSupabaseError({ data, error }) || []) as PushSubscription[];
  },

  /**
   * Deactivate a specific subscription (e.g., for another device)
   */
  async deactivateSubscription(subscriptionId: string): Promise<void> {
    const { data, error } = await supabase
      .from('push_subscriptions')
      .update({ active: false })
      .eq('id', subscriptionId);

    throwIfSupabaseError({ data, error });
  },
};

import { supabase } from '@/lib/supabase';
import type { Notification, NotificationType } from '@/types/notifications';
import { throwIfSupabaseError, requireData, logError } from '@/lib/errorHandler';

/** Data needed to queue a notification */
interface QueueNotificationParams {
  recipientUserId: string;
  notificationType: NotificationType;
  title: string;
  body: string;
  eventId?: string | null;
  participantId?: string | null;
  actorUserId?: string | null;
  actionUrl?: string | null;
}

export const notificationService = {
  /**
   * Get user's notifications (inbox)
   */
  async getNotifications(limit = 50, offset = 0): Promise<Notification[]> {
    const { data, error } = await supabase
      .from('notifications')
      .select('*')
      .order('created_at', { ascending: false })
      .range(offset, offset + limit - 1);

    return (throwIfSupabaseError({ data, error }) || []) as Notification[];
  },

  /**
   * Get unread notification count
   */
  async getUnreadCount(): Promise<number> {
    const { count, error } = await supabase
      .from('notifications')
      .select('*', { count: 'exact', head: true })
      .is('read_at', null);

    throwIfSupabaseError({ data: count, error });
    return count || 0;
  },

  /**
   * Get a single notification by ID
   */
  async getNotificationById(notificationId: string): Promise<Notification | null> {
    const { data, error } = await supabase
      .from('notifications')
      .select('*')
      .eq('id', notificationId)
      .single();

    // PGRST116 = no rows returned
    if (error && error.code !== 'PGRST116') throw error;
    return data as Notification | null;
  },

  /**
   * Mark notification as read
   */
  async markAsRead(notificationId: string): Promise<void> {
    const { data, error } = await supabase
      .from('notifications')
      .update({ read_at: new Date().toISOString() })
      .eq('id', notificationId);

    throwIfSupabaseError({ data, error });
  },

  /**
   * Mark all notifications as read
   */
  async markAllAsRead(): Promise<void> {
    const { data, error } = await supabase
      .from('notifications')
      .update({ read_at: new Date().toISOString() })
      .is('read_at', null);

    throwIfSupabaseError({ data, error });
  },

  /**
   * Delete a notification
   */
  async deleteNotification(notificationId: string): Promise<void> {
    const { data, error } = await supabase.from('notifications').delete().eq('id', notificationId);

    throwIfSupabaseError({ data, error });
  },

  /**
   * Create a notification in the inbox for the current user
   */
  async createNotification(notification: {
    type: string;
    title: string;
    body: string;
    event_id?: string | null;
    action_url?: string | null;
  }): Promise<Notification> {
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) throw new Error('Not authenticated');

    const { data, error } = await supabase
      .from('notifications')
      .insert({
        ...notification,
        recipient_user_id: user.id,
      })
      .select()
      .single();

    throwIfSupabaseError({ data, error });
    return requireData(data, 'create notification') as Notification;
  },

  /**
   * Subscribe to real-time notification updates
   */
  subscribeToNotifications(
    userId: string,
    onInsert: (notification: Notification) => void
  ): () => void {
    const channel = supabase
      .channel(`notifications:${userId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'notifications',
          filter: `recipient_user_id=eq.${userId}`,
        },
        (payload) => {
          onInsert(payload.new as Notification);
        }
      )
      .subscribe();

    // Return unsubscribe function
    return () => {
      supabase.removeChannel(channel);
    };
  },

  // ============================================================================
  // Notification Queue Functions (moved from DB triggers)
  // ============================================================================

  /**
   * Queue a notification for delivery. Uses an RPC function with SECURITY DEFINER
   * to bypass RLS, allowing users to queue notifications for other users
   * (e.g., participant queues organizer notification).
   */
  async queueNotification(params: QueueNotificationParams): Promise<void> {
    const { error } = await supabase.rpc('queue_notification', {
      p_recipient_user_id: params.recipientUserId,
      p_notification_type: params.notificationType,
      p_title: params.title,
      p_body: params.body,
      p_event_id: params.eventId || undefined,
      p_participant_id: params.participantId || undefined,
      p_actor_user_id: params.actorUserId || undefined,
      p_action_url: params.actionUrl || undefined,
    });

    // Silently ignore duplicate notifications (unique constraint violations)
    if (error && error.code !== '23505') {
      logError('Failed to queue notification', error, { params });
    }
  },

  /**
   * Queue new_signup notification to organizer when someone registers
   */
  async queueNewSignup(params: {
    organizerId: string;
    eventId: string;
    eventName: string;
    participantId: string;
    participantName: string;
    actorUserId: string | null;
  }): Promise<void> {
    // Don't notify organizer if they signed up themselves
    if (params.actorUserId === params.organizerId) return;

    await this.queueNotification({
      recipientUserId: params.organizerId,
      notificationType: 'new_signup',
      title: `New signup for ${params.eventName}`,
      body: `${params.participantName} just signed up`,
      eventId: params.eventId,
      participantId: params.participantId,
      actorUserId: params.actorUserId,
      actionUrl: `/signup/${params.eventId}`,
    });
  },

  /**
   * Queue signup_confirmed notification to participant when they register
   */
  async queueSignupConfirmed(params: {
    participantUserId: string;
    organizerId: string;
    eventId: string;
    eventName: string;
    participantId: string;
  }): Promise<void> {
    // Don't send confirmation to organizer
    if (params.participantUserId === params.organizerId) return;

    await this.queueNotification({
      recipientUserId: params.participantUserId,
      notificationType: 'signup_confirmed',
      title: 'Signup confirmed!',
      body: `You're registered for ${params.eventName}`,
      eventId: params.eventId,
      participantId: params.participantId,
      actionUrl: `/signup/${params.eventId}`,
    });
  },

  /**
   * Queue capacity_reached notification to organizer when event is full
   */
  async queueCapacityReached(params: {
    organizerId: string;
    eventId: string;
    eventName: string;
    maxParticipants: number;
  }): Promise<void> {
    await this.queueNotification({
      recipientUserId: params.organizerId,
      notificationType: 'capacity_reached',
      title: `${params.eventName} is now full!`,
      body: `Your event has reached maximum capacity (${params.maxParticipants} participants)`,
      eventId: params.eventId,
      actionUrl: `/signup/${params.eventId}`,
    });
  },

  /**
   * Queue withdrawal notification to organizer when someone withdraws
   */
  async queueWithdrawal(params: {
    organizerId: string;
    eventId: string;
    eventName: string;
    participantName: string;
    actorUserId: string | null;
  }): Promise<void> {
    // Don't notify organizer if they withdrew themselves
    if (params.actorUserId === params.organizerId) return;

    await this.queueNotification({
      recipientUserId: params.organizerId,
      notificationType: 'withdrawal',
      title: `Withdrawal from ${params.eventName}`,
      body: `${params.participantName} has withdrawn`,
      eventId: params.eventId,
      actorUserId: params.actorUserId,
      actionUrl: `/signup/${params.eventId}`,
    });
  },

  /**
   * Queue payment_received notification to organizer
   */
  async queuePaymentReceived(params: {
    organizerId: string;
    eventId: string;
    eventName: string;
    participantId: string;
    participantName: string;
    actorUserId: string | null;
  }): Promise<void> {
    await this.queueNotification({
      recipientUserId: params.organizerId,
      notificationType: 'payment_received',
      title: 'Payment received',
      body: `${params.participantName} paid for ${params.eventName}`,
      eventId: params.eventId,
      participantId: params.participantId,
      actorUserId: params.actorUserId,
      actionUrl: `/signup/${params.eventId}`,
    });
  },

  /**
   * Queue event_updated notifications to all participants
   */
  async queueEventUpdated(params: {
    organizerId: string;
    eventId: string;
    eventName: string;
    changes: string[];
    participantUserIds: string[];
  }): Promise<void> {
    if (params.changes.length === 0) return;

    const changesText = params.changes.join(', ');

    for (const userId of params.participantUserIds) {
      // Don't notify organizer
      if (userId === params.organizerId) continue;

      await this.queueNotification({
        recipientUserId: userId,
        notificationType: 'event_updated',
        title: `Event updated: ${params.eventName}`,
        body: `The ${changesText} has been updated`,
        eventId: params.eventId,
        actorUserId: params.organizerId,
        actionUrl: `/signup/${params.eventId}`,
      });
    }
  },

  /**
   * Queue event_cancelled notifications to all participants
   */
  async queueEventCancelled(params: {
    organizerId: string;
    eventName: string;
    participantUserIds: string[];
  }): Promise<void> {
    for (const userId of params.participantUserIds) {
      // Don't notify organizer
      if (userId === params.organizerId) continue;

      await this.queueNotification({
        recipientUserId: userId,
        notificationType: 'event_cancelled',
        title: `Event cancelled: ${params.eventName}`,
        body: `The event "${params.eventName}" has been cancelled`,
        eventId: null,
        actorUserId: params.organizerId,
        actionUrl: '/events',
      });
    }
  },
};

import { supabase } from '@/lib/supabase';
import type { NotificationPreferences, NotificationPreferencesInput } from '@/types/notifications';
import { throwIfSupabaseError, requireData } from '@/lib/errorHandler';

// Default preferences for new users
const DEFAULT_PREFERENCES: Omit<
  NotificationPreferences,
  'id' | 'user_id' | 'created_at' | 'updated_at'
> = {
  push_enabled: true,
  notify_new_signup: true,
  notify_withdrawal: true,
  notify_payment_received: true,
  notify_capacity_reached: true,
  notify_signup_confirmed: true,
  notify_event_updated: true,
  notify_event_cancelled: true,
  notify_payment_reminder: true,
  notify_waitlist_promotion: true,
};

export const notificationPreferenceService = {
  /**
   * Get user's notification preferences
   * Returns null if none exist
   */
  async getPreferences(): Promise<NotificationPreferences | null> {
    const { data, error } = await supabase.from('notification_preferences').select('*').single();

    // PGRST116 = no rows returned
    if (error && error.code !== 'PGRST116') throw error;
    return data as NotificationPreferences | null;
  },

  /**
   * Get preferences with defaults applied
   * Creates preferences if they don't exist
   */
  async getOrCreatePreferences(): Promise<NotificationPreferences> {
    const existing = await this.getPreferences();
    if (existing) return existing;

    // Get current user
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) throw new Error('Not authenticated');

    // Create default preferences
    const { data, error } = await supabase
      .from('notification_preferences')
      .insert({
        user_id: user.id,
        ...DEFAULT_PREFERENCES,
      })
      .select()
      .single();

    // Handle race condition: if another request already created preferences,
    // fetch and return the existing row
    if (error?.code === '23505') {
      const existingAfterRace = await this.getPreferences();
      if (existingAfterRace) return existingAfterRace;
      throw requireData(null, 'get notification preferences after race condition');
    }

    throwIfSupabaseError({ data, error });
    return requireData(data, 'create notification preferences') as NotificationPreferences;
  },

  /**
   * Update notification preferences
   */
  async updatePreferences(updates: NotificationPreferencesInput): Promise<NotificationPreferences> {
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) throw new Error('Not authenticated');

    const { data, error } = await supabase
      .from('notification_preferences')
      .upsert(
        {
          user_id: user.id,
          ...updates,
          updated_at: new Date().toISOString(),
        },
        {
          onConflict: 'user_id',
        }
      )
      .select()
      .single();

    throwIfSupabaseError({ data, error });
    return requireData(data, 'update notification preferences') as NotificationPreferences;
  },

  /**
   * Toggle a specific notification type
   */
  async toggleNotificationType(
    type: keyof NotificationPreferencesInput,
    enabled: boolean
  ): Promise<NotificationPreferences> {
    return this.updatePreferences({ [type]: enabled });
  },

  /**
   * Enable all notifications
   */
  async enableAll(): Promise<NotificationPreferences> {
    return this.updatePreferences(DEFAULT_PREFERENCES);
  },

  /**
   * Disable all notifications (master toggle)
   */
  async disableAll(): Promise<NotificationPreferences> {
    return this.updatePreferences({ push_enabled: false });
  },
};

import { supabase } from '@/lib/supabase';
import type {
  Tables,
  TablesInsert,
  TablesUpdate,
  ResponseRecord,
  CustomField,
  Json,
} from '@/types/app.types';
import { throwIfSupabaseError, requireData, fireAndForget } from '@/lib/errorHandler';
import { notificationService } from './notificationService';
import { participantActivityService } from './participantActivityService';

/** Extended Participant type with labels and computed properties */
export interface Participant extends Omit<Tables<'participants'>, 'responses' | 'created_at'> {
  created_at: string;
  labels?: Label[];
  responses: ResponseRecord;
  claimed_by_user_id: string | null;
  payment_status: 'pending' | 'paid' | 'waived';
  payment_marked_at: string | null;
  payment_notes: string | null;
  avatar_url?: string | null;
  /** Current name from auth.users for linked user accounts */
  auth_full_name?: string | null;
}

export type Label = Tables<'labels'>;

export type ParticipantLabel = Tables<'participant_labels'>;

/**
 * Converts a database participant record to the application Participant type.
 * Applies default values for nullable fields.
 * @param dbParticipant - Raw participant record from the database
 * @returns Typed Participant object with defaults applied
 */
function dbParticipantToParticipant(dbParticipant: Tables<'participants'>): Participant {
  return {
    ...dbParticipant,
    created_at: dbParticipant.created_at || new Date().toISOString(),
    responses: (dbParticipant.responses as ResponseRecord) || {},
    claimed_by_user_id: dbParticipant.claimed_by_user_id || null,
    payment_status: (dbParticipant.payment_status as 'pending' | 'paid' | 'waived') || 'pending',
    payment_marked_at: dbParticipant.payment_marked_at || null,
    payment_notes: dbParticipant.payment_notes || null,
  };
}

/** Helper to get event info needed for notifications */
async function getEventInfo(eventId: string): Promise<{
  id: string;
  name: string;
  organizer_id: string;
  max_participants: number | null;
} | null> {
  const { data } = await supabase
    .from('events')
    .select('id, name, organizer_id, max_participants')
    .eq('id', eventId)
    .single();
  return data;
}

/** Helper to count participants for capacity check */
async function getParticipantCount(eventId: string): Promise<number> {
  const { count } = await supabase
    .from('participants')
    .select('id', { count: 'exact', head: true })
    .eq('event_id', eventId);
  return count || 0;
}

export const participantService = {
  /**
   * Retrieves all participants for an event with their labels and avatar URLs.
   * Uses JOINs to fetch labels and an RPC call to get user avatars.
   * @param eventId - UUID of the event
   * @returns Participants sorted by created_at, with labels and avatar_url populated
   * @throws Error if database query fails
   */
  async getParticipantsByEventId(eventId: string): Promise<Participant[]> {
    const { data: participants, error: participantsError } = await supabase
      .from('participants')
      .select(
        `
        *,
        participant_labels!left(
          labels!inner(*)
        )
      `
      )
      .eq('event_id', eventId)
      .order('created_at', { ascending: true });

    const data = throwIfSupabaseError({ data: participants, error: participantsError });

    if (!data || data.length === 0) return [];

    const { data: userInfoData } = await supabase.rpc('get_event_participants_with_avatar', {
      p_event_id: eventId,
    });

    const avatarMap = new Map<string, string | null>();
    const nameMap = new Map<string, string | null>();
    if (userInfoData) {
      for (const item of userInfoData) {
        avatarMap.set(item.participant_id, item.avatar_url);
        nameMap.set(item.participant_id, item.full_name);
      }
    }

    return data.map((p) => {
      const labels: Label[] = [];
      if (Array.isArray(p.participant_labels)) {
        for (const pl of p.participant_labels) {
          if (pl.labels) {
            labels.push(pl.labels as Label);
          }
        }
      }

      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { participant_labels: _, ...participantWithoutLabels } = p as Tables<'participants'> & {
        participant_labels: Array<{ labels: Label } | null>;
      };

      return {
        ...dbParticipantToParticipant(participantWithoutLabels),
        labels,
        responses: (participantWithoutLabels.responses as ResponseRecord) || {},
        avatar_url: avatarMap.get(p.id) || null,
        auth_full_name: nameMap.get(p.id) || null,
      };
    });
  },

  /**
   * Retrieves a single participant by ID.
   * @param participantId - UUID of the participant
   * @returns The participant record
   * @throws Error if participant not found
   */
  async getParticipantById(participantId: string): Promise<Participant> {
    const { data, error } = await supabase
      .from('participants')
      .select('*')
      .eq('id', participantId)
      .single();

    throwIfSupabaseError({ data, error });
    return dbParticipantToParticipant(requireData(data, 'get participant'));
  },

  /**
   * Creates a new participant registration.
   * Handles both self-registration and claiming spots for others.
   * @param participant - Participant data without id, created_at, or labels
   * @param options - Optional claiming options for registering on behalf of others
   * @param options.claimingUserId - UUID of user claiming the spot (sets claimed_by_user_id)
   * @param options.claimingUserEmail - Email for claimed spots
   * @returns The created participant
   * @throws Error if insertion fails
   */
  async createParticipant(
    participant: Omit<Participant, 'id' | 'created_at' | 'labels'>,
    options?: {
      claimingUserId?: string;
      claimingUserEmail?: string;
    }
  ): Promise<Participant> {
    const finalName = participant.name?.trim() || 'Guest';

    let finalEmail = participant.email || null;
    if (options?.claimingUserId && options?.claimingUserEmail) {
      finalEmail = options.claimingUserEmail;
    }

    const insertData = {
      event_id: participant.event_id,
      name: finalName,
      email: finalEmail,
      phone: participant.phone || null,
      notes: participant.notes || null,
      user_id: options?.claimingUserId ? null : participant.user_id,
      claimed_by_user_id: options?.claimingUserId || null,
      responses: participant.responses as Json,
    } as TablesInsert<'participants'>;

    const { data, error } = await supabase
      .from('participants')
      .insert(insertData)
      .select()
      .single();

    throwIfSupabaseError({ data, error });
    const created = dbParticipantToParticipant(requireData(data, 'create participant'));

    // Queue notifications and log activity (fire and forget - don't block on these)
    const eventInfo = await getEventInfo(participant.event_id);
    if (eventInfo) {
      const actorUserId = created.user_id || created.claimed_by_user_id;

      // Log activity
      fireAndForget(
        participantActivityService.logJoined({
          participantId: created.id,
          eventId: created.event_id,
          participantName: created.name || 'Unknown',
        }),
        'log joined activity'
      );

      // Notify organizer of new signup
      fireAndForget(
        notificationService.queueNewSignup({
          organizerId: eventInfo.organizer_id,
          eventId: eventInfo.id,
          eventName: eventInfo.name,
          participantId: created.id,
          participantName: created.name || 'Unknown',
          actorUserId,
        }),
        'queue new signup notification'
      );

      // Notify participant of confirmation (if they have a user account)
      if (actorUserId) {
        fireAndForget(
          notificationService.queueSignupConfirmed({
            participantUserId: actorUserId,
            organizerId: eventInfo.organizer_id,
            eventId: eventInfo.id,
            eventName: eventInfo.name,
            participantId: created.id,
          }),
          'queue signup confirmed notification'
        );
      }

      // Check if capacity reached and notify
      if (eventInfo.max_participants) {
        const count = await getParticipantCount(participant.event_id);
        if (count === eventInfo.max_participants) {
          fireAndForget(
            notificationService.queueCapacityReached({
              organizerId: eventInfo.organizer_id,
              eventId: eventInfo.id,
              eventName: eventInfo.name,
              maxParticipants: eventInfo.max_participants,
            }),
            'queue capacity reached notification'
          );
        }
      }
    }

    return created;
  },

  /**
   * Updates an existing participant with partial data.
   * @param participantId - UUID of the participant to update
   * @param updates - Partial participant data to apply
   * @returns The updated participant
   * @throws Error if participant not found or update fails
   */
  async updateParticipant(
    participantId: string,
    updates: Partial<Participant>
  ): Promise<Participant> {
    // Get old data first to track changes
    const oldParticipant = await this.getParticipantById(participantId);

    const updateData: TablesUpdate<'participants'> = {};

    if (updates.name !== undefined) updateData.name = updates.name;
    if (updates.email !== undefined) updateData.email = updates.email || null;
    if (updates.phone !== undefined) updateData.phone = updates.phone || null;
    if (updates.notes !== undefined) updateData.notes = updates.notes || null;
    if (updates.responses !== undefined) updateData.responses = updates.responses as Json;

    const { data, error } = await supabase
      .from('participants')
      .update(updateData)
      .eq('id', participantId)
      .select()
      .single();

    throwIfSupabaseError({ data, error });
    const updated = dbParticipantToParticipant(requireData(data, 'update participant'));

    // Log info changes (fire and forget)
    const changes: {
      name?: { from: string | null; to: string | null };
      email?: { from: string | null; to: string | null };
      phone?: { from: string | null; to: string | null };
      notes?: { from: string | null; to: string | null };
    } = {};

    if (oldParticipant.name !== updated.name) {
      changes.name = { from: oldParticipant.name, to: updated.name };
    }
    if (oldParticipant.email !== updated.email) {
      changes.email = { from: oldParticipant.email, to: updated.email };
    }
    if (oldParticipant.phone !== updated.phone) {
      changes.phone = { from: oldParticipant.phone, to: updated.phone };
    }
    if (oldParticipant.notes !== updated.notes) {
      changes.notes = { from: oldParticipant.notes, to: updated.notes };
    }

    if (Object.keys(changes).length > 0) {
      fireAndForget(
        participantActivityService.logInfoUpdated({
          participantId: updated.id,
          eventId: updated.event_id,
          participantName: updated.name || 'Unknown',
          changes,
        }),
        'log info updated activity'
      );
    }

    return updated;
  },

  /**
   * Deletes a participant by ID.
   * @param participantId - UUID of the participant to delete
   * @throws Error if deletion fails
   */
  async deleteParticipant(participantId: string): Promise<void> {
    // Get participant and event info BEFORE deleting
    const participant = await this.getParticipantById(participantId);
    const eventInfo = await getEventInfo(participant.event_id);

    // Log withdrawal activity BEFORE deleting — must be awaited so the participant
    // row still exists when the activity log insert references it via FK.
    await participantActivityService.logWithdrew({
      participantId: participant.id,
      eventId: participant.event_id,
      participantName: participant.name || 'Unknown',
      paymentStatus: participant.payment_status,
    });

    const { data, error } = await supabase.from('participants').delete().eq('id', participantId);

    throwIfSupabaseError({ data, error });

    // Queue withdrawal notification AFTER successful delete
    if (eventInfo) {
      const actorUserId = participant.user_id || participant.claimed_by_user_id;
      fireAndForget(
        notificationService.queueWithdrawal({
          organizerId: eventInfo.organizer_id,
          eventId: eventInfo.id,
          eventName: eventInfo.name,
          participantName: participant.name || 'Unknown',
          actorUserId,
        }),
        'queue withdrawal notification'
      );
    }
  },

  /**
   * Deletes multiple participants in a single operation.
   * @param participantIds - Array of participant UUIDs to delete
   * @throws Error if deletion fails
   */
  async bulkDeleteParticipants(participantIds: string[]): Promise<void> {
    const { data, error } = await supabase.from('participants').delete().in('id', participantIds);

    throwIfSupabaseError({ data, error });
  },

  /**
   * Finds a participant by user ID and event ID.
   * Useful for checking if a user is already registered for an event.
   * @param userId - UUID of the user
   * @param eventId - UUID of the event
   * @returns The participant if found, null otherwise
